-- Poems batch 119
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('0a7620e2-ce6a-472e-83f5-0d69ecfb3de7','明日復雨排悶二首  其一','陸游','宋','宋诗','song-poetry','','[]','湖上孤村冷欲冰，更堪衰與病相乘。',64,'全唐诗/poet.song.130000.json','["湖上孤村冷欲冰，更堪衰與病相乘。", "夢回點滴簾間雨，心折青熒帳外燈。", "雖有數椽常似客，僅存一肉未成僧。", "披衣偶取南華讀，打破愁城喜不勝。"]'),
('498b3d2b-a986-4b2b-ba05-2352360926ac','明日復雨排悶二首  其二','陸游','宋','宋诗','song-poetry','','[]','此老在家如出家，蒲團趺坐讀南華。',64,'全唐诗/poet.song.130000.json','["此老在家如出家，蒲團趺坐讀南華。", "濕雲不散雁呼伴，幽室無聲燈墜花。", "心法先當破巢窟，世緣最忌養萌芽。", "行年七十方知悔，萬事無涯生有涯。"]'),
('60412e65-cf26-4b68-964f-52b21e2db08b','小室','陸游','宋','宋诗','song-poetry','','[]','小室僅容膝，焚香觀昨非。',48,'全唐诗/poet.song.130000.json','["小室僅容膝，焚香觀昨非。", "出門寜有碍，知我正須希。", "霜橘爭棋樂，仙壺賣藥歸。", "平生釣竿手，不解叩黄扉。"]'),
('732c48f9-4f14-4b6d-b9eb-a5170ad58079','浮世','陸游','宋','宋诗','song-poetry','','[]','浮世如流水，滔滔日夜東。',48,'全唐诗/poet.song.130000.json','["浮世如流水，滔滔日夜東。", "百年均夢寐，萬古一虚空。", "青鳥來雲外，銅駝卧棘中。", "相逢惟痛飲，令我憶無功。"]'),
('ad4331c3-7f67-4ec7-9a78-7d5c22869d8c','紅梅二首  其一','陸游','宋','宋诗','song-poetry','','[]','苧蘿山下越谿女，戲作長安時世粧。',32,'全唐诗/poet.song.130000.json','["苧蘿山下越谿女，戲作長安時世粧。", "白白朱朱雖小異，斷知不是百花香。"]'),
('2c3b5d4d-a97b-410c-9263-508541f5e8bc','紅梅二首  其二','陸游','宋','宋诗','song-poetry','','[]','雪裏溪頭已占春，小園又試晚粧新。',32,'全唐诗/poet.song.130000.json','["雪裏溪頭已占春，小園又試晚粧新。", "放翁老去風情在，惱得梅花醉似人。"]'),
('336a80ca-6404-4b38-afea-8e6d71616bb0','湖上','陸游','宋','宋诗','song-poetry','','[]','今朝雨初晴，湖上好天色。',72,'全唐诗/poet.song.130000.json','["今朝雨初晴，湖上好天色。", "落梅紛可藉，桑柳亦已拆。", "老夫病良已，並水散輕策。", "冉冉春物新，忽忽衰髮白。", "四方豈不樂，懶惰畏遠客。", "惟當勤買酒，東城復南陌。"]'),
('0c70feca-2bf7-44e7-a0bf-8a32ccf19704','晴甫一日復大風雨連日不止遣懷','陸游','宋','宋诗','song-poetry','','[]','書劍當年隘九州，白頭歸卧一窗幽。',64,'全唐诗/poet.song.130000.json','["書劍當年隘九州，白頭歸卧一窗幽。", "染成草色春猶淺，老盡梅花雨未休。", "得句已無前輩賞，開編時與古人遊。", "山房小甕今朝熟，不恨尊前自獻酬。"]'),
('a5dceaa6-ef3c-4941-995d-898ef9f6d2e0','癸丑上元三夕皆大雨雪','陸游','宋','宋诗','song-poetry','','[]','雨雪連三日，孤城冷欲冰。',48,'全唐诗/poet.song.130000.json','["雨雪連三日，孤城冷欲冰。", "泥深唯響屐，風惡更吹燈。", "空惱追歡客，何關在定僧。", "一杯嘗豉候，寒影對崚嶒。"]'),
('e40089fb-a878-4464-ba3e-045f89ec6a13','寓嘆','陸游','宋','宋诗','song-poetry','','[]','人生各自有窮通，世事寧論拙與工。',64,'全唐诗/poet.song.130000.json','["人生各自有窮通，世事寧論拙與工。", "裹馬革心空許國，不龜手藥却成功。", "早朝玉勒千門雪，夜坐蓬窗萬壑風。", "借得奇書且勤讀，小兒能續地爐紅。"]'),
('16e9c7cc-3829-437c-9952-b38bc0945a23','幽興','陸游','宋','宋诗','song-poetry','','[]','雨後梅花無復在，老來酒盞頓成疏。',64,'全唐诗/poet.song.130000.json','["雨後梅花無復在，老來酒盞頓成疏。", "身如海燕不逢社，家似瓜牛僅有廬。", "短髮垂肩懶中散，深居謝客病相如。", "從今何以消長日，剩種芭蕉學草書。"]'),
('0499d5d6-b6e6-4c95-8cea-c696cd8918e9','緗梅三首  其一','陸游','宋','宋诗','song-poetry','','[]','疏影横斜事已非，小園日暮鎖芳菲。',32,'全唐诗/poet.song.130000.json','["疏影横斜事已非，小園日暮鎖芳菲。", "素綃應怯東風思，故著重重淺色衣。"]'),
('863ee31a-e010-4e18-9ed5-5425beb515c9','緗梅三首  其二','陸游','宋','宋诗','song-poetry','','[]','香似海沈黄似酒，不禁風雪最遲開。',32,'全唐诗/poet.song.130000.json','["香似海沈黄似酒，不禁風雪最遲開。", "放翁欲作梅花譜，蠟屐搘笻日日來。"]'),
('f80b4086-ad58-4d8f-b0df-12d958fd4991','緗梅三首  其三','陸游','宋','宋诗','song-poetry','','[]','紅梅眼看風吹盡，更有緗梅亦已無。',32,'全唐诗/poet.song.130000.json','["紅梅眼看風吹盡，更有緗梅亦已無。", "天與色香天自愛，不教一點上蜂鬚。"]'),
('a62b2ad6-53ae-4a99-b323-9ff43a6692d7','僧廬','陸游','宋','宋诗','song-poetry','','[]','僧廬土木塗金碧，四出徴求如羽檄。',128,'全唐诗/poet.song.130000.json','["僧廬土木塗金碧，四出徴求如羽檄。", "富商豪吏多厚積，宜其棄金如瓦礫。", "貧民妻子半菽食，一饑轉作溝中瘠。", "賦斂鞭笞縣庭赤，持以與僧亦不惜。", "古者養民如養兒，勸相農事憂其饑。", "露臺百金止不爲，尚愧七月周公詩。", "流俗紛紛豈知此，熟視創殘謂當爾。", "傑屋大像無時止，安得疲民免饑死。"]'),
('61c780d7-32b1-4c64-b721-f5726745c780','春日','陸游','宋','宋诗','song-poetry','','[]','節節足足雀噪檐，朱朱白白花窺簾。',64,'全唐诗/poet.song.130000.json','["節節足足雀噪檐，朱朱白白花窺簾。", "坐旁設酒隨時飲，床上堆書信手拈。", "寓世無求猶役役，杜門不病亦厭厭。", "春濃日永有佳處，睡味著人如蜜甜。"]'),
('0901eb87-83cf-49ce-bc45-33c63dea453e','春遊','陸游','宋','宋诗','song-poetry','','[]','鏡湖春遊甲吳越，鶯花如海城南陌。',96,'全唐诗/poet.song.130000.json','["鏡湖春遊甲吳越，鶯花如海城南陌。", "十里笙歌聲不絕，不待清明寒食節。", "青絲玉瓶挈新釀，細柳穿魚初出浪。", "花外金羈絡雪駒，橋邊翠幙圍螭舫。", "怕雨愁陰人未知，時時微雨却相宜。", "養花天色君須記，正在輕雲嫩靄時。"]'),
('1587dd22-2e40-48f3-b924-a6b08d7fed27','懷昔','陸游','宋','宋诗','song-poetry','','[]','昔遇高皇帝，華纓接俊遊。',48,'全唐诗/poet.song.130000.json','["昔遇高皇帝，華纓接俊遊。", "年光一彈指，世事幾浮漚。", "故國但青嶂，羈臣今白頭。", "平生笑李廣，癡絕望封侯。"]'),
('1defa2a8-651c-44cc-8245-2253e30cf0ea','記夢','陸游','宋','宋诗','song-poetry','','[]','夢不出心境，曠然成遠遊。',48,'全唐诗/poet.song.130000.json','["夢不出心境，曠然成遠遊。", "花殘杜城醉，木落華山秋。", "戰血磨長劍，塵痕洗故裘。", "那知覺来處，身卧五湖舟。"]'),
('bc59ed8a-afea-4d67-864b-0b8e858ae0dd','春陰','陸游','宋','宋诗','song-poetry','','[]','老境三年病，新春十日陰。',48,'全唐诗/poet.song.130000.json','["老境三年病，新春十日陰。", "孤舟鏡湖客，萬里玉關心。", "出岫雲多態，呼風鳥獨吟。", "讀書惟恐盡，傾酒却愁深。"]'),
('822ab12e-ee2a-4870-9400-6f4052b0ee7b','睡起行至門外有賦','陸游','宋','宋诗','song-poetry','','[]','窗黑停書課，屏深養病眸。',48,'全唐诗/poet.song.130000.json','["窗黑停書課，屏深養病眸。", "雨聲工破睡，酒力不禁愁。", "兀兀披衣起，昏昏曳杖遊。", "柴荆晚未閉，隔水數歸牛。"]'),
('e987dfd1-58f2-47e2-82e8-2a1d8d9a6f62','早春四首  其一','陸游','宋','宋诗','song-poetry','','[]','舊學樊遲稼，新通汜勝書。',24,'全唐诗/poet.song.130000.json','["舊學樊遲稼，新通汜勝書。", "不成籌國論，且復愛吾廬。"]'),
('36573cfb-b81e-4471-b4fe-a7f8db768bb8','早春四首  其二','陸游','宋','宋诗','song-poetry','','[]','具牛將犢行，野雉挾雌鳴。',24,'全唐诗/poet.song.130000.json','["具牛將犢行，野雉挾雌鳴。", "農事不可緩，閑人亦勸耕。"]'),
('991a4ed1-f5d1-4c1e-821d-094e28ef86df','早春四首  其三','陸游','宋','宋诗','song-poetry','','[]','近陂牛湩白，遠浦鴨頭青。',24,'全唐诗/poet.song.130000.json','["近陂牛湩白，遠浦鴨頭青。", "一櫂悠然去，東風吹酒醒。"]'),
('c1e3595a-41e0-4597-845a-d633eb52c81d','早春四首  其四','陸游','宋','宋诗','song-poetry','','[]','西村一抹烟，柳弱小桃妍。',24,'全唐诗/poet.song.130000.json','["西村一抹烟，柳弱小桃妍。", "要識春風處，先生拄杖前。"]'),
('a33f49d7-5368-4fdc-a4e8-bc7fdcbd2a53','醉吟三首  其一','陸游','宋','宋诗','song-poetry','','[]','少日沉迷汗簡青，如今毁譽兩冥冥。',32,'全唐诗/poet.song.130000.json','["少日沉迷汗簡青，如今毁譽兩冥冥。", "書生弄筆如何信，只合花前醉不醒。"]'),
('b97f0491-715a-4101-bba0-2502edbcadd3','醉吟三首  其二','陸游','宋','宋诗','song-poetry','','[]','驅使難凴赤丁子，傳呼底用蒼頭兒。',32,'全唐诗/poet.song.130000.json','["驅使難凴赤丁子，傳呼底用蒼頭兒。", "世間如夢身如寄，春去花空欲泥誰。"]'),
('0f17922a-53e4-46d3-b02d-b41d5dfda327','醉吟三首  其三','陸游','宋','宋诗','song-poetry','','[]','牽經引禮人誰聴，是古非今世共憎。',32,'全唐诗/poet.song.130000.json','["牽經引禮人誰聴，是古非今世共憎。", "何似對花傾綠酒，自歌一曲醉騰騰。"]'),
('a6b52f74-490c-4bc9-b807-30865c5f8273','贈劉改之秀才','陸游','宋','宋诗','song-poetry','','[]','君居古荆州，醉膽天宇小。',88,'全唐诗/poet.song.130000.json','["君居古荆州，醉膽天宇小。", "尚不拜龐公，况肯依劉表。", "胸中九淵蛟龍蟠，筆底六月冰雹寒。", "有時大叫脫烏幘，不怕酒杯如海寛。", "放翁七十病欲死，相逢尚能刮眼看。", "李廣不生楚漢間，封侯萬户宜其難。"]'),
('0e196649-b18c-42f7-bf74-e6105b9d3663','蓬門','陸游','宋','宋诗','song-poetry','','[]','莫笑蓬門雀可羅，老農正要養天和。',64,'全唐诗/poet.song.130000.json','["莫笑蓬門雀可羅，老農正要養天和。", "穿林裊裊孫登嘯，叩角嗚嗚甯戚歌。", "睡美到明三展轉，飯甘捧腹一摩挲。", "床頭更聴糟床注，造物私吾亦已多。"]'),
('602aa77d-52b6-4a90-bb9c-964630d0f068','龍鍾','陸游','宋','宋诗','song-poetry','','[]','龍鍾一老寄荒村，鼎食山棲久已分。',64,'全唐诗/poet.song.130000.json','["龍鍾一老寄荒村，鼎食山棲久已分。", "平日氣吞雲夢澤，莫年緣在武夷君。", "搶榆敢羨垂天翼，倚市從嗤刺繡文。", "幸有筆床茶竈在，孤舟更入剡溪雲。"]'),
('f6113660-59a6-4214-9976-b9259b6f1d85','送佛照光老赴徑山','陸游','宋','宋诗','song-poetry','','[]','大覺住育王，拗折拄杖强到底。',120,'全唐诗/poet.song.130000.json','["大覺住育王，拗折拄杖强到底。", "佛照住育王，挑得鉢囊隨詔起。", "從来宗門話，只要句不死。", "說同說異庵外人，若是吾宗寜有此。", "日日風雨今日晴，萬里春光入帝城。", "傳宣江上走中使，開堂座下羅公卿。", "御香靄靄雲共布，法音浩浩潮收聲。", "報恩一句作麽道，常遣山林見太平。"]'),
('f173be3c-139b-496c-befc-50fe129d4d0c','春社有感','陸游','宋','宋诗','song-poetry','','[]','憔悴前朝白髮郎，祠庭賦祿玷恩光。',64,'全唐诗/poet.song.130000.json','["憔悴前朝白髮郎，祠庭賦祿玷恩光。", "寸心未與年俱老，萬事惟憑酒暫忘。", "穿仗兩曾觀揖遜，扶犂獨幸返耕桑。", "耆年凋落還堪嘆，社飲推排冠一鄉。"]'),
('a290bcbf-4c52-43e1-9353-916b9c54c046','春社四首  其一','陸游','宋','宋诗','song-poetry','','[]','桑眼初開麥正青，勃姑聲裏雨冥冥。',32,'全唐诗/poet.song.130000.json','["桑眼初開麥正青，勃姑聲裏雨冥冥。", "今朝有喜君知否，到處人家醉不醒。"]'),
('0a298e59-d031-4a12-a775-2fff6d3aaff3','春社四首  其二','陸游','宋','宋诗','song-poetry','','[]','社肉如林社酒濃，鄉鄰羅拜祝年豐。',32,'全唐诗/poet.song.130000.json','["社肉如林社酒濃，鄉鄰羅拜祝年豐。", "太平氣象吾能說，盡在鼕鼕社鼓中。"]'),
('fa0de73a-1db5-40ae-9bc2-125149637af1','春社四首  其三','陸游','宋','宋诗','song-poetry','','[]','柴門西畔枕陂塘，社雨新添一尺强。',32,'全唐诗/poet.song.130000.json','["柴門西畔枕陂塘，社雨新添一尺强。", "臺省諸公方衮衮，故應分喜到耕桑。"]'),
('2a87b9e7-16d9-4173-b08a-c44707475f96','春社四首  其四','陸游','宋','宋诗','song-poetry','','[]','太平處處是優場，社日兒童喜欲狂。',32,'全唐诗/poet.song.130000.json','["太平處處是優場，社日兒童喜欲狂。", "且看參軍喚蒼鶻，京都新禁舞齋郎。"]'),
('f7164ac6-20ff-4811-9f6c-34a85062750c','村夜','陸游','宋','宋诗','song-poetry','','[]','寂寂山村夜，悠然醉倚門。',48,'全唐诗/poet.song.130000.json','["寂寂山村夜，悠然醉倚門。", "月昏天有暈，風軟水無痕。", "迹爲遭讒遠，身由不仕尊。", "敢嗟車馬絕，同社自雞豚。"]'),
('d4ec11f8-1f71-4ea3-b3f3-9da548af44aa','山園遣興','陸游','宋','宋诗','song-poetry','','[]','輸逋告糴走比鄰，恤患分灾累故人。',32,'全唐诗/poet.song.130000.json','["輸逋告糴走比鄰，恤患分灾累故人。", "安得此身無一事，林中數筍過殘春。"]'),
('e651049c-cb24-400e-8563-903e504b25f9','次韵陳機宜見贈','陸游','宋','宋诗','song-poetry','','[]','邂逅今年得若人，翛然不染庾公塵。',64,'全唐诗/poet.song.130000.json','["邂逅今年得若人，翛然不染庾公塵。", "思幽屈子歌山鬼，語妙陳王賦洛神。", "初接笑談忘老憊，熟觀風度愛清真。", "花時飛盡頻行樂，莫學衰翁睡過春。"]'),
('a7d69eed-700c-4a64-8f85-7d18852b68ab','野意','陸游','宋','宋诗','song-poetry','','[]','堤長逾十里，村小只三家。',48,'全唐诗/poet.song.130000.json','["堤長逾十里，村小只三家。", "山客弛樵擔，溪翁鳴釣車。", "花深迷蝶夢，雨急散蜂衙。", "衰疾新年減，青鞵上若耶。"]'),
('f4fed0ae-fb21-4b49-9dba-6078a3844998','戒殺','陸游','宋','宋诗','song-poetry','','[]','物生天地間，同此一太虚。',168,'全唐诗/poet.song.130000.json','["物生天地間，同此一太虚。", "林林各自植，但坐形骸拘。", "日夜相殘殺，曾不置斯須。", "皮毛備裘褐，膏血資甘腴。", "雞鶩羊彘輩，尚食稗與芻。", "飛潛何與汝，禍乃及禽魚。", "豺虎之害人，亦爲饑所驅。", "汝顧不自省，何暇議彼歟。", "又于人類中，各私六尺軀。", "方其忿怒時，流血視若無。", "我欲反其源，黙觀受氣初。", "挺刃之所加，慘若在我膚。", "朝飯一鬴豆，莫飯一杯蔬。", "捫腹茆檐下，陶然歡有餘。"]'),
('641ea684-16ab-4943-a38e-1f8ab7105169','余年四十六入峽忽復二十三年感懷賦長句','陸游','宋','宋诗','song-poetry','','[]','當年吊古巴東峽，雪灑扁舟見早梅。',64,'全唐诗/poet.song.130000.json','["當年吊古巴東峽，雪灑扁舟見早梅。", "宋玉宅邊新酒美，巫山廟下莫猿哀。", "樵柯爛盡棋方劇，客甑炊成夢未回。", "已把癡頑敵憂患，不勞團扇念寒灰。"]'),
('cb0cde81-7720-4eec-9406-b9e8f0d14c6a','山行','陸游','宋','宋诗','song-poetry','','[]','七十衰翁短鬢斑，藥瓢藤杖伴清閑。',64,'全唐诗/poet.song.130000.json','["七十衰翁短鬢斑，藥瓢藤杖伴清閑。", "平生惡路羊腸坂，晚歲羸軀飯顆山。", "一寸塔餘青靄外，數聲鐘下翠微間。", "往来處處皆奇絕，莫道先生興盡還。"]'),
('853c1883-935a-43f1-ad3c-34a18808cb53','雨中排悶','陸游','宋','宋诗','song-poetry','','[]','一春苦沉陰，未省見桃李。',48,'全唐诗/poet.song.130000.json','["一春苦沉陰，未省見桃李。", "已逢暗寒食，更值雨甲子。", "重雲失南山，寸步困泥滓。", "籜龍已𧥄𧥄，一飽差可喜。"]'),
('bc8f2244-f007-4fd6-94a6-07536fa80971','杜敬叔寓僧舍開軒松下以虚瀨名之来求詩','陸游','宋','宋诗','song-poetry','','[]','君不見洛陽八節灘，未至一舍聞驚湍。',130,'全唐诗/poet.song.130000.json','["君不見洛陽八節灘，未至一舍聞驚湍。", "生綃六幅誰所畫，入眼能令三伏寒。", "又不見桐廬七里瀨，濺雪跳珠舞澎湃。", "羊裘老子去千年，絕世孤風凜如在。", "杜陵之孫今勝遊，飄然不必事遠遊。", "結茆古寺聴松吹，坐擅洛水桐江秋。", "放翁百念倶已矣，獨有好奇心未死。", "約君少待秋月明，抱琴来宿寫灘聲。"]'),
('007fce62-da8b-4cbf-8cbe-2f8a2c1d0dde','贈徑山銛書記','陸游','宋','宋诗','song-poetry','','[]','徑山老將無勍敵，百萬魔軍俱掃迹。',128,'全唐诗/poet.song.130000.json','["徑山老將無勍敵，百萬魔軍俱掃迹。", "座下何人策雋功，籌略縱横銛記室。", "銛公聲名滿吳會，惟有放翁最先識。", "奕奕揮毫王粲詩，翩翩插羽陳琳檄。", "風雷東海起伏龍，繅藉圜丘薦蒼璧。", "徑山入門第一義，萬口譁言真稱職。", "我謂銛公豈止此，徑山鉢袋渠能得。", "一枝白拂倘付之，會見青天飛霹靂。"]'),
('638aa83f-d2f3-4251-aac9-9d72e307f1f5','五月一日作','陸游','宋','宋诗','song-poetry','','[]','處處稻分秧，家家麥上場。',48,'全唐诗/poet.song.130000.json','["處處稻分秧，家家麥上場。", "敢悲身老大，獨幸歲豐穰。", "酪美朱櫻熟，菰青角黍香。", "翛然一竹几，飽受北窗涼。"]'),
('51d988af-8dae-4700-bcf2-e0662dafaf15','春夏之交衰病相仍過芒種始健戲作','陸游','宋','宋诗','song-poetry','','[]','藥裹關心百不知，可憐筆硯鎖蛛絲。',64,'全唐诗/poet.song.130000.json','["藥裹關心百不知，可憐筆硯鎖蛛絲。", "倒壺猶有莫春酒，開卷遂無初夏詩。", "户外逢人驚隔濶，燈前顧影嘆支離。", "癡頑未伏常愁卧，鼓缶長謡樂聖時。"]'),
('47699adb-fda0-4d2d-a4f8-f20e892cf9ae','自嗟','陸游','宋','宋诗','song-poetry','','[]','青蔬半畆老生涯，霜鬢蕭蕭只自嗟。',64,'全唐诗/poet.song.130000.json','["青蔬半畆老生涯，霜鬢蕭蕭只自嗟。", "勛業蹉跎空許國，文詞淺俗不名家。", "殘骸皆作麒麟楦，舊友仍非處士牙。", "收得平生釣竿手，長安西日更須遮。"]'),
('a4af3f35-5e97-4e7c-8183-4d434e10d6bd','枕上述夢','陸游','宋','宋诗','song-poetry','','[]','江湖送老一漁舟，清夢猶成塞上遊。',64,'全唐诗/poet.song.130000.json','["江湖送老一漁舟，清夢猶成塞上遊。", "生馬駒馳鐵蹏踠，古鐃歌奏錦衣褠。", "玉關雪急傳烽火，青海雲開見戍樓。", "白首不侯非所恨，咿嚶床簀死堪羞。"]'),
('0b09f24a-6e04-4e5b-9759-0360f4b2a16d','雨中排悶','陸游','宋','宋诗','song-poetry','','[]','潤入盆山綠葉稠，倦攤書帙小窗幽。',64,'全唐诗/poet.song.130000.json','["潤入盆山綠葉稠，倦攤書帙小窗幽。", "浮雲不卷時時雨，薄酒無功日日愁。", "積潦漲来妨躡屐，好山遮盡罷登樓。", "青秧揺蕩湖堤決，一飽前知未易謀。"]'),
('442638b3-999a-4fc2-87de-0223c93a3e2e','小軒夏夜涼甚偶得長句呈杜叔高秀才','陸游','宋','宋诗','song-poetry','','[]','遥夜簾櫳已借秋，闌干星斗挂檐頭。',64,'全唐诗/poet.song.130000.json','["遥夜簾櫳已借秋，闌干星斗挂檐頭。", "鵲翻清影移枝宿，螢弄孤光拂簟流。", "榻上琴書紛枕籍，髮根風露冷颼飀。", "故人莫笑幽居陋，此夕真從造物遊。"]'),
('423bcaeb-b5a8-435a-90ae-bb622805879c','憶昔','陸游','宋','宋诗','song-poetry','','[]','憶昔西征日，飛騰尚少年。',120,'全唐诗/poet.song.130000.json','["憶昔西征日，飛騰尚少年。", "軍書插鳥羽，戍壘候狼烟。", "渭水秋風夜，岐山曉雪天。", "金鞿馳叱撥，繡袂舞嬋娟。", "但恨功名晚，寜知老病纒。", "虎頭空有相，麟閣竟無緣。", "壯士埋巴峽，孤身卧海壖。", "安西九千里，孫武十三篇。", "裘嘆蘇秦弊，鞭憂祖逖先。", "何時聞詔下，遣將入幽燕。"]'),
('05970631-921f-48cc-b6bd-1841ed4a66b8','夏日晚興','陸游','宋','宋诗','song-poetry','','[]','高挂虚窗對綠池，鳥啼聲歇柳陰移。',64,'全唐诗/poet.song.130000.json','["高挂虚窗對綠池，鳥啼聲歇柳陰移。", "含風珍簟閑眠處，疊雪輕衫新浴時。", "泉冷甘瓜開碧玉，手香素藕罥長絲。", "夕陽四面漁歌起，又赴鄰翁把釣期。"]'),
('71136800-0f8a-4277-9b02-68408fd5ccde','老翁','陸游','宋','宋诗','song-poetry','','[]','老翁垂七十，不復嘆頭顱。',48,'全唐诗/poet.song.130000.json','["老翁垂七十，不復嘆頭顱。", "浩蕩新漁艇，凋零舊酒徒。", "嚴徐元衮衮，管葛亦區區。", "獨有欣然處，登山未用扶。"]'),
('90261c29-7ef2-4c95-aa79-595784eeca5a','困甚戲書','陸游','宋','宋诗','song-poetry','','[]','官如枝頭乾，不受雨露恩。',96,'全唐诗/poet.song.130000.json','["官如枝頭乾，不受雨露恩。", "身如水上浮，泛泛寜有根。", "刈茆以苫屋，縛柴以爲門。", "故人分祿米，鄰父餉魚飱。", "前門吏徴租，後門質襦禈。", "不敢謀歲月，且復支朝昏。", "雨餘幽花拆，亦可侑清尊。", "吾生信已乎，終老此山村。"]'),
('f0c50c9b-814b-4910-84d3-e4364231e68e','歲晚','陸游','宋','宋诗','song-poetry','','[]','日月忽其逝，吾生猶幾何。',48,'全唐诗/poet.song.130000.json','["日月忽其逝，吾生猶幾何。", "不從屠狗醉，即和飯牛歌。", "斧鉞稽天討，金繒約虜和。", "無情恨荆棘，歲晚暗銅駝。"]'),
('c5c157e1-39af-4269-95b3-8a4be91bc46b','戲詠山陰風物','陸游','宋','宋诗','song-poetry','','[]','萬里秦吳稅駕遲，還鄉已嘆鬢成絲。',64,'全唐诗/poet.song.130000.json','["萬里秦吳稅駕遲，還鄉已嘆鬢成絲。", "城邊緑樹山陰道，水際朱扉夏禹祠。", "項里楊梅鹽可徹，湘湖蓴菜豉偏宜。", "圖經草草常堪恨，好事他年采此詩。"]'),
('260f569f-6daf-4957-9457-9af54f029562','老健','陸游','宋','宋诗','song-poetry','','[]','才智不足狂有餘，此身老健更誰如。',64,'全唐诗/poet.song.130000.json','["才智不足狂有餘，此身老健更誰如。", "齒牢尚可決乾肉，目瞭未妨觀細書。", "不怪模稜嗤了了，但驚紾臂勸徐徐。", "曉看瓜壟初牽蔓，一笑呼兒勿廢鉏。"]'),
('c25888e2-1f17-42f2-a154-f72b3ba5d669','六月晦日作','陸游','宋','宋诗','song-poetry','','[]','長夏忽云過，徂年行且休。',48,'全唐诗/poet.song.130000.json','["長夏忽云過，徂年行且休。", "川原方渴雨，草木已驚秋。", "露蔓晨猶泫，風蟬莫更遒。", "明窗對清鏡，世事判悠悠。"]'),
('0aefd985-6070-4567-a414-ece450c67db9','喜雨','陸游','宋','宋诗','song-poetry','','[]','雷車隆隆南山陽，電光煜煜北斗傍。',96,'全唐诗/poet.song.130000.json','["雷車隆隆南山陽，電光煜煜北斗傍。", "急雨横斜生土香，草木蘇醒起仆僵。", "芭蕉抽心鳯尾長，薜茘引蔓龍鱗蒼。", "葛幮竹簟夜更涼，超然真欲無羲皇。", "常年七月蚊殷廊，今夕肅肅疑飛霜。", "水車罷踏戽斗藏，家家買酒歌時康。"]'),
('44e81fc4-0922-491c-acb4-3e168d837bcc','門外納涼','陸游','宋','宋诗','song-poetry','','[]','玄雲障落日，早得數刻涼。',96,'全唐诗/poet.song.130000.json','["玄雲障落日，早得數刻涼。", "寒泉灑門前，浴罷倚胡床。", "蟬聲晚逾壯，藕花凋更香。", "嘯咏忽已久，野色来蒼蒼。", "新月淡無輝，大星森有芒。", "水鳥亦歸宿，飛鳴掠横塘。", "人生各有時，何至終身忙。", "撫髀三太息，墜露濕衣裳。"]'),
('4d1f4e01-b913-4c54-a543-5d2e44aa4149','贈蘇趙叟兄弟','陸游','宋','宋诗','song-poetry','','[]','君家真德門，才傑生衮衮。',72,'全唐诗/poet.song.130000.json','["君家真德門，才傑生衮衮。", "託契則甚深，所恨相識晚。", "擕文數過我，每讀必三反。", "譬如天廐駒，真是渥洼産。", "閉門萬卷讀，更要極源本。", "才難聖所嘆，期子敢不遠。"]'),
('b59cfc1d-e8ba-4e96-a843-4d661fc8fae1','癸丑七夕','陸游','宋','宋诗','song-poetry','','[]','風露中庭十丈寛，天河仰視白漫漫。',64,'全唐诗/poet.song.130000.json','["風露中庭十丈寛，天河仰視白漫漫。", "難尋仙客乘槎路，且伴吾兒乞巧盤。", "秋早時聞桐葉墜，夜涼已怯紵衣單。", "民無餘力年多惡，退士私憂實萬端。"]'),
('2d614b19-3453-426e-b4dd-bf01801b37cb','共語','陸游','宋','宋诗','song-poetry','','[]','喬嶽成塵巨海枯，欲求共語一人無。',32,'全唐诗/poet.song.130000.json','["喬嶽成塵巨海枯，欲求共語一人無。", "黄金已作飛烟去，癡漢終身守藥爐。"]'),
('e9ef7fd6-edd4-40e5-a58f-ea802d996e8c','書嘆','陸游','宋','宋诗','song-poetry','','[]','少年志欲掃胡塵，至老寜知不少伸。',64,'全唐诗/poet.song.130000.json','["少年志欲掃胡塵，至老寜知不少伸。", "覽鏡已悲身潦倒，横戈空覺膽輪囷。", "生無鮑叔能知已，死有要離與卜鄰。", "西望不須揩病眼，長安冠劍幾番新。"]'),
('bfe8785f-ddcc-4e44-bacd-49f686df304b','秋曉倚闌','陸游','宋','宋诗','song-poetry','','[]','雲罅纖纖玉一鉤，小庭風露更清柔。',32,'全唐诗/poet.song.130000.json','["雲罅纖纖玉一鉤，小庭風露更清柔。", "老来朋舊凋零盡，獨倚闌干特地愁。"]'),
('498cb8cc-ceda-4444-81f5-91e4856963fb','癸丑七月二十七夜夢遊華嶽廟二首  其一','陸游','宋','宋诗','song-poetry','','["\u534e\u5c71"]','驛樹秋風急，關城暮角悲。',24,'全唐诗/poet.song.130000.json','["驛樹秋風急，關城暮角悲。", "平生忠憤意，来拜華山祠。"]'),
('ac5c88e2-f02a-419c-ba62-fcf4d209355a','癸丑七月二十七夜夢遊華嶽廟二首  其二','陸游','宋','宋诗','song-poetry','','["\u534e\u5c71"]','牲碑别正朔，祠祝虜衣冠。',24,'全唐诗/poet.song.130000.json','["牲碑别正朔，祠祝虜衣冠。", "神亦豈堪此，出門山雨寒。"]'),
('3867e4bb-4f82-4576-ba59-221cc71d7e1e','僕頃在征西大幕登高望關輔樂之毎冀王師拓定得卜居焉暇日記此意以示子孫','陸游','宋','宋诗','song-poetry','','[]','八月殘暑退，秋聲滿庭樹。',84,'全唐诗/poet.song.130000.json','["八月殘暑退，秋聲滿庭樹。", "豈無四方志，衰病迫霜露。", "南北會當一，老我悲不遇。", "子孫勉西遷，俗厚吾所慕。", "約已收孤嫠，教子立門户。", "黍稌暗阡陌，鶉雉足匕箸。", "永爲河渭民，勿憚關山路。"]'),
('fbf42834-6087-40d2-8471-1741b107edd4','讀陶詩','陸游','宋','宋诗','song-poetry','','[]','我詩慕淵明，恨不造其微。',48,'全唐诗/poet.song.130000.json','["我詩慕淵明，恨不造其微。", "退歸亦已晚，飲酒或庶幾。", "雨餘鉏瓜壟，月下坐釣磯。", "千載無斯人，吾將誰與歸。"]'),
('2a6aea7a-9e80-4608-8dcf-dd072f7f30d6','秋夜感舊十二韵','陸游','宋','宋诗','song-poetry','','[]','冷螢綴蓬根，忽復照高樹。',144,'全唐诗/poet.song.130000.json','["冷螢綴蓬根，忽復照高樹。", "年光逝不留，百感集遲暮。", "往者秦蜀間，慷慨事征戍。", "猿啼鬼迷店，馬噤飛石鋪。", "危嶺高入雲，朽棧劣容步。", "天近星宿大，江惡蛟鼉怒。", "意氣頗自奇，性命那復顧。", "最懷清渭上，衝雪夜掠渡。", "封侯細事爾，所冀垂竹素。", "兜鍪竟何成，豈獨儒冠誤。", "當時妄校尉，旗纛今照路。", "浩歌遂成章，聊慰老不遇。"]'),
('ec511062-7bcf-43e2-a61b-c1ff117a8845','幽居','陸游','宋','宋诗','song-poetry','','[]','海澨結茆新，退藏常畏人。',48,'全唐诗/poet.song.130000.json','["海澨結茆新，退藏常畏人。", "已侵垂老境，尚愛不貲身。", "丹竈長生藥，巢居上古民。", "秋来有奇事，鷗鷺日相親。"]'),
('b622b87d-1481-44fb-be36-f77208ae94b9','醉題','陸游','宋','宋诗','song-poetry','','[]','勿笑山翁病滿軀，胸中俠氣未全無。',64,'全唐诗/poet.song.130000.json','["勿笑山翁病滿軀，胸中俠氣未全無。", "雙瞳遇醉猶如電，五木隨呼盡作盧。", "代北軍人富羊馬，江南奇士出菰蘆。", "何由親奉平戎詔，蹴踏關中建帝都。"]'),
('a5a84907-5481-432b-9937-d858154c3f9d','雨涼小飲戲作','陸游','宋','宋诗','song-poetry','','[]','孤村小院雨輸涼，團扇流塵簟避床。',64,'全唐诗/poet.song.130000.json','["孤村小院雨輸涼，團扇流塵簟避床。", "蛩思感秋吟壊壁，螢光乘暗遶高梁。", "巾箱字細成褫懶，閤醁杯深斷送狂。", "坐睡覺来人已散，簾櫳時度玉簮香。"]'),
('7718693f-0b96-4578-aacb-5c33a965d66f','題齋壁','陸游','宋','宋诗','song-poetry','','[]','迹是滄浪客，家居䆉稏村。',48,'全唐诗/poet.song.130000.json','["迹是滄浪客，家居䆉稏村。", "秋菰芼羮滑，社酒带醅渾。", "勛業知難遂，文章不更論。", "惟餘此身在，分付與乾坤。"]'),
('8a8eb022-3aad-44c2-a549-186d5b17899f','書憤','陸游','宋','宋诗','song-poetry','','[]','山河自古有乖分，京洛腥膻實未聞。',64,'全唐诗/poet.song.130000.json','["山河自古有乖分，京洛腥膻實未聞。", "劇盜曾從宗父命，遺民猶望岳家軍。", "上天悔禍終平虜，公道何人肯散群。", "白首自知疏報國，尚憑精意祝爐熏。"]'),
('f40f9057-f091-4634-ba0a-2bf4448ac4fe','秋興','陸游','宋','宋诗','song-poetry','','[]','秋風又滿會稽城，有客飄然萬事輕。',64,'全唐诗/poet.song.130000.json','["秋風又滿會稽城，有客飄然萬事輕。", "久向林間得佳趣，不知身外有浮名。", "葡萄雨足初全紫，烏桕霜前已半頳。", "欲把一杯終覺懶，老来懷抱爲誰傾。"]'),
('fb9cb9f2-d585-492b-b66b-955be4807145','雨夜排悶二首  其一','陸游','宋','宋诗','song-poetry','','[]','羸病愁燈影，羈懷怯雨聲。',48,'全唐诗/poet.song.130000.json','["羸病愁燈影，羈懷怯雨聲。", "新秋忽已半，垂老若爲情。", "金印兒嬉事，青編身後名。", "何如破窗下，袖手送餘生。"]'),
('b557e334-764e-4077-adf4-41388163f40f','雨夜排悶二首  其二','陸游','宋','宋诗','song-poetry','','[]','村巷時時雨，江城夜夜砧。',48,'全唐诗/poet.song.130000.json','["村巷時時雨，江城夜夜砧。", "沉憂羈客夢，孤憤遠臣心。", "身病常須藥，囊空未贖琴。", "明朝鏡中髮，飽受雪霜侵。"]'),
('c266dd27-ea87-4ba7-8697-90f5f7fd8425','秋日出遊戲作二首  其一','陸游','宋','宋诗','song-poetry','','[]','箬帽簑衣自道宜，不論晴雨著無時。',32,'全唐诗/poet.song.130000.json','["箬帽簑衣自道宜，不論晴雨著無時。", "半醒半醉人爭看，是聖是凡誰得知。"]'),
('f26d9e32-8071-41e6-a3ac-2289b0c0eedd','秋日出遊戲作二首  其二','陸游','宋','宋诗','song-poetry','','[]','薄雲韜日未成雨，野水齧沙爭赴溪。',32,'全唐诗/poet.song.130000.json','["薄雲韜日未成雨，野水齧沙爭赴溪。", "書册懶看聊作伴，酒壺不飲亦常擕。"]'),
('87c6bc87-d2d7-4d5e-b6ac-99efe66c65dd','雨中夕食戲作三首  其一','陸游','宋','宋诗','song-poetry','','[]','高秋滴階雨作泥，黄昏爭林雀欲棲。',32,'全唐诗/poet.song.130000.json','["高秋滴階雨作泥，黄昏爭林雀欲棲。", "臨窗一飯頗簡快，半升脫粟澆黄虀。"]'),
('961b85d2-e8c9-4ffa-b0e8-d57f29ac2d09','雨中夕食戲作三首  其二','陸游','宋','宋诗','song-poetry','','[]','粗飯寒菹到手空，屬饜也與八珍同。',32,'全唐诗/poet.song.130000.json','["粗飯寒菹到手空，屬饜也與八珍同。", "家人見慣渾閑事，笑殺新来兩髻童。"]'),
('396fd3e2-7e66-46c1-afdf-1dda3f8d1ae8','雨中夕食戲作三首  其三','陸游','宋','宋诗','song-poetry','','[]','粳粒微紅愧食珍，蕨芽初白喜嘗新。',32,'全唐诗/poet.song.130000.json','["粳粒微紅愧食珍，蕨芽初白喜嘗新。", "摩挲便腹無憂責，我是人間得計人。"]'),
('50d64b0d-3c27-464b-bb34-f8c5d7086c6e','自警','陸游','宋','宋诗','song-poetry','','[]','墮髮滿晨梳，荒畦入晚鉏。',48,'全唐诗/poet.song.130000.json','["墮髮滿晨梳，荒畦入晚鉏。", "涼生團扇阨，病退短笻疏。", "聖道功殊淺，塵緣習未除。", "青燈幸如故，勉近讀殘書。"]'),
('1cd11b4c-ac30-495c-ab54-b5c9a85d89b7','寄方瞳胡先生','陸游','宋','宋诗','song-poetry','','[]','形槁神彌王，心虚腦自凝。',48,'全唐诗/poet.song.130000.json','["形槁神彌王，心虚腦自凝。", "平生一酒榼，萬里兩行縢。", "安枕存玄牝，齋居養絳陵。", "他年喬嶽下，正晝看飛騰。"]'),
('53a4f3b8-755a-4a9c-8e5d-842abd5d5928','雨夕焚香','陸游','宋','宋诗','song-poetry','','[]','芭蕉葉上雨催涼，蟋蟀聲中夜漸長。',32,'全唐诗/poet.song.130000.json','["芭蕉葉上雨催涼，蟋蟀聲中夜漸長。", "繙十二經真太漫，與君共此一爐香。"]'),
('c2dff563-cac0-479b-8179-9eefa061b582','秋雨初霽徙倚門外有作','陸游','宋','宋诗','song-poetry','','[]','三十餘年此結廬，客来不用笑迂疏。',64,'全唐诗/poet.song.130000.json','["三十餘年此結廬，客来不用笑迂疏。", "前身已預蘭亭會，老眼曾窺禹穴書。", "浮甕社醅香出屋，登場秋稼穗盈車。", "蕭蕭蓬鬢雖衰矣，追逐鄉鄰尚有餘。"]'),
('831cc07e-4bfe-48e3-a677-4d6015490483','雨中作','陸游','宋','宋诗','song-poetry','','[]','野外偏于看雨宜，映空渡水細如絲。',64,'全唐诗/poet.song.130000.json','["野外偏于看雨宜，映空渡水細如絲。", "川雲借潤支琴石，磵水分流洗藥池。", "未肯高眠成老態，却緣危坐得新詩。", "悠然更助鄰丁喜，漸近收蕎下麥時。"]'),
('92012cdd-2d55-47b1-9083-6bd0cdba44ba','贈老雞二首  其一','陸游','宋','宋诗','song-poetry','','[]','峨峨赤幘先群輩，喔喔長鳴盖四郊。',32,'全唐诗/poet.song.130000.json','["峨峨赤幘先群輩，喔喔長鳴盖四郊。", "意氣雖雄無處用，風霜從我老衡茅。"]'),
('a6a3c969-7335-4280-a75c-f2ae4a330130','贈老雞二首  其二','陸游','宋','宋诗','song-poetry','','[]','場中啄粟樹頭棲，三唱明星出尚低。',32,'全唐诗/poet.song.130000.json','["場中啄粟樹頭棲，三唱明星出尚低。", "關路元無孟嘗客，吳兒莫議會稽雞。"]'),
('8d7115f7-d14b-46ec-a878-adb65c074647','秋晚閑步鄰曲以予近嘗卧病皆欣然迎勞','陸游','宋','宋诗','song-poetry','','[]','放翁病起出門行，績女窺籬牧豎迎。',64,'全唐诗/poet.song.130000.json','["放翁病起出門行，績女窺籬牧豎迎。", "酒似粥醲知社到，餅如盤大喜秋成。", "歸来早覺人情好，對此彌將世事輕。", "紅樹青山只如昨，長安拜免幾公卿。"]'),
('1867d8b2-3c18-4d66-a23e-06b649f4121f','雨夜','陸游','宋','宋诗','song-poetry','','[]','歲晚茆茨劣自容，齒揺將脫髮將童。',64,'全唐诗/poet.song.130000.json','["歲晚茆茨劣自容，齒揺將脫髮將童。", "心遊萬里關河外，身卧一窗風雨中。", "醫不可招惟忍病，書猶能讀足忘窮。", "夜闌睡覺蛩聲裏，時見燈花落碎紅。"]'),
('73b945db-3679-418b-bee1-6d2b809e9b8c','醉卧道傍','陸游','宋','宋诗','song-poetry','','[]','爛醉今朝卧道傍，鄉閭共爲護牛羊。',64,'全唐诗/poet.song.130000.json','["爛醉今朝卧道傍，鄉閭共爲護牛羊。", "高懷那遣群兒覺，至理真能萬事忘。", "喚起瘦軀猶嵬峨，扶歸困睫更芒洋。", "凍韲快嚼茆簷下，拍手從人笑老狂。"]'),
('eb71e145-e65e-4ee5-b1c6-419e333191a1','枕上聞急雨二首  其一','陸游','宋','宋诗','song-poetry','','[]','枕上雨聲如許奇，殘荷叢竹共催詩。',32,'全唐诗/poet.song.130000.json','["枕上雨聲如許奇，殘荷叢竹共催詩。", "喚回二十三年夢，燈火雲安驛裏時。"]'),
('e1844952-27ed-4f27-9557-029a3dae3035','枕上聞急雨二首  其二','陸游','宋','宋诗','song-poetry','','[]','酒病羈愁一洗空，長歌高枕雨聲中。',32,'全唐诗/poet.song.130000.json','["酒病羈愁一洗空，長歌高枕雨聲中。", "傳聞溪港深三尺，明日扁舟處處通。"]'),
('03b14e0a-4cf1-4d0d-a4f8-d7f456b30746','得趙若川書因寄','陸游','宋','宋诗','song-poetry','','[]','澤居路絕人不到，晨起忽傳雙鯉魚。',64,'全唐诗/poet.song.130000.json','["澤居路絕人不到，晨起忽傳雙鯉魚。", "儲泪一升悲世事，減愁三尺看君書。", "龍墀對筞言傷直，山邑迎親計未疏。", "老病閉門誰省録，因風時肯問何如。"]'),
('536bdfc1-cab7-4d41-8c11-e365e56d5e4f','夢至洛中觀牡丹繁麗溢目覺而有賦','陸游','宋','宋诗','song-poetry','','[]','兩京初駕小羊車，憔悴江湖歲月賖。',64,'全唐诗/poet.song.130000.json','["兩京初駕小羊車，憔悴江湖歲月賖。", "老去已忘天下事，夢中猶看洛陽花。", "妖魂艶骨千年在，朱彈金鞭一笑譁。", "寄語氈裘莫癡絕，祁連還汝舊風沙。"]'),
('e3100edd-0519-4087-bc88-31045dae4eb3','閑居對食書愧二首  其一','陸游','宋','宋诗','song-poetry','','[]','遊宦無功坐免歸，誰令盤筯極甘肥。',64,'全唐诗/poet.song.130000.json','["遊宦無功坐免歸，誰令盤筯極甘肥。", "錦鱗差尾魚登俎，繡羽駢頭雉觸機。", "桑落滿壺春盎盎，雨前轉磑雪霏霏。", "殘年何地酬君賜，自古羈臣厭蕨薇。"]'),
('dd031cca-7bc1-43d0-b8a6-8ee83b98457b','閑居對食書愧二首  其二','陸游','宋','宋诗','song-poetry','','[]','老病家居幸歲穰，味兼南北飫枯腸。',64,'全唐诗/poet.song.130000.json','["老病家居幸歲穰，味兼南北飫枯腸。", "滿脾蜜熟餦餭美，下棧羊肥餺飥香。", "撥剌河魴初出水，迷離穴兔正迎霜。", "山僧一鉢無餘念，應笑先生爲口忙。"]'),
('c8ac7771-ff13-4ccb-804a-bfeafb45c814','秋夜獨酌','陸游','宋','宋诗','song-poetry','','[]','壯志隨年減，羈愁與夜長。',48,'全唐诗/poet.song.130000.json','["壯志隨年減，羈愁與夜長。", "月高寒暈淡，花坼露叢香。", "仕畏讒銷骨，歸判酒腐腸。", "青燈寫孤影，相勸盡餘觴。"]'),
('e7806568-db8b-463c-abd8-e0dc783663e1','風雲交作戲題','陸游','宋','宋诗','song-poetry','','[]','雲脚如龍爪，空中挾雨来。',24,'全唐诗/poet.song.130000.json','["雲脚如龍爪，空中挾雨来。", "何關風伯事，欲到却吹回。"]'),
('8b36628f-462d-483e-b194-aea0a4c8fec3','自嘲','陸游','宋','宋诗','song-poetry','','[]','歲月推遷萬事非，放翁可笑白頭癡。',64,'全唐诗/poet.song.130000.json','["歲月推遷萬事非，放翁可笑白頭癡。", "此生竟出古人下，有志尚如年少時。", "僻學固應知者少，長歌莫問和予誰。", "自嘲自解君毋怪，老大從人百不宜。"]'),
('5e97ab72-e3af-4833-b73f-43a4e32f9fc8','書室','陸游','宋','宋诗','song-poetry','','[]','客来莫笑席塵凝，静處工夫却少增。',64,'全唐诗/poet.song.130000.json','["客来莫笑席塵凝，静處工夫却少增。", "黑蟻常繙魯壁簡，瘦蛟時落越溪藤。", "尚能豪健如霜鶻，未遽衰殘學凍蠅。", "更喜論文有兒子，夜窗相對短檠燈。"]'),
('4a3209c8-7eb8-463e-a5cc-e1beac0d9fbb','數日秋氣已深清坐無酒戲題長句','陸游','宋','宋诗','song-poetry','','[]','漸近重陽天氣嘉，數椽茆屋淡生涯。',64,'全唐诗/poet.song.130000.json','["漸近重陽天氣嘉，數椽茆屋淡生涯。", "山童擁篲掃黄葉，鄰女傍籬收碧花。", "避俗要生輪四角，出門何啻路三义。", "晚窗酒盡無多嘆，試問前村好事家。"]'),
('71cec464-d889-459b-a25d-ba6595662ab1','五更起坐','陸游','宋','宋诗','song-poetry','','[]','世間醉夢過浮生，誰肯披衣坐五更。',64,'全唐诗/poet.song.130000.json','["世間醉夢過浮生，誰肯披衣坐五更。", "煜煜心光回自照，緜緜踵息浩無聲。", "古人得意捐糟粕，癡子何知墮化城。", "七十老翁須努力，鄰雞纔唱又窗明。"]'),
('6fc42991-1614-47f1-b762-e4383b234cc4','谿上雜言','陸游','宋','宋诗','song-poetry','','[]','谿上之丘，吾可以休。',156,'全唐诗/poet.song.130000.json','["谿上之丘，吾可以休。", "谿中之舟，吾可以遊。", "一裘雖弊可度風雪虐，一簞雖薄未有旦夕憂。", "愧于此心鼎食其敢飽，負其所學蟬冕增吾羞。", "古人誰謂不可見，黄卷猶能覩生面。", "百穀薿薿知稷功，九州茫茫開禹甸。", "巍巍成功亦何有，治亂但如翻覆手。", "逢時皆可致唐虞，比身管樂寜非苟。", "樹桑釀酒蕃雞豚，是中端有王業存。", "一朝遇合得施設，千載始知吾道尊。"]'),
('145b1156-1f23-40c9-9e61-a4ec9539073a','厭事','陸游','宋','宋诗','song-poetry','','[]','厭事便微疾，貪眠幸早寒。',48,'全唐诗/poet.song.130000.json','["厭事便微疾，貪眠幸早寒。", "人雖笑疏懶，天實閔衰殘。", "韋布何曾賤，茆茨本自寛。", "黄花插烏帽，一醉有餘歡。"]'),
('e169dd81-91f6-4613-819f-941f87206b62','方池','陸游','宋','宋诗','song-poetry','','[]','莫笑方池小，清泉數斛寛。',48,'全唐诗/poet.song.130000.json','["莫笑方池小，清泉數斛寛。", "照花紅錦爛，洗硯黑蛟蟠。", "日取供茶鼎，時來擲釣竿。", "秋風過欄角，也解作微瀾。"]'),
('b770b286-8750-4cf9-981e-ab23674ae1b4','癸丑重九登山亭追懷頃在興元常以是日臘中梁山下樂甚慨然賦詩予于是生六十有九年矣','陸游','宋','宋诗','song-poetry','','[]','生年六十九，轍遍秦吳歲月長。',62,'全唐诗/poet.song.130000.json','["生年六十九，轍遍秦吳歲月長。", "南鄭從戎嗟尚壯，中梁縱臘最難忘。", "離披雉拂雕鞍墮，獨㑛狐穿古冢藏。", "夢斷酒醒今萬里，亦逢佳節重悲傷。"]'),
('166296cd-c646-4085-8b4f-eb0bc6093b10','感懷四首  其一','陸游','宋','宋诗','song-poetry','','[]','老病與世絕，屏迹三家村。',96,'全唐诗/poet.song.130000.json','["老病與世絕，屏迹三家村。", "我居一何陋，舉手屋可捫。", "客至不能迎，堅坐度朝昏。", "一窗修竹下，超然傲羲軒。", "外物自變遷，內景常黙存。", "黄流不注海，浩浩朝崐崘。", "妙道本自得，至言初不煩。", "功成出緒餘，猶足康黎元。"]'),
('99977a7e-dd75-4148-bb71-f43f6a2e281b','感懷四首  其二','陸游','宋','宋诗','song-poetry','','[]','卜居鏡湖上，一庵環翠屏。',96,'全唐诗/poet.song.130000.json','["卜居鏡湖上，一庵環翠屏。", "竹林藏谽谺，嶺路蟠青冥。", "鶱騰立奇石，嶄絕瞻危亭。", "車馬雖掃迹，猿鳥與忘形。", "我行半九州，蹋盡芒鞵青。", "豈知雪滿鬢，于兹敞雲扃。", "丹砂收箭鏃，茯苓劚人形。", "遼天渺歸鶴，一瞬三千齡。"]'),
('ea62d816-c4dc-403f-8503-82e3e874333d','感懷四首  其三','陸游','宋','宋诗','song-poetry','','[]','平生喜栽花，賴以娛寂寞。',96,'全唐诗/poet.song.130000.json','["平生喜栽花，賴以娛寂寞。", "小園財一畝，粲粲萬跗萼。", "典衣買紫桂，輟食致紅藥。", "阡眠香草茂，掩苒烟柳弱。", "踏雨探花開，障風畏花落。", "雖慚童心在，終勝塵事縳。", "今日疾稍間，天氣亦清廓。", "啼鳥寒不歸，可以侑吾酌。"]'),
('295db5b0-10aa-4fe7-ad2e-68cc5abf0407','感懷四首  其四','陸游','宋','宋诗','song-poetry','','[]','殘年迫衰謝，嬰疾歸鄉枌。',96,'全唐诗/poet.song.130000.json','["殘年迫衰謝，嬰疾歸鄉枌。", "諸賢渡江初，總角幸有聞。", "才非楚倚相，亦能讀典墳。", "夫豈或使之，後死與斯文。", "世儒鑿户牖，道術將瓜分。", "孤陋守一說，百氏殆可焚。", "後来豈無人，鼻堊誰揮斤。", "巍巍貞觀治，房魏出河汾。"]'),
('d1ef394a-dce3-4291-8813-25e9a5b89774','出遊二首  其一','陸游','宋','宋诗','song-poetry','','[]','采藥今朝偶出遊，溪邊小立喚漁舟。',32,'全唐诗/poet.song.130000.json','["采藥今朝偶出遊，溪邊小立喚漁舟。", "未須著句悲揺落，嫩日和風不似秋。"]'),
('30012bf1-f9f9-4868-8569-8de332d5bf2f','出遊二首  其二','陸游','宋','宋诗','song-poetry','','[]','朝行躡屩穿幽谷，暮返褰裳涉亂流。',32,'全唐诗/poet.song.130000.json','["朝行躡屩穿幽谷，暮返褰裳涉亂流。", "提起短笻成一笑，毎煩上座爲分憂。"]'),
('ab3054b6-19e2-4774-89c6-5ab914677d22','讀杜詩偶成','陸游','宋','宋诗','song-poetry','','[]','一念寜容事物侵，天魔元自是知音。',32,'全唐诗/poet.song.130000.json','["一念寜容事物侵，天魔元自是知音。", "拾遺大欠修行力，小吏相輕尚動心。"]'),
('f553b500-6560-47a7-8262-5e39f8526690','秋夜即事','陸游','宋','宋诗','song-poetry','','[]','鳥宿牛歸户欲扃，燈前老子影伶俜。',64,'全唐诗/poet.song.130000.json','["鳥宿牛歸户欲扃，燈前老子影伶俜。", "濕雲不散初聞雁，深竹微明尚有螢。", "一卷舊書開蠧簡，半升濁酒倒餘瓶。", "乘閑欲擬歸来作，小草斜行滿曲屏。"]'),
('dea10634-8950-4b1c-9654-52a2af0abe07','物有可嘆者因戲作數語以識之','陸游','宋','宋诗','song-poetry','','[]','雞棲及我未掩扉，犬雖遠出暮自歸。',96,'全唐诗/poet.song.130000.json','["雞棲及我未掩扉，犬雖遠出暮自歸。", "司晨警夜職交舉，簸糠棄粒報亦微。", "查查雙鵲更愧汝，庭樹夜宿常相依。", "豈憐主人老寂寞，暖熱蓬户不忍違。", "養鴟甚恩健即去，養鷹雖久飽亦飛。", "嗟哉物性厚薄異，使我隠几空歔欷。"]'),
('1a5ec251-3962-404b-961a-7e2c6243230b','老懷','陸游','宋','宋诗','song-poetry','','[]','身見高皇再造初，名場流輩略無餘。',64,'全唐诗/poet.song.130000.json','["身見高皇再造初，名場流輩略無餘。", "舊書科斗纔存字，薄業蝸牛僅有廬。", "迂士豈堪新貴使，少年自與老人疏。", "荒園寂寂堆霜葉，抱甕何妨日灌蔬。"]'),
('c1ac4aac-a006-4135-87a0-2b41e9b27a30','對酒','陸游','宋','宋诗','song-poetry','','[]','古今共有死，長短無百年。',96,'全唐诗/poet.song.130000.json','["古今共有死，長短無百年。", "方其欲暝時，如困得熟眠。", "世以生時心，妄度死者情。", "疑其不忍去，一笑可絕纓。", "區區計生死，不如持一觴。", "一觴澆不平，萬事俱可忘。", "待酒忘萬事，猶是役於酒。", "醉醒不到處，夭魔自奔走。"]'),
('e7bab1f1-bab3-444a-9a16-1060604bc865','東村散步有懷張漢州','陸游','宋','宋诗','song-poetry','','[]','扶杖村東路，秋来始此回。',48,'全唐诗/poet.song.130000.json','["扶杖村東路，秋来始此回。", "寒鴉盤陣起，野菊卧枝開。", "憂國丹心折，懷人雪鬢催。", "房湖八千里，那得足書来。"]'),
('03faf537-1423-4f2a-a4c9-39656a643018','晚寒自東村步歸','陸游','宋','宋诗','song-poetry','','[]','夕陽下平野，落葉滿荒街。',51,'全唐诗/poet.song.130000.json','["夕陽下平野，落葉滿荒街。", "村店賣蕎麫，人家焼豆{艹點}。", "溪風透布褐，草露濕芒鞵。", "骨相元如此，何由與世諧。"]'),
('80c5d9d5-e05a-41fc-a6b5-8b5f15635459','排悶六首  其一','陸游','宋','宋诗','song-poetry','','[]','丈夫結髮志功名，大事真當以死爭。',32,'全唐诗/poet.song.130000.json','["丈夫結髮志功名，大事真當以死爭。", "我昔駐車籌筆驛，孔明千載尚如生。"]'),
('71d3ca41-f43b-4997-8dbe-821ab25e55fd','排悶六首  其二','陸游','宋','宋诗','song-poetry','','[]','曾擕一劍遠從戎，秦趙關河顧盼中。',32,'全唐诗/poet.song.130000.json','["曾擕一劍遠從戎，秦趙關河顧盼中。", "老去功名無復夢，凌烟分付黑頭公。"]'),
('9c05379c-dde8-4fb2-98bc-5949ebddd280','排悶六首  其三','陸游','宋','宋诗','song-poetry','','[]','四十從軍渭水邊，功名無命氣猶全。',32,'全唐诗/poet.song.130000.json','["四十從軍渭水邊，功名無命氣猶全。", "白頭爛醉東吳市，自拔長刀割彘肩。"]'),
('78e387ca-608a-4a6c-b167-4d69a183c5bf','排悶六首  其四','陸游','宋','宋诗','song-poetry','','[]','西塞山前吹笛聲，曲終已過雒陽城。',32,'全唐诗/poet.song.130000.json','["西塞山前吹笛聲，曲終已過雒陽城。", "君能洗盡世間念，何處樓臺無月明。"]'),
('d01346a0-2342-4a1b-a3d7-a9c37107037c','排悶六首  其五','陸游','宋','宋诗','song-poetry','','[]','萬里風中寄斷蓬，古来虚死幾英雄。',32,'全唐诗/poet.song.130000.json','["萬里風中寄斷蓬，古来虚死幾英雄。", "拔山力與回天勢，不滿先生一笑中。"]'),
('1f0be743-6de2-4692-b49a-aaf554616588','排悶六首  其六','陸游','宋','宋诗','song-poetry','','[]','風霜九月冷颼飀，湖海飄然一布裘。',32,'全唐诗/poet.song.130000.json','["風霜九月冷颼飀，湖海飄然一布裘。", "親見伏羲初畫卦，轉頭三十萬春秋。"]'),
('3cfc8069-c47c-4d6d-b1eb-ee7486f6e921','初寒病中有感','陸游','宋','宋诗','song-poetry','','[]','楚水楓林霜露新，白頭一叟正吟呻。',64,'全唐诗/poet.song.130000.json','["楚水楓林霜露新，白頭一叟正吟呻。", "牛衣未起王章疾，馬磨何傷許靖貧。", "治道本来存簡册，神州誰與静烟塵。", "新亭對泣猶稀見，况覔夷吾一輩人。"]'),
('4a627df6-2724-4ae7-9417-dbb525e4e7a6','放歌行','陸游','宋','宋诗','song-poetry','','[]','君不見汾陽富貴近古無，二十四考書中書。',134,'全唐诗/poet.song.130000.json','["君不見汾陽富貴近古無，二十四考書中書。", "又不見慈明起自布衣中，九十五日至三公。", "人生窮達各有命，拂衣徑去猶差勝。", "介推焚死終不悔，梁鴻寄食吾何病。", "安用隨牒東復西，獻諛耐辱希階梯。", "初無公論判涇渭，徒使新貴矜雲泥。", "稽山一老貧無食，衣破履穿面黧黑。", "誰知快意舉世無，南山之南北山北。"]'),
('ab729496-5d17-475f-a70d-7feacdd02c27','山頭石','陸游','宋','宋诗','song-poetry','','[]','秋風萬木霣，春雨百草生。',80,'全唐诗/poet.song.130000.json','["秋風萬木霣，春雨百草生。", "造物初何心，時至自枯榮。", "惟有山頭石，歲月浩莫測。", "不知四時運，常带太古色。", "老翁一生居此山，脚力欲盡猶躋攀。", "時時撫石三太息，安得此身如爾頑。"]'),
('7915a41e-2fdf-44c1-b383-b70a25c59911','有客','陸游','宋','宋诗','song-poetry','','[]','有客隠華山，學道忘歲月。',144,'全唐诗/poet.song.130000.json','["有客隠華山，學道忘歲月。", "靈苗生絕壁，光景中夜發。", "劚根食之盡，倐爾換金骨。", "通籍虎豹閽，日預通明謁。", "緑章奏封事，誤字坐責罰。", "後身幸不忘，去日苦飄忽。", "白首三入朝，未省及黔突。", "方逃申公鉗，已取卞和刖。", "福微不盈眥，罪衆幾擢髮。", "上天豈憐之，寸步使屢蹶。", "拔其利欲根，還之山水窟。", "洗心謝宿愆，世事等閩粤。"]'),
('7f37bc8a-bddc-4f05-8220-b1bb6a8eb113','幽居五首  其一','陸游','宋','宋诗','song-poetry','','[]','窮老苦畏事，雅意在丘壑。',48,'全唐诗/poet.song.130000.json','["窮老苦畏事，雅意在丘壑。", "結茆鏡湖上，卒歲安寂寞。", "有門常懶開，壁間挂雙屩。", "猶恨未遠人，静夜聞城角。"]'),
('353d3857-28f0-4dbb-97b1-8993c105a5c3','幽居五首  其二','陸游','宋','宋诗','song-poetry','','[]','来客無僮奴，剝啄自叩户。',48,'全唐诗/poet.song.130000.json','["来客無僮奴，剝啄自叩户。", "主人亦蕭然，茗飲不能具。", "清言正絕倒，日莫亟散去。", "更欲盡所懷，衣薄畏霜露。"]'),
('8a9126be-62d6-49b9-b1a8-c35fa83416ef','幽居五首  其三','陸游','宋','宋诗','song-poetry','','[]','山園手栽花，日夜數花時。',48,'全唐诗/poet.song.130000.json','["山園手栽花，日夜數花時。", "花開亦已落，一歡自無期。", "勸君强自娛，勿作兒女悲。", "春風染柳條，不染君鬢絲。"]'),
('378f3e00-6eeb-418e-b085-925c30d7d821','幽居五首  其四','陸游','宋','宋诗','song-poetry','','[]','種菜三四畦，畜豚七八箇。',48,'全唐诗/poet.song.130000.json','["種菜三四畦，畜豚七八箇。", "永言給賔祭，且復課慵惰。", "霜清黄犢健，土潤小雨過。", "冬耕不可失，努力勿安卧。"]'),
('31113bbb-5bad-4b73-99d1-3d59708613cf','幽居五首  其五','陸游','宋','宋诗','song-poetry','','[]','放翁家山陰，其貧盖一國。',48,'全唐诗/poet.song.130000.json','["放翁家山陰，其貧盖一國。", "骨相異虎頭，祠祿真雞肋。", "有米薪未具，坐待至曛黑。", "躬耕豈所難，一飽非爾力。"]'),
('06658a70-dd4d-4c4b-b22c-281f526e671e','野興四首  其一','陸游','宋','宋诗','song-poetry','','[]','身似孤鴻鎩羽翰，悲鳴飲啄住江干。',64,'全唐诗/poet.song.130000.json','["身似孤鴻鎩羽翰，悲鳴飲啄住江干。", "酒闌客思多新感，病起衰顔失故丹。", "倦枕忽聞中夜雨，疏砧又報一年寒。", "幽窗晤語無来客，空倚詩情强自寛。"]'),
('3ea3ff47-642c-43b9-af40-e4a01baf21e2','野興四首  其二','陸游','宋','宋诗','song-poetry','','[]','老去癡頑百不能，非醒非醉日騰騰。',64,'全唐诗/poet.song.130000.json','["老去癡頑百不能，非醒非醉日騰騰。", "敲門惟有徴租吏，好事元無送米僧。", "舊俗不還誰復念，古書雖在漸難憑。", "平生意氣今如此，惆悵西窗半夜燈。"]'),
('0083ddcc-7575-42a2-9ff8-40edb3d10e79','野興四首  其三','陸游','宋','宋诗','song-poetry','','[]','殘水涓涓入野塘，菊花猶放數枝黄。',64,'全唐诗/poet.song.130000.json','["殘水涓涓入野塘，菊花猶放數枝黄。", "悶思野步便晴日，病怯冬温喜薄霜。", "湯餅鬻成新兔美，膾韲擣罷綠橙香。", "人間富貴知何得，商略山林却味長。"]'),
('876de169-0855-433b-8482-ce9b265241bf','野興四首  其四','陸游','宋','宋诗','song-poetry','','[]','水作縠紋微起伏，天如卵色半陰晴。',64,'全唐诗/poet.song.130000.json','["水作縠紋微起伏，天如卵色半陰晴。", "偶来竹下搘頤坐，却向藤陰曳杖行。", "西埭人喧荻船過，東村燈上緯車鳴。", "幽居應接真無暇，莫訝經年懶入城。"]'),
('c322ddb4-9af8-436c-8aa4-9d95961876da','買油','陸游','宋','宋诗','song-poetry','','[]','習氣年来掃未平，夢回猶喜讀書聲。',32,'全唐诗/poet.song.130000.json','["習氣年来掃未平，夢回猶喜讀書聲。", "冬裘不贖渾閑事，且爲吾兒續短檠。"]'),
('ff89fdf5-4dde-4a27-a847-a72ab2a58a4c','繫舟二首  其一','陸游','宋','宋诗','song-poetry','','[]','繫舟江浦待潮平，嘆息無人共月明。',32,'全唐诗/poet.song.130000.json','["繫舟江浦待潮平，嘆息無人共月明。", "歴盡世間多少事，飄然依舊老書生。"]'),
('934e6b29-90a8-4a84-b82e-f34ef6902c71','繫舟二首  其二','陸游','宋','宋诗','song-poetry','','[]','地曠月明鋪素練，霜寒河淺拂輕綃。',32,'全唐诗/poet.song.130000.json','["地曠月明鋪素練，霜寒河淺拂輕綃。", "手扶萬里天壇杖，夜過前村禹會橋。"]'),
('b28f43f4-9d89-40e7-af0b-c430d9924f03','初冬至近村','陸游','宋','宋诗','song-poetry','','[]','南國霜常晚，初冬葉始紅。',48,'全唐诗/poet.song.130000.json','["南國霜常晚，初冬葉始紅。", "曠懷牛屋下，美睡雨聲中。", "沮水憶浮馬，嶓山思射熊。", "何由効唐將，八十下遼東。"]'),
('a52f25a0-10f7-4312-b67a-61c74dd89748','古築城曲四首  其一','陸游','宋','宋诗','song-poetry','','[]','築城聲酸嘶，漢月傍城低。',24,'全唐诗/poet.song.130000.json','["築城聲酸嘶，漢月傍城低。", "白骨若不掩，高與長城齊。"]'),
('ac7ff4b0-27fa-4c51-8304-cb602fd1dfbb','古築城曲四首  其二','陸游','宋','宋诗','song-poetry','','[]','長城高際天，三十萬人守。',24,'全唐诗/poet.song.130000.json','["長城高際天，三十萬人守。", "一日詔書来，扶蘇先授首。"]'),
('6502ac5e-1d17-4534-a72b-fe19e7733551','古築城曲四首  其三','陸游','宋','宋诗','song-poetry','','[]','百丈築城身，千步掘城壕。',24,'全唐诗/poet.song.130000.json','["百丈築城身，千步掘城壕。", "咸陽三月火，始悔此徒勞。"]'),
('f78d0882-a28e-4195-b048-549b70056c44','古築城曲四首  其四','陸游','宋','宋诗','song-poetry','','[]','嶧山訪秦碑，斷裂無完筆。',24,'全唐诗/poet.song.130000.json','["嶧山訪秦碑，斷裂無完筆。", "惟有築城詞，哀怨如當日。"]'),
('0b25301d-9110-4310-afe3-14f6c5b6dea7','山園','陸游','宋','宋诗','song-poetry','','[]','山泉引派漲清池，野蔓移根絡短籬。',64,'全唐诗/poet.song.130000.json','["山泉引派漲清池，野蔓移根絡短籬。", "藝果極知非老事，接花聊復効兒嬉。", "提壺言語開顔聽，斵木衣襦緩步窺。", "莫笑題詩還滿紙，小園幽事要君知。"]'),
('e83752f0-6cb9-4744-87e2-c987c8b24b36','將軍行','陸游','宋','宋诗','song-poetry','','[]','將軍入奏平燕筞，持笏榻前親指畫。',128,'全唐诗/poet.song.130000.json','["將軍入奏平燕筞，持笏榻前親指畫。", "天山熱海在目中，下殿即日名烜赫。", "馳出都門雪初霽，直過黄河冰未坼。", "繡旗方掠桑乾渡，羽檄已入金臺陌。", "勇士如鷹健欲飛，孱王似兔何勞搦。", "戎服押俘獻廟社，正衙第賞頒詔冊。", "端門賜酺天下慶，御觴尚恨滄溟迮。", "從来文吏喜相輕，聊遣濡毫書竹帛。"]'),
('b1085fdc-2afc-4138-a9ce-16ffafdfad12','古别離','陸游','宋','宋诗','song-poetry','','[]','孤城窮巷秋寂寂，美人停梭夜嘆息。',96,'全唐诗/poet.song.130000.json','["孤城窮巷秋寂寂，美人停梭夜嘆息。", "空園露濕荆棘枝，荒蹊月照狐狸迹。", "憶君去時兒在腹，走如黄犢爺未識。", "紫姑吉語元無據，况憑瓦兆占歸日。", "嫁来不省出門前，魂夢何因識酒泉。", "粉綿磨鏡不忍照，女子盛時無十年。"]'),
('dc200012-4c76-4ff1-97a8-7bbf42d475ea','寄子虡','陸游','宋','宋诗','song-poetry','','[]','吾兒適淮壖，送之梅市橋。',144,'全唐诗/poet.song.130000.json','["吾兒適淮壖，送之梅市橋。", "三年安得過，思汝雙鬢凋。", "今年當代歸，秋色已蕭蕭。", "迎汝不憚遠，夢泝錢塘潮。", "人事不可料，邑民挽歸橈。", "郡牧部使者，交章聞之朝。", "增秩復使留，此事久寂寥。", "念汝未育子，大女方垂髫。", "小女聞學行，想像扶床嬌。", "汝少知讀易，外物莫能揺。", "但願早舉孫，不必七葉貂。", "歸来郎罷前，相從樂簞瓢。"]'),
('36866dfd-004c-42ce-8f15-44273fc6be9f','泛舟自中堰入湖','陸游','宋','宋诗','song-poetry','','[]','水縮沙洲出，霜清木葉丹。',48,'全唐诗/poet.song.130000.json','["水縮沙洲出，霜清木葉丹。", "鷺群横澹靄，鴉陣報初寒。", "冷落人情見，衰遲世念闌。", "惟留一句子，村舍話團圞。"]'),
('cfa7bbee-caf4-4818-b199-f9f1d0438038','夜歸舟中作','陸游','宋','宋诗','song-poetry','','[]','意薄楊修喚小兒，孤舟自笑髮成絲。',64,'全唐诗/poet.song.130000.json','["意薄楊修喚小兒，孤舟自笑髮成絲。", "放開癡腹無非夢，拈起幽懷摠是詩。", "霜下忽驚桐葉盡，灘生更覺水聲奇。", "餘年那恨驅黄犢，除却爲農百不宜。"]'),
('791d948c-5785-459c-83e2-1ab80427dc40','蓬莱閣聞大風','陸游','宋','宋诗','song-poetry','','[]','天風揺蕩萬松聲，卷海頹山得我驚。',64,'全唐诗/poet.song.130000.json','["天風揺蕩萬松聲，卷海頹山得我驚。", "觸灧澦堆秋起柂，鏖皋蘭下夜還營。", "荷戈老氣縱横在，看劍新詩欬唾成。", "興盡却尋湖上路，醉看月墮斗枃傾。"]'),
('20aee9aa-9a12-4d96-b5a6-b44e3069a71f','小出塞曲','陸游','宋','宋诗','song-poetry','','[]','全師出雁塞，百戰運龍韜。',48,'全唐诗/poet.song.130000.json','["全師出雁塞，百戰運龍韜。", "金絡洮州馬，珠装夏國刀。", "度沙風破肉，攻壘雪平壕。", "明日受降處，甲齊熊耳高。"]'),
('41e89bee-e5f2-4c21-bd93-3343820f748c','冬日園中作','陸游','宋','宋诗','song-poetry','','[]','園荒闕掃除，籬敗且枝梧。',48,'全唐诗/poet.song.130000.json','["園荒闕掃除，籬敗且枝梧。", "久旱池萍死，新霜野蔓枯。", "寒爐殊未議，濁酒却時酤。", "飛動郊原興，饑鷹待指呼。"]'),
('5a08eb86-fed7-4cd1-a4c2-5dbd3aa3be3f','登山亭','陸游','宋','宋诗','song-poetry','','[]','新得天台古澗藤，强扶衰疾蹋崚增。',64,'全唐诗/poet.song.130000.json','["新得天台古澗藤，强扶衰疾蹋崚增。", "登高臨遠雖多感，嘆老嗟卑却未曾。", "紙上是非難盡信，人間禍福有相乘。", "早知等是枯魚肆，乞水何須望斗升。"]'),
('d5391760-5c7f-445b-b69a-d65f87fa6a52','拄杖歌','陸游','宋','宋诗','song-poetry','','[]','道人四壁空無有，一炷清香閑袖手。',96,'全唐诗/poet.song.130000.json','["道人四壁空無有，一炷清香閑袖手。", "床邊獨有拄杖子，疾病相扶真我友。", "禪房按膝秋聴雨，野店敲門莫賖酒。", "畏途九折歴欲盡，世上誰如君耐久。", "老矣更踏千山雲，何可一日無此君。", "歸来燈前夜欲半，露柱說法君應聞。"]'),
('44c83a4e-205c-4abb-9ff8-c6e5db146fda','冬晴','陸游','宋','宋诗','song-poetry','','[]','吳中霜雪晚，初冬正佳時。',72,'全唐诗/poet.song.130000.json','["吳中霜雪晚，初冬正佳時。", "丹楓未辭林，黄菊猶殘枝。", "鳴雁過長空，纖鱗泳清池。", "氣和未重裘，臨水照鬚眉。", "悠然據石坐，亦復出門嬉。", "野老荷鉏至，一笑成幽期。"]'),
('405a5255-a4c7-4f15-bd53-02159f77f21c','冬夕二首  其一','陸游','宋','宋诗','song-poetry','','[]','犬吠驚飄葉，禽喧換宿枝。',48,'全唐诗/poet.song.130000.json','["犬吠驚飄葉，禽喧換宿枝。", "墮空霜肅肅，垂地斗離離。", "野叟讀書罷，高城吹角悲。", "功名渾錯料，老病却如期。"]'),
('fb02ed5a-d11a-4600-9786-c224ee20eabd','冬夕二首  其二','陸游','宋','宋诗','song-poetry','','[]','不寐起中夕，披衣增慨慷。',48,'全唐诗/poet.song.130000.json','["不寐起中夕，披衣增慨慷。", "千金空市骨，三沐竟刳腸。", "世事粗能識，吾生安用長。", "布裘茆屋底，死去亦芬芳。"]'),
('08e0b362-7f84-4a69-b804-79d4a6b1341c','十月十五夜對月','陸游','宋','宋诗','song-poetry','','[]','離海月盈丈，寒光萬里明。',48,'全唐诗/poet.song.130000.json','["離海月盈丈，寒光萬里明。", "衆星斂欲盡，一鏡獨徐行。", "重露滴松鬛，高風吹鶴聲。", "老来殊畏冷，不盡倚闌情。"]'),
('61c0666c-76e9-4961-aa26-fc690a67da60','久疾三首  其一','陸游','宋','宋诗','song-poetry','','[]','久疾無時已，殘年莫更論。',48,'全唐诗/poet.song.130000.json','["久疾無時已，殘年莫更論。", "流離魂未返，窮困舌空存。", "畊壟關心事，祠官荷主恩。", "但愁垂老眼，不見定中原。"]'),
('def3176e-61ef-4b47-b5c8-63c359b75a50','久疾三首  其二','陸游','宋','宋诗','song-poetry','','[]','殘年仍卧疾，窗户夜愔愔。',48,'全唐诗/poet.song.130000.json','["殘年仍卧疾，窗户夜愔愔。", "一日且復過，久生非所欽。", "暗塵侵藥笥，微月伴衣砧。", "萬里懷良友，前盟可得尋。"]'),
('28b68ff0-98a5-450d-8868-68b41398189f','久疾三首  其三','陸游','宋','宋诗','song-poetry','','[]','幽屏元無事，沉緜自鮮歡。',48,'全唐诗/poet.song.130000.json','["幽屏元無事，沉緜自鮮歡。", "脛長猶可截，冠挂豈容彈。", "擣藥香塵細，尋書蜜炬殘。", "晚来差覺健，風月小庭寛。"]'),
('e1f8d889-5f70-4ab3-aa1a-312609c4a3f6','舍北望牛頭山山有延勝寺先太傅書堂在焉六年前嘗泛小江往遊寺焚於睦冦書堂無復存矣','陸游','宋','宋诗','song-poetry','','[]','太傅讀書處，秋風曾問途。',48,'全唐诗/poet.song.130000.json','["太傅讀書處，秋風曾問途。", "江如青弋險，山似白鹽孤。", "路盡還登嶺，林開忽見湖。", "草堂無復識，流涕想規模。"]'),
('d95fd0ce-78a4-412c-9783-180690e8c0eb','十月十九日大風作寒閉户竟日','陸游','宋','宋诗','song-poetry','','[]','霜風捲地起，落葉擁蝸廬。',48,'全唐诗/poet.song.130000.json','["霜風捲地起，落葉擁蝸廬。", "終日澹無事，一窗寛有餘。", "坐多知力耗，食少覺心虚。", "懶惰無新句，松聲忽起予。"]'),
('15614c95-72c9-4a07-9f76-fc0f6369be4b','寄天封明老','陸游','宋','宋诗','song-poetry','','[]','浪迹天台一夢中，距今四十五秋風。',64,'全唐诗/poet.song.130000.json','["浪迹天台一夢中，距今四十五秋風。", "勝遊回首似昨日，衰病侵人成老翁。", "聖寺參差石橋外，仙蓬縹緲玉霄東。", "因君又動青鞵興，目斷千峰翠倚空。"]'),
('79925734-88b5-4ab2-87ce-4e0087d84d2f','村居二首  其一','陸游','宋','宋诗','song-poetry','','[]','衰病汙朝著，恩寛得免歸。',48,'全唐诗/poet.song.130000.json','["衰病汙朝著，恩寛得免歸。", "粗能心自信，不恨世相違。", "草市寒沽酒，江城夜擣衣。", "是中堪送老，高枕謝招麾。"]'),
('f5a38197-1693-4b18-9a36-fcf70d6e1ad4','村居二首  其二','陸游','宋','宋诗','song-poetry','','[]','自笑觸藩羝，人嘲失旦雞。',48,'全唐诗/poet.song.130000.json','["自笑觸藩羝，人嘲失旦雞。", "囊慳衣任短，山冷屋便低。", "宦拙讒銷骨，言狂悔噬臍。", "自今焚筆硯，有手但扶犂。"]'),
('32c259ed-c2b0-4148-b633-d188f2063abb','十月下旬暄甚戲作小詩','陸游','宋','宋诗','song-poetry','','[]','老怯霜風盡日眠，素屏紙帳擁蠻氊。',32,'全唐诗/poet.song.130000.json','["老怯霜風盡日眠，素屏紙帳擁蠻氊。", "爲君小試回春手，便似暄妍二月天。"]'),
('91b3ebeb-d003-4c54-91de-3bac5cb88faa','霜天雜興三首  其一','陸游','宋','宋诗','song-poetry','','[]','楓葉全丹槲葉黄，江城殘角伴斜陽。',64,'全唐诗/poet.song.130000.json','["楓葉全丹槲葉黄，江城殘角伴斜陽。", "琴書自足閑中樂，天地能容醉後狂。", "老死山林初不憾，夢遊河渭獨難忘。", "穀城黄石今安在，取履猶思効子房。"]'),
('ec08aa85-38e8-4886-9be0-20ba2f53779b','霜天雜興三首  其二','陸游','宋','宋诗','song-poetry','','[]','萬鼓風聲吼屋邊，老人裘絝旋装綿。',64,'全唐诗/poet.song.130000.json','["萬鼓風聲吼屋邊，老人裘絝旋装綿。", "晨梳墮髮知衰甚，夜枕聞雞尚慨然。", "身後文章空飽蠧，眼前交舊半沉泉。", "飯蔬飲水平生慣，恥向天公更乞憐。"]'),
('9a499e0b-abe9-40c9-8f1d-77bd834931f0','霜天雜興三首  其三','陸游','宋','宋诗','song-poetry','','[]','少學愚公一味愚，莫年仍似病相如。',64,'全唐诗/poet.song.130000.json','["少學愚公一味愚，莫年仍似病相如。", "閑吟寄友惟生紙，草具留僧只野蔬。", "雨澀溪流殊未足，霜高木葉已無餘。", "潭州丞相憐衰疾，細字時收尺素書。"]'),
('376c707a-45a7-4e06-b1aa-b5b4f7adc14b','連日風雨寒甚夜忽大風明旦遂晴','陸游','宋','宋诗','song-poetry','','[]','萬里浮雲一掃空，碧天無際日曈曨。',32,'全唐诗/poet.song.130000.json','["萬里浮雲一掃空，碧天無際日曈曨。", "歡聲四起春風裏，恰似祥符景德中。"]'),
('b183e1c5-7356-4341-b5bf-04acd073ee9d','懷昔','陸游','宋','宋诗','song-poetry','','[]','昔者戍梁益，寢飯鞍馬間。',120,'全唐诗/poet.song.130000.json','["昔者戍梁益，寢飯鞍馬間。", "一日歲欲莫，揚鞭臨散關。", "增冰塞渭水，飛雪暗岐山。", "悵望釣璜公，英槩如可還。", "挺劍刺乳虎，血濺貂裘殷。", "至今傳軍中，尚愧壯士顔。", "豈知墮老境，槁木蒙霜菅。", "澤國氣候晚，仲冬雪猶慳。", "曩事空夢想，擁褐自笑孱。", "烽烟尚未靖，大弓何時彎。"]'),
('b9e1c1a6-7258-42da-8bb1-5132c5339e8a','寄題王俊卿看山堂二首  其一','陸游','宋','宋诗','song-poetry','','[]','廣文風度絕清真，一代論交不數人。',32,'全唐诗/poet.song.130000.json','["廣文風度絕清真，一代論交不數人。", "車馬到門常謝病，北山雖遠却相親。"]'),
('e4283ea6-ebb8-460d-94a4-d953a722e43b','寄題王俊卿看山堂二首  其二','陸游','宋','宋诗','song-poetry','','[]','閉户終年懶出遊，北山山色可消愁。',32,'全唐诗/poet.song.130000.json','["閉户終年懶出遊，北山山色可消愁。", "何時一掃胡塵盡，更約同吟太華秋。"]'),
('34927091-1a58-42d5-9ccd-f972a7365836','絕嘆','陸游','宋','宋诗','song-poetry','','[]','老屋環青嶂，衰翁卧白頭。',48,'全唐诗/poet.song.130000.json','["老屋環青嶂，衰翁卧白頭。", "殘書且遮眼，薄酒不澆愁。", "世故真難料，吾生愈覺浮。", "餘年更須惜，幸得返山丘。"]'),
('853bae5e-ea31-4749-a52c-5237bcec75b8','風雨','陸游','宋','宋诗','song-poetry','','[]','風雨連三日，衰翁不下堂。',48,'全唐诗/poet.song.130000.json','["風雨連三日，衰翁不下堂。", "弄書聊自適，與世已相忘。", "坼栗經霜飽，搓橙带露香。", "地爐供小飲，亦足慰淒涼。"]'),
('470eaa23-9e6c-4cf8-90b9-682cb935ebd5','晚過鄰曲','陸游','宋','宋诗','song-poetry','','[]','陽狂跌宕送年華，信步来尋野老家。',64,'全唐诗/poet.song.130000.json','["陽狂跌宕送年華，信步来尋野老家。", "淺瀨水清逢立鷺，横林葉盡數栖鴉。", "書生一飽依耕耒，壯士孤愁入戍笳。", "王績但思酣美醖，葛洪不復問丹砂。"]'),
('2136e3fc-2cae-43b1-8d47-b18e6bab89ec','莫仲謙挽詞','陸游','宋','宋诗','song-poetry','','[]','懷器潛山澤，逢時起薜蘿。',48,'全唐诗/poet.song.130000.json','["懷器潛山澤，逢時起薜蘿。", "星辰占寶劍，雷雨化龍梭。", "禹穴書雖富，浯溪石未磨。", "門閭更須築，有子繼三科。"]'),
('34732e4e-a32b-43f3-a7d1-927b6044ebde','病起','陸游','宋','宋诗','song-poetry','','[]','一病輒經旬，幾病能不死。',72,'全唐诗/poet.song.130000.json','["一病輒經旬，幾病能不死。", "誠知迫頽年，暫健亦自喜。", "半窗風竹影，晴景極清美。", "讀書雖益懶，尚可日百紙。", "引鏡整角巾，病思真一洗。", "悠然度朝晡，萬事如覆水。"]'),
('cab25f95-9f21-4501-b749-6648c8e3a1e5','晚興','陸游','宋','宋诗','song-poetry','','[]','一聲天邊斷雁哀，數蕊籬外蚤梅開。',32,'全唐诗/poet.song.130000.json','["一聲天邊斷雁哀，數蕊籬外蚤梅開。", "幽人耐冷倚門久，送月墮湖歸去来。"]'),
('ba5f2e7f-b30e-4e52-a72b-e736cd4f34ae','贈粉鼻','陸游','宋','宋诗','song-poetry','','[]','連夕狸奴磔鼠頻，怒髯噀血護殘囷。',32,'全唐诗/poet.song.130000.json','["連夕狸奴磔鼠頻，怒髯噀血護殘囷。", "問渠何似朱門裏，日飽魚飱睡錦茵。"]'),
('bd6ef0a4-9ce6-4aca-ac2c-897f6593be69','與兒輩論李杜韓柳文章偶成','陸游','宋','宋诗','song-poetry','','[]','吏部儀曹體不同，拾遺供奉各家風。',32,'全唐诗/poet.song.130000.json','["吏部儀曹體不同，拾遺供奉各家風。", "未言看到無同處，看得同時已有功。"]'),
('dd29aaf4-2056-4024-a4b2-076950a1a953','夢至小益','陸游','宋','宋诗','song-poetry','','[]','夢覺空山泪漬衿，西遊歲月苦駸駸。',64,'全唐诗/poet.song.130000.json','["夢覺空山泪漬衿，西遊歲月苦駸駸。", "葭萌古路緣雲壁，桔柏浮梁暗櫟林。", "坐上新聲猶蜀伎，道傍逆旅已秦音。", "荷戈意氣渾如昨，自笑摧頹負壯心。"]'),
('75b50bff-8d8b-4cd9-b092-cdb28d3b5762','懷紹興間往還諸公','陸游','宋','宋诗','song-poetry','','[]','早歲從諸傑，森然盡國華。',48,'全唐诗/poet.song.130000.json','["早歲從諸傑，森然盡國華。", "辭工出月脇，筆健拔鯨牙。", "道在窮何憾，年殂生有涯。", "湖山元不改，老泪濕風沙。"]'),
('b5aa4401-9456-41e5-b832-e7b0b33aec4d','磨衲道衣','陸游','宋','宋诗','song-poetry','','[]','久脫朝衣學道裝，溪雲野鶴作身章。',32,'全唐诗/poet.song.130000.json','["久脫朝衣學道裝，溪雲野鶴作身章。", "何時九轉丹砂熟，却插金貂侍紫皇。"]'),
('d23fca23-87fc-46e5-8e1f-da8d50fbcc01','溪上作二首  其一','陸游','宋','宋诗','song-poetry','','[]','落日溪邊杖白頭，破裘不補冷颼颼。',64,'全唐诗/poet.song.130000.json','["落日溪邊杖白頭，破裘不補冷颼颼。", "戅愚酷信紙上語，老病猶先天下憂。", "末俗陵遲稀獨立，斯文崩壊欲横流。", "紹興人物嗟誰在，空記當年接俊遊。"]'),
('0ef1118f-1a4a-478a-9c31-60964379bb95','溪上作二首  其二','陸游','宋','宋诗','song-poetry','','[]','傴僂溪頭白髮翁，暮年心事一枝笻。',64,'全唐诗/poet.song.130000.json','["傴僂溪頭白髮翁，暮年心事一枝笻。", "山銜落日青横野，鴉起平沙黑蔽空。", "天下可憂非一事，書生無地効孤忠。", "東山七月猶關念，未忍浮沉酒醆中。"]'),
('3905fb54-0970-4c9b-9c3e-dfb5b6dca648','小憩','陸游','宋','宋诗','song-poetry','','[]','徐行散腰膂，小憩嗇精神。',48,'全唐诗/poet.song.130000.json','["徐行散腰膂，小憩嗇精神。", "休養觀書眼，調娛宴坐身。", "青氊我家舊，紅粟太倉陳。", "溫飽無餘事，寒龜息自勻。"]'),
('f00e0d2e-7a74-47d3-832a-a44ce33ed0f9','癸丑十一月下旬溫燠如春晦日忽大風作雪','陸游','宋','宋诗','song-poetry','','[]','今年一冬晴日多，草木萌甲風氣和。',96,'全唐诗/poet.song.130000.json','["今年一冬晴日多，草木萌甲風氣和。", "百錢布被未議贖，老翁曝背兒行歌。", "吾儕小人慮不遠，積雪苦寒来豈晚。", "青天方行三尺烏，不料黑雲高𡾰嵼。", "明朝雪惡凍復餓，兒啼頰皴翁噤卧。", "九重巍巍那得知，閣門催班百官賀。"]'),
('5490bd0a-e5bb-4b56-9b82-516e8af5fa8d','占城椶竹拄杖','陸游','宋','宋诗','song-poetry','','[]','參雲氣壓葛陂龍，跨海来扶笠澤翁。',32,'全唐诗/poet.song.130000.json','["參雲氣壓葛陂龍，跨海来扶笠澤翁。", "八十尚思行脚在，與君處處現神通。"]'),
('f5f12662-35fe-4a85-ba89-b6a1c29c51b2','西城','陸游','宋','宋诗','song-poetry','','[]','市步群囂散，關門夕照明。',48,'全唐诗/poet.song.130000.json','["市步群囂散，關門夕照明。", "河流倒橋影，雪野聚烏聲。", "繁杵聞深巷，寒烟下廢城。", "匆匆船盡發，爭趁早潮平。"]'),
('3eb475be-31ce-46f2-aa6d-2f58c5b5a5f6','東城','陸游','宋','宋诗','song-poetry','','[]','墟落斂暮烟，林梢偃新月。',48,'全唐诗/poet.song.130000.json','["墟落斂暮烟，林梢偃新月。", "河橋燈漸閙，柳岸船猶發。", "薄酒吹欲無，佇立搔短髮。", "誰知七十翁，歲晚念裘褐。"]'),
('28b30c49-7ee5-4ef0-b188-0f94ac4d1973','斯道','陸游','宋','宋诗','song-poetry','','[]','斯道有顯晦，所憂非賤貧。',48,'全唐诗/poet.song.130000.json','["斯道有顯晦，所憂非賤貧。", "乾坤均一氣，邊徼亦吾人。", "朋黨消廷論，鉏耰洗戰塵。", "清時更何事，處處是堯民。"]'),
('899fe2df-907a-4d35-80c9-bbc91f4bba2f','病起山居日有幽事戲作二首  其一','陸游','宋','宋诗','song-poetry','','[]','靈府超然外物輕，静中談笑却三彭。',64,'全唐诗/poet.song.130000.json','["靈府超然外物輕，静中談笑却三彭。", "晴窗風竹參差影，霜樹山禽格磔聲。", "客出異苗咨藥品，僧擕奇篆乞書評。", "幽居亦未全無事，更用人間有姓名。"]'),
('67645c23-1b12-4b99-8d39-94642c03714c','病起山居日有幽事戲作二首  其二','陸游','宋','宋诗','song-poetry','','[]','鶴骨龜腸欲不禁，扶衰初喜罷呻吟。',64,'全唐诗/poet.song.130000.json','["鶴骨龜腸欲不禁，扶衰初喜罷呻吟。", "盆山冰釋書窗暖，藥竈香濃道院深。", "筆健乍臨新獲帖，手生重理舊傳琴。", "閉門局促還堪恨，雲海何時豁此心。"]'),
('e6489776-8f73-4476-a91d-6e58b614a3fc','蝸廬','陸游','宋','宋诗','song-poetry','','[]','蝸廬四壁空，也過百年中。',48,'全唐诗/poet.song.131000.json','["蝸廬四壁空，也過百年中。", "葑火朝供爨，蘆綿夕禦風。", "不憎窮有祟，自以放名翁。", "但恨村醪薄，衰顔只暫紅。"]'),
('92d222ab-23a1-4f3c-8f87-88a9bbedd139','冬夜讀書有感二首  其一','陸游','宋','宋诗','song-poetry','','[]','一指頭禪用不窮，一刀匕藥去凌空。',32,'全唐诗/poet.song.131000.json','["一指頭禪用不窮，一刀匕藥去凌空。", "汗牛充棟成何事，堪笑迂儒錯用功。"]'),
('0e27c07c-90bc-4557-8dbe-64b7d0234b04','冬夜讀書有感二首  其二','陸游','宋','宋诗','song-poetry','','[]','胸中十萬宿貔貅，皂纛黄旗志未酬。',32,'全唐诗/poet.song.131000.json','["胸中十萬宿貔貅，皂纛黄旗志未酬。", "莫笑蓬窗白頭客，時来談笑取幽州。"]'),
('af54c42e-91ca-4209-ae42-5ee8a0004b05','十二月九日枕上作','陸游','宋','宋诗','song-poetry','','[]','卧聴百舌語簾櫳，已是新春不是冬。',32,'全唐诗/poet.song.131000.json','["卧聴百舌語簾櫳，已是新春不是冬。", "堪嘆老来如許病，正令無病亦無悰。"]'),
('ab0f8ee1-3085-4e6e-a68b-bf8693c32dd6','記夢三首  其一','陸游','宋','宋诗','song-poetry','','[]','黄河衮衮抱潼關，蒼翠中條接華山。',32,'全唐诗/poet.song.131000.json','["黄河衮衮抱潼關，蒼翠中條接華山。", "城郭丘墟人盡老，藥爐依舊白雲間。"]'),
('ad76dad0-3889-4db7-9f22-c567e88a40f1','記夢三首  其二','陸游','宋','宋诗','song-poetry','','[]','西巖老宿雪垂肩，白石爲糧四百年。',32,'全唐诗/poet.song.131000.json','["西巖老宿雪垂肩，白石爲糧四百年。", "喜我未忘山下路，慇懃握手一欣然。"]'),
('cfb271d5-654d-488a-8f11-09d3d849d289','記夢三首  其三','陸游','宋','宋诗','song-poetry','','[]','三髻山童喜欲顛，下山迎我拜溪邊。',32,'全唐诗/poet.song.131000.json','["三髻山童喜欲顛，下山迎我拜溪邊。", "松陰拂罷蒼苔石，接竹穿雲理舊泉。"]'),
('2d73e771-983d-4cbe-8900-95fb17eaf887','鏡湖女','陸游','宋','宋诗','song-poetry','','[]','湖中居人事舟檝，家家以舟作生業。',64,'全唐诗/poet.song.131000.json','["湖中居人事舟檝，家家以舟作生業。", "女兒粧面花樣紅，小繖翻翻亂荷葉。", "日暮歸来月色新，菱歌縹緲泛烟津。", "到家更約西鄰女，明日湖橋看賽神。"]'),
('d46fb649-cdca-4e62-8ea8-90ec338ae58c','水村曲','陸游','宋','宋诗','song-poetry','','[]','山村今年晚禾旱，奏下民租蠲太半。',64,'全唐诗/poet.song.131000.json','["山村今年晚禾旱，奏下民租蠲太半。", "水村雨足米狼戾，也放三分慰民意。", "看榜歸来迭歌舞，共喜清平好官府。", "老翁猶記軍興時，汝輩少年那得知。"]'),
('d8cf8c6a-06da-4879-bff7-da62df2d7332','石洞餉酒','陸游','宋','宋诗','song-poetry','','[]','忘憂自古無上筞，欲飲家貧酒杯迮。',96,'全唐诗/poet.song.131000.json','["忘憂自古無上筞，欲飲家貧酒杯迮。", "今朝鵲喜報遠餉，未坼赤泥先動色。", "魚長三尺催膾玉，巨蟹兩螯仍斫雪。", "勿言地僻少過從，清風明月俱吾客。", "驅除二豎走三彭，零落眼花生耳熱。", "陶然酣卧聴松聲，愧爾公卿足憂責。"]'),
('ce7e7b78-ebc9-416d-9e01-f5601a601b9d','病退','陸游','宋','宋诗','song-poetry','','[]','病退身仍健，春回日漸長。',48,'全唐诗/poet.song.131000.json','["病退身仍健，春回日漸長。", "神訶金鼎藥，龍出玉函方。", "美睡三竿日，安禪半篆香。", "殘年已如許，幸復起膏盲。"]'),
('11c3bf0d-f46c-4980-b56e-7bd03e380cc6','偶書','陸游','宋','宋诗','song-poetry','','[]','身放江湖遠，年推里巷尊。',48,'全唐诗/poet.song.131000.json','["身放江湖遠，年推里巷尊。", "鄰翁分酒子，羽客借桐孫。", "決決冰消澗，纎纎柳映門。", "小車非漢相，時亦到前村。"]'),
('8ac16398-447a-4b30-8a1f-0b5778303ca8','讀史','陸游','宋','宋诗','song-poetry','','[]','南言蓴菜似羊酪，北說茘枝如石榴。',32,'全唐诗/poet.song.131000.json','["南言蓴菜似羊酪，北說茘枝如石榴。", "自古論人多類此，簡編千載判悠悠。"]'),
('ac3e8ed4-b1a5-4b53-aa11-02e0b47ebf73','飲石洞酒戲作','陸游','宋','宋诗','song-poetry','','[]','酣酣霞暈力通神，澹澹鵝雛色可人。',64,'全唐诗/poet.song.131000.json','["酣酣霞暈力通神，澹澹鵝雛色可人。", "一笑破除垂老日，滿懷揺蕩隔年春。", "梅花的的吹初破，楊柳纎纎染未勻。", "醉倒橋邊人不怪，西曹免護相君茵。"]'),
('27ffdef9-32ba-424c-9ba0-09b6fde6be45','霜寒','陸游','宋','宋诗','song-poetry','','[]','霜重晨簷滴，薪乾夜焙温。',48,'全唐诗/poet.song.131000.json','["霜重晨簷滴，薪乾夜焙温。", "老惟便布褐，病不出柴門。", "瓶裏梅花墮，窗間鵲語喧。", "閑人信無事，午睡到黄昏。"]'),
('07253ef2-e787-42d3-9902-93dd63066c95','賽神曲','陸游','宋','宋诗','song-poetry','','[]','擊鼓坎坎，吹笙嗚嗚。',154,'全唐诗/poet.song.131000.json','["擊鼓坎坎，吹笙嗚嗚。", "緑袍槐簡立老巫，紅衫繡裙舞小姑。", "烏桕燭明蠟不如，鯉魚糝美出神厨。", "老巫前致詞，小姑抱酒壺。", "願神来享常歡娛，使我嘉穀收連車。", "牛羊暮歸塞門閭，雞鶩一母生百雛。", "歲歲賜粟，年年蠲租。", "蒲鞭不施，圜土空虚。", "束草作官但形模，刻木爲吏無文書。", "淳風復還羲皇初，繩亦不結况其餘。", "神歸人散醉相扶，夜深歌舞官道隅。"]'),
('e5970bde-6dc1-4a29-888d-13954c6dc453','涼州行','陸游','宋','宋诗','song-poetry','','[]','涼州四面皆沙磧，風吹沙平馬無迹。',96,'全唐诗/poet.song.131000.json','["涼州四面皆沙磧，風吹沙平馬無迹。", "東門供張接中使，萬里朱宣布襖勑。", "勅中墨色如未乾，君王心念兒郎寒。", "當街謝恩拜舞罷，萬歲聲上黄雲端。", "安西北庭皆郡縣，四方朝貢無征戰。", "舊時胡虜陷關中，五丈原頭作邊面。"]'),
('b0526f70-c8f9-46e8-a252-534e77975331','望夫石','陸游','宋','宋诗','song-poetry','','[]','送君遠戍交河北，男兒自以身許國。',64,'全唐诗/poet.song.131000.json','["送君遠戍交河北，男兒自以身許國。", "不能彎弓騎惡馬，欲隨君去何由得。", "登山矯首西北雲，形容雖變心猶存。", "月明夜夜照泪痕，鐵心石腸輸與君。"]'),
('43262de4-e2e5-41a5-8051-50856598e0e6','江村道中書觸目','陸游','宋','宋诗','song-poetry','','[]','短籬曲曲對開門，修竹陰陰不見村。',64,'全唐诗/poet.song.131000.json','["短籬曲曲對開門，修竹陰陰不見村。", "别浦回潮魚滬密，孤舟春近雁沙温。", "路逢行客時交轡，店賣新醅一舉樽。", "忽過亂山幽絕處，恍如白帝到東屯。"]'),
('70f37812-8c4d-4279-a96d-1e31bde9cdb2','采蓮曲','陸游','宋','宋诗','song-poetry','','[]','采蓮吳姝巧笑倩，小舟點破烟波面。',64,'全唐诗/poet.song.131000.json','["采蓮吳姝巧笑倩，小舟點破烟波面。", "雙頭折得欲有贈，重重葉盖羞人見。", "女伴相邀拾翠羽，歸棹如飛那可許。", "傾鬟障袖不譍人，遥指石帆山下雨。"]'),
('469ba000-11c3-4527-a80b-57d088c5379d','兀坐頗念遊歴山水戲作','陸游','宋','宋诗','song-poetry','','[]','萬里當時寄一官，十年客枕不曾安。',64,'全唐诗/poet.song.131000.json','["萬里當時寄一官，十年客枕不曾安。", "鬼愁灘下扁舟晚，蛇退陂前古驛寒。", "昔嘆遠遊生雪鬢，近緣多病學金丹。", "功名非復衰翁事，獨有江山興未闌。"]'),
('b2ebbfbb-6eaa-4999-888e-6a936e29c8bd','五雜組二首  其一','陸游','宋','宋诗','song-poetry','','[]','五雜組，山雉羽。',24,'全唐诗/poet.song.131000.json','["五雜組，山雉羽。", "往復還，江頭路。", "不得已，貴臣去。"]'),
('8a876468-8a0d-4c79-b7ed-fbf4eb866ce9','五雜組二首  其二','陸游','宋','宋诗','song-poetry','','[]','五雜組，機上綺。',24,'全唐诗/poet.song.131000.json','["五雜組，機上綺。", "往復還，冶逰子。", "不得已，富兒死。"]'),
('f6745b32-06c8-4e4e-afe6-8f0d868e2be1','漁扉','陸游','宋','宋诗','song-poetry','','[]','湖上千峰翠作圍，正應佳處著漁扉。',64,'全唐诗/poet.song.131000.json','["湖上千峰翠作圍，正應佳處著漁扉。", "迂疏自計難謀食，老病誰令未拂衣。", "萬里滄波鷗乍沒，千年華表鶴重歸。", "一盂粟飯吾何恨，自古高人有采薇。"]'),
('f3d85a3d-3e2d-4e6b-a6fd-b3c64ea4b2c9','詠史','陸游','宋','宋诗','song-poetry','','[]','夜雨燈前感概深，爲邦一士重千金。',64,'全唐诗/poet.song.131000.json','["夜雨燈前感概深，爲邦一士重千金。", "風雲未展康時略，天地能知許國心。", "劍忽拄頤都將相，帽曾壓耳隠山林。", "英雄自古常如此，君看隆中梁甫吟。"]'),
('ad214ff8-6e6e-4c6d-9f29-6004b3d8b6d2','烏棲曲','陸游','宋','宋诗','song-poetry','','[]','楚王手自格猛獸，七澤三江爲苑囿。',80,'全唐诗/poet.song.131000.json','["楚王手自格猛獸，七澤三江爲苑囿。", "城門夜開待獵歸，萬炬照空如白晝。", "樂聲前後震百里，樹樹棲烏盡驚起。", "宫中美人謂將旦，髮澤口脂費千萬。", "樂聲早暮少斷時，莫怪棲烏無穏枝。"]'),
('c60f7ec5-bea5-47c2-901b-93b8234fd905','古别離','陸游','宋','宋诗','song-poetry','','[]','君北遊司并，我南適熊湘。',96,'全唐诗/poet.song.131000.json','["君北遊司并，我南適熊湘。", "邂逅淮陰市，共飲官道傍。", "丈夫各有懷，窮達詎可量。", "臨别一取醉，浩歌神激揚。", "勲業有際會，風雲正蒼茫。", "亂點劍峰血，苦寒芒屨霜。", "死即萬鬼鄰，生當致虞唐。", "丹雞不須盟，我非兒女腸。"]'),
('32d99340-ace3-4eda-86ae-03efb6e7e59b','書嘆','陸游','宋','宋诗','song-poetry','','[]','夜深青燈耿窗扉，老翁稚子窮相依。',128,'全唐诗/poet.song.131000.json','["夜深青燈耿窗扉，老翁稚子窮相依。", "韲鹽不給脫粟飯，布褐僅有懸鶉衣。", "偶然得肉思共飽，吾兒苦讓不忍違。", "兒饑讀書到雞唱，意雖甚壯氣力微。", "可憐落筆漸健快，其奈瘦面無光輝。", "布衣儒生例骨立，紈袴市兒皆瓠肥。", "勿言學古徒自困，吾曹捨此將安歸。", "作詩自寛亦慰汝，吟罷撫几頻歔欷。"]'),
('f873ef9c-c762-45a8-849a-2b3efc69dcea','十二月二十六夜聴雨','陸游','宋','宋诗','song-poetry','','[]','新春尚七日，小雨暗江城。',72,'全唐诗/poet.song.131000.json','["新春尚七日，小雨暗江城。", "茆簷夜點滴，已作春雨聲。", "輕黄上柳枝，嫩綠抽菊萌。", "造物本何心，誰主此發生。", "頗疑重雲外，斗杓已東傾。", "老至不可却，一尊忘濁清。"]'),
('7d76030f-f774-44f6-b067-8bd1b293015b','起晚','陸游','宋','宋诗','song-poetry','','[]','傍簷百舌語璁瓏，已覺新春在眼中。',32,'全唐诗/poet.song.131000.json','["傍簷百舌語璁瓏，已覺新春在眼中。", "欲起未成還小睡，忽看初日滿窗紅。"]'),
('23916da9-e65b-4fde-88a5-da0a50308bbd','陳少監餉澄清堂酒','陸游','宋','宋诗','song-poetry','','[]','酣暢年来豈易逢，韲湯蜜汁亦時中。',32,'全唐诗/poet.song.131000.json','["酣暢年来豈易逢，韲湯蜜汁亦時中。", "玉醅忽逐春風至，一吸懸知百榼空。"]'),
('1d06495b-3cd4-4369-8360-f01349bc5b85','雪中作','陸游','宋','宋诗','song-poetry','','[]','黑風卷地連三日，密雪穿簾又一回。',64,'全唐诗/poet.song.131000.json','["黑風卷地連三日，密雪穿簾又一回。", "衰病不禁天色惡，笑談誰共酒尊開。", "忍寒瘦馬嘶空櫪，覔食饑鴉啄廢臺。", "笑遣蠻童撼園竹，輟羮分火待歸来。"]'),
('80f25700-c11f-450f-a342-a78f67d1b4fd','甲寅元日予七十矣酒間作短歌示子','陸游','宋','宋诗','song-poetry','','[]','我昔自蜀歸，百年已過半。',192,'全唐诗/poet.song.131000.json','["我昔自蜀歸，百年已過半。", "觀棋未終局，回視斧柯爛。", "飽知山林樂，富貴何足換。", "退休失健決，正坐闇且懦。", "齒髮日衰殘，歲月難把玩。", "蕭朱尚或隙，籍湜固宜畔。", "出門無一欣，撫事有三嘆。", "新年遂七十，推敬愧里閈。", "眷眷惜兹夕，凜凜畏明旦。", "豁然忽大笑，愁若春冰泮。", "窮達真兩忘，生死付一貫。", "清尊既瀲灧，碩果亦璀璨。", "擁門紛鼓笛，上壽列童冠。", "老翁亦忘疲，起舞影零亂。", "不獨誇癡頑，自足洗患難。", "投床判宿酲，美睡到日旰。"]'),
('a1891a98-6cdf-4524-a292-a221f50954c6','七十','陸游','宋','宋诗','song-poetry','','[]','七十殘年百念枯，桑榆元不補東隅。',64,'全唐诗/poet.song.131000.json','["七十殘年百念枯，桑榆元不補東隅。", "但存隠具金鴉觜，那夢朝衣玉鹿盧。", "身世蠶眠將作繭，形容牛老已垂胡。", "客来莫問先生處，不釣娥江即鏡湖。"]'),
('9b83d32e-732f-4f56-9cf4-83bda34e6e90','正旦後一日','陸游','宋','宋诗','song-poetry','','[]','七十今年是，連朝樂未休。',48,'全唐诗/poet.song.131000.json','["七十今年是，連朝樂未休。", "比鄰更頌禱，親黨共遲留。", "羊映紅纒酒，花簪絳帕頭。", "從今日有喜，農事起西疇。"]'),
('76a1d80f-5529-43c5-8c2e-9ac02519e64d','立春','陸游','宋','宋诗','song-poetry','','[]','採花枝上寶旛新，看徧秦山楚水春。',32,'全唐诗/poet.song.131000.json','["採花枝上寶旛新，看徧秦山楚水春。", "村舍不知時節換，傍檐百舌苦撩人。"]'),
('0562a259-3398-4499-b6d7-3d462113fa22','老境','陸游','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','髮白未及童，齒揺未及脫。',72,'全唐诗/poet.song.131000.json','["髮白未及童，齒揺未及脫。", "正如一席飲，燒燭將見跋。", "谿山環草舍，霜露侵布褐。", "文章雖自力，亦已强弩末。", "寜將垂老耳，更受世事聒。", "匡廬入我夢，行已寄瓶鉢。"]'),
('a84fe251-c867-4824-92bd-4cd0f1561136','偶懷小益南鄭之間悵然有賦','陸游','宋','宋诗','song-poetry','','[]','西戍涼州鬢未絲，嶓山漾水幾題詩。',64,'全唐诗/poet.song.131000.json','["西戍涼州鬢未絲，嶓山漾水幾題詩。", "劍分蒼石高皇迹，巖擁朱門老子祠。", "燒兔驛亭微雪夜，騎驢棧路早梅時。", "登臨不用頻悽斷，未死安知無後期。"]'),
('644dc5b3-d97c-414f-8e8e-6104fa4147fd','再用前韵不依次','陸游','宋','宋诗','song-poetry','','[]','憶昨從戎丞相府，元瑜書檄仲宣詩。',64,'全唐诗/poet.song.131000.json','["憶昨從戎丞相府，元瑜書檄仲宣詩。", "雲屯騎士臨邊日，魚貫降戎獻捷時。", "史冊誤人悲壯志，關河回首負初期。", "豈知二紀身猶在，衰鬢星星老侍祠。"]'),
('e1c16175-aeda-47e4-bfba-105ebe008252','北坡梅開已久一枝獨不著花立春日忽放一枝戲作','陸游','宋','宋诗','song-poetry','','[]','日日来尋坡上梅，枯槎忽見一枝開。',32,'全唐诗/poet.song.131000.json','["日日来尋坡上梅，枯槎忽見一枝開。", "廣寒宫裏長生藥，醫得冰魂雪魄回。"]'),
('26e78c41-bff4-44fc-822d-f36b7c324040','人日','陸游','宋','宋诗','song-poetry','','[]','新歲逢人日，老夫持道齋。',48,'全唐诗/poet.song.131000.json','["新歲逢人日，老夫持道齋。", "斷冰浮野水，微緑發枯荄。", "霽景豐年象，閑吟曠士懷。", "春旛已陳迹，鬭巧笑吳娃。"]'),
('fcde0934-e1d7-4e64-b5bb-2f02e091a153','夜讀吕化光文章抛盡愛功名之句戲作','陸游','宋','宋诗','song-poetry','','[]','玉關西望氣横秋，肯信功名不自由。',32,'全唐诗/poet.song.131000.json','["玉關西望氣横秋，肯信功名不自由。", "却是文章差得力，至今知有吕衡州。"]'),
('759c51c0-7585-4c5e-888d-5a472739def3','遇術士飲以巵酒','陸游','宋','宋诗','song-poetry','','[]','行藥来村北，觀魚立水邊。',48,'全唐诗/poet.song.131000.json','["行藥来村北，觀魚立水邊。", "忽逢長揖客，能算小行年。", "酒薄聊頳頬，囊空闕贈錢。", "時清君未死，訪我華山前。"]'),
('fab55cbd-0549-48c5-ae7b-ce43030bc6f8','閑趣','陸游','宋','宋诗','song-poetry','','[]','老子即今雙白鬢，鏡湖自古幾青山。',64,'全唐诗/poet.song.131000.json','["老子即今雙白鬢，鏡湖自古幾青山。", "半窗蘿月獨欹枕，滿院松風常掩關。", "天地許寛誰礙汝，琴尊是處可開顔。", "將行亦莫買春草，幸有一笻相伴閑。"]'),
('ef4ec2c9-dbe7-46d5-afe0-452cb14575d6','正月二十日晨起弄筆','陸游','宋','宋诗','song-poetry','','[]','深院窗扉曉色遲，新愁宿醉兩參差。',64,'全唐诗/poet.song.131000.json','["深院窗扉曉色遲，新愁宿醉兩參差。", "雨聲欲與夢相入，春意不隨人共衰。", "零落殘梅臨小彴，縱横野水赴清池。", "物華撩我緣何事，似恐新年漸廢詩。"]'),
('b386aa47-cf80-46ef-ba9d-4b7b8005277d','春夜讀書','陸游','宋','宋诗','song-poetry','','[]','枉是儒冠遇太平，窮人那許共功名。',64,'全唐诗/poet.song.131000.json','["枉是儒冠遇太平，窮人那許共功名。", "枯腸不飽三升稷，皓首猶親二尺檠。", "寓世已爲當去客，愛書更付未来生。", "夜闌撫几愁無奈，起視離離斗柄傾。"]'),
('df43c546-ea52-4acd-86e8-b33b8f965dc8','春晴泛湖入城','陸游','宋','宋诗','song-poetry','','[]','春色初回杜若洲，隔烟時見矯輕鷗。',64,'全唐诗/poet.song.131000.json','["春色初回杜若洲，隔烟時見矯輕鷗。", "嵩雲緱月年年夢，楚柁吳檣處處愁。", "魚躍銀刀論網買，酒傾綠蟻滿杯浮。", "前生杜牧吾身是，又向江南遍倚樓。"]'),
('c8f7428e-b6c8-4f8e-bbd5-c3672c342447','書齋壁二首  其一','陸游','宋','宋诗','song-poetry','','[]','老病人扶氣力微，闌干西角立斜暉。',64,'全唐诗/poet.song.131000.json','["老病人扶氣力微，闌干西角立斜暉。", "流年冉冉功名誤，新冢纍纍故舊稀。", "仗馬曾鳴宜永棄，牧羝雖乳敢言歸。", "住庵活計無多子，只要笻枝與衲衣。"]'),
('cf2215ca-6521-4d5a-8702-5001db68ff1c','書齋壁二首  其二','陸游','宋','宋诗','song-poetry','','[]','落魄人間不記年，晚營茆棟鏡湖邊。',64,'全唐诗/poet.song.131000.json','["落魄人間不記年，晚營茆棟鏡湖邊。", "室空惟是四壁立，面瘦漸生雙頬顴。", "地僻門無殘客到，歲豐路有醉人眠。", "君看朝市紅塵閙，始信吾曹是地仙。"]'),
('44c851ad-df52-4aaf-b546-d4802f66ab06','春日睡起','陸游','宋','宋诗','song-poetry','','[]','睡起悠然弄衲琴，銅猊半燼海南沉。',64,'全唐诗/poet.song.131000.json','["睡起悠然弄衲琴，銅猊半燼海南沉。", "淒涼故里逢春處，忠憤孤臣許國心。", "水滿鳬鷖初拍拍，雨餘花木已陰陰。", "吾兒捩柂淮邊未，歸近清愁轉不禁。"]'),
('f19ea6d1-347d-4c2a-862b-a8b28512ff07','老病謝客或者非之戲作','陸游','宋','宋诗','song-poetry','','[]','病侵腰膂兩經秋，欲下繩床不自由。',64,'全唐诗/poet.song.131000.json','["病侵腰膂兩經秋，欲下繩床不自由。", "客至難令三握髮，佛来僅可小低頭。", "安禪還我閑蒙衲，怒氣從渠勇挟輈。", "亦欲署門還懶去，死生貴賤兩悠悠。"]'),
('54001d05-12b5-42b3-bc8e-7005ff85cb31','永日無一事作詩自詒','陸游','宋','宋诗','song-poetry','','[]','目昏罷觀書，足蹇停遊山。',96,'全唐诗/poet.song.131000.json','["目昏罷觀書，足蹇停遊山。", "二事差可樂，造物乃復慳。", "得非閔我老，作意鐫其頑。", "掃除盡宿習，使得終日閑。", "閑亦何負汝，剡曲茆三間。", "奇石玩犖角，清流聴潺湲。", "勿言村醪薄，數酌可解顔。", "翛然日已夕，卧看飛鳥還。"]'),
('2ea2700c-d0db-4743-8901-d33bd9ffdab5','窗前作小土山蓻蘭及玉簪最後得香百合併種之戲作','陸游','宋','宋诗','song-poetry','','[]','方蘭移取徧中林，餘地何妨種玉簪。',32,'全唐诗/poet.song.131000.json','["方蘭移取徧中林，餘地何妨種玉簪。", "更乞兩叢香百合，老翁七十尚童心。"]'),
('290eb48e-557e-4c89-a44e-97c5af3a59f7','泛舟觀桃花五首  其一','陸游','宋','宋诗','song-poetry','','[]','花涇二月桃花發，霞照波心錦裹山。',32,'全唐诗/poet.song.131000.json','["花涇二月桃花發，霞照波心錦裹山。", "說與東風直須惜，莫吹一片落人間。"]'),
('f1c71fdf-38c3-4473-ab4b-1b331924d61c','泛舟觀桃花五首  其二','陸游','宋','宋诗','song-poetry','','[]','桃源只在鏡湖中，影落清波十里紅。',32,'全唐诗/poet.song.131000.json','["桃源只在鏡湖中，影落清波十里紅。", "自别西川海棠後，初將爛醉荅春風。"]'),
('bcda1183-e67c-48b2-968c-3ae0e011e765','泛舟觀桃花五首  其三','陸游','宋','宋诗','song-poetry','','[]','種桃亦解比封君，世故紛紛寂不聞。',32,'全唐诗/poet.song.131000.json','["種桃亦解比封君，世故紛紛寂不聞。", "九轉金丹應已熟，全家仙去隠紅雲。"]'),
('7982b880-b0a4-4654-80bc-77a8e50d534b','泛舟觀桃花五首  其四','陸游','宋','宋诗','song-poetry','','[]','湖南小山花更多，不醉將如春色何。',32,'全唐诗/poet.song.131000.json','["湖南小山花更多，不醉將如春色何。", "釣得鮮鱗堪斫膾，任教微雨濕漁簔。"]'),
('6c0b8419-3c8d-4d81-a0b1-1c9866f797be','泛舟觀桃花五首  其五','陸游','宋','宋诗','song-poetry','','[]','鄰曲一生花裏活，村翁疑是古遺民。',32,'全唐诗/poet.song.131000.json','["鄰曲一生花裏活，村翁疑是古遺民。", "初来自被春留住，枉道當時爲避秦。"]'),
('bfb029b5-1232-4138-846e-0145d1eb99e4','新闢小園六首  其一','陸游','宋','宋诗','song-poetry','','[]','人生如意毎難全，草草園池却自然。',64,'全唐诗/poet.song.131000.json','["人生如意毎難全，草草園池却自然。", "世事已抛高枕外，春風常在短笻前。", "墮空花片紛紅雨，徧地苔痕長緑錢。", "酒户漸增詩興在，天容此老剩狂顛。"]'),
('faa98485-5651-4524-bae4-d636c04501b7','新闢小園六首  其二','陸游','宋','宋诗','song-poetry','','[]','西戍歸来鬢已霜，生兒又過乃翁長。',64,'全唐诗/poet.song.131000.json','["西戍歸来鬢已霜，生兒又過乃翁長。", "眼明身健殘年足，飯軟茶甘萬事忘。", "學廢僅能書妵字，客来懶復倒衣裳。", "山園寂寂春將晚，酷愛幽花似蜜香。"]'),
('669e38d0-c9c2-4421-9b68-99039db69be5','新闢小園六首  其三','陸游','宋','宋诗','song-poetry','','[]','席地幕天君勿嘲，隨宜野蓛與山殽。',64,'全唐诗/poet.song.131000.json','["席地幕天君勿嘲，隨宜野蓛與山殽。", "幽花避日藏深葉，歸燕尋人理舊巢。", "曲水詠觴空念昔，斜川鄰曲自論交。", "清貧尚愧茶山在，送老湖邊有把茆。"]'),
('7d094edf-d010-4021-a37c-b061c54545e4','新闢小園六首  其四','陸游','宋','宋诗','song-poetry','','[]','新展山園半畆强，笑人車馬出籠坊。',64,'全唐诗/poet.song.131000.json','["新展山園半畆强，笑人車馬出籠坊。", "山禽乍暖慇懃語，野蘤無風自在香。", "點點水紋迎細雨，疏疏籬影界斜陽。", "出門遥向鄰翁說，釋耒相從共一觴。"]'),
('24fb84d7-2c62-48a9-b7c0-a8bf1ddf4216','新闢小園六首  其五','陸游','宋','宋诗','song-poetry','','[]','東軒嫩日上疏櫺，吹盡浮雲作意晴。',64,'全唐诗/poet.song.131000.json','["東軒嫩日上疏櫺，吹盡浮雲作意晴。", "林暖牆頭雙鵲語，水清池面小魚行。", "畦添藥品誰能别，架引藤陰忽已成。", "倚杖怡然便終日，老夫那復不平鳴。"]'),
('f16171d3-fb05-4580-91e2-ef03652104eb','新闢小園六首  其六','陸游','宋','宋诗','song-poetry','','[]','祠祿縻人未棄官，春深幽谷有餘歡。',64,'全唐诗/poet.song.131000.json','["祠祿縻人未棄官，春深幽谷有餘歡。", "筍生遮道妨行藥，果熟團枝礙整冠。", "煮酒拆泥初灧灧，生綃裁扇又團團。", "退飛風際由来事，莫羨青霄刷羽翰。"]'),
('52b558c8-286b-4830-a450-9f147ce942ac','上巳小飲追憶乾道中嘗以是日病酒留三泉江月亭悽然有感','陸游','宋','宋诗','song-poetry','','[]','零落殘花一兩枝，綠陰庭院燕差池。',32,'全唐诗/poet.song.131000.json','["零落殘花一兩枝，綠陰庭院燕差池。", "隔牆笑語鞦韆散，惆悵三泉驛裏時。"]'),
('9bd243da-b7f3-4380-a289-ce2928ee9457','晚步門外散懷二首  其一','陸游','宋','宋诗','song-poetry','','[]','大千沙界一浮漚，成壊元知不自由。',64,'全唐诗/poet.song.131000.json','["大千沙界一浮漚，成壊元知不自由。", "寓迹箇中誰耐久，問君底事不歸休。", "春陂欲雨黄鴉閙，晚渡無人白犢浮。", "七十之年何啻足，戲憑藥物小遲留。"]'),
('9a5835b2-0c76-4895-ac77-5d07f58bd3e2','晚步門外散懷二首  其二','陸游','宋','宋诗','song-poetry','','[]','萬化紛紛本一機，不爲腐骨欲安歸。',64,'全唐诗/poet.song.131000.json','["萬化紛紛本一機，不爲腐骨欲安歸。", "彭殤共盡孰修短，堯桀兩忘無是非。", "濡首極知當痛飲，剪翎那復許群飛。", "江郊未解春寒惡，高柳吹花又滿衣。"]'),
('7fcc9914-a0cc-4227-98f7-f74f2851ecc9','欲出遇雨','陸游','宋','宋诗','song-poetry','','[]','東風吹雨惱遊人，滿路新泥換細塵。',32,'全唐诗/poet.song.131000.json','["東風吹雨惱遊人，滿路新泥換細塵。", "花睡柳眠春自懶，誰知我更懶於春。"]'),
('9679eb4c-980e-496b-b383-81b5db58e420','饑坐戲詠','陸游','宋','宋诗','song-poetry','','[]','衰鬢蕭然滿鏡霜，一庵歸老鏡湖傍。',64,'全唐诗/poet.song.131000.json','["衰鬢蕭然滿鏡霜，一庵歸老鏡湖傍。", "有懷每恨交朋遠，無食方知日月長。", "落筆未妨詩衮衮，閉門猶喜氣揚揚。", "晚来袖手蒲團穏，笑喚兒童代夜香。"]'),
('c2696787-a9c6-43a9-85c0-18738fb9790a','蔬食','陸游','宋','宋诗','song-poetry','','[]','今年徹底貧，不復具一肉。',80,'全唐诗/poet.song.131000.json','["今年徹底貧，不復具一肉。", "日高對空案，腸鳴轉車軸。", "春薺忽已花，老筍欲成竹。", "平生飯蔬食，至此亦不足。", "孰知讀書却少進，忍饑對客談堯舜。", "但令此道粗有傳，深山餓死吾何恨。"]'),
('bf10da2b-0a1d-48b7-84de-bf7388e7eccd','山亭','陸游','宋','宋诗','song-poetry','','[]','風惡闌回雨，天寒勒住花。',48,'全唐诗/poet.song.131000.json','["風惡闌回雨，天寒勒住花。", "尋幽扶楖栗，息倦倚槎枒。", "分韵僧吟苦，爭碁客笑譁。", "相逢仍草草，歸路並山斜。"]'),
('a486b3ab-1056-473b-9507-924c757af6f3','久不得張漢州書','陸游','宋','宋诗','song-poetry','','[]','儘道三巴遠，那無一紙書。',24,'全唐诗/poet.song.131000.json','["儘道三巴遠，那無一紙書。", "衰遲自難記，不是故人疏。"]'),
('ac267d2a-6ab4-4a83-b07d-d9d20530c016','春晚村居','陸游','宋','宋诗','song-poetry','','[]','一事元無可得忙，悠然半醉倚胡床。',64,'全唐诗/poet.song.131000.json','["一事元無可得忙，悠然半醉倚胡床。", "牡丹枝上青春老，燕子聲中白日長。", "身世已如風六鷁，文章仍似閏黄楊。", "太平有象無人識，南陌東阡擣麨香。"]'),
('3a37d870-91a8-48fc-9ba4-8efb0dce603d','遊雲山諸蘭若','陸游','宋','宋诗','song-poetry','','[]','花過木陰合，溪雲生莫涼。',48,'全唐诗/poet.song.131000.json','["花過木陰合，溪雲生莫涼。", "牛行響白水，鷺下點青秧。", "古寺宛如昔，稚松森已行。", "耆年不下榻，童子爲燒香。"]'),
('0fdadb50-fbfa-49cd-8bbc-776043909c49','與子坦子聿遊明覺十四韵','陸游','宋','宋诗','song-poetry','','[]','我自何山来，覔路占樓鐘。',168,'全唐诗/poet.song.131000.json','["我自何山来，覔路占樓鐘。", "聨翩兩葛巾，跌蕩一短笻。", "深谷已曛黑，夕陽猶半峰。", "堂中千歲師，磊砢如古松。", "殘僧三四輩，斗粟各自舂。", "長廊久寂寞，香火亦闕供。", "頗聞在世時，一鉢制惡龍。", "時時出雷雨，百里常年豐。", "宿緣忽云盡，獻供無春農。", "饞烏晨攫飯，饑鼠夜穿墉。", "而况我輩人，生世本不逢。", "胡不安汝分，終年抗塵容。", "靜觀興廢事，可洗芥蒂胸。", "一笑下山去，村塢烟重重。"]'),
('82c0f991-e12b-415e-81a4-d673fc9077d9','淨智西窗','陸游','宋','宋诗','song-poetry','','[]','一窗新綠惬幽情，袖手哦詩取次成。',32,'全唐诗/poet.song.131000.json','["一窗新綠惬幽情，袖手哦詩取次成。", "牆外蜜蜂来又去，可憐終日太忙生。"]'),
('83148e91-6ce3-46e7-a0c5-9809088e8b93','小僧乞詩','陸游','宋','宋诗','song-poetry','','[]','風前掩苒草吹香，溪上霏微雨送涼。',32,'全唐诗/poet.song.131000.json','["風前掩苒草吹香，溪上霏微雨送涼。", "萬里安西無夢到，却尋僧話破年光。"]'),
('6bb23163-50b4-47b3-9689-225879a9db6f','西窗睡起','陸游','宋','宋诗','song-poetry','','[]','老便寂寂厭紛紛，借得禪房卧看雲。',64,'全唐诗/poet.song.131000.json','["老便寂寂厭紛紛，借得禪房卧看雲。", "夜宴怕逢觥録事，秋山傭伴獵將軍。", "餘年敢望十寒暑，夙習正須三沐熏。", "斜日滿窗誰喚起，數聲啼鳥隔溪聞。"]'),
('7affe149-f1cc-4fdb-97bb-98e4b02de20f','平水','陸游','宋','宋诗','song-poetry','','[]','旅飯風埃小市傍，却呼拄杖踏斜陽。',32,'全唐诗/poet.song.131000.json','["旅飯風埃小市傍，却呼拄杖踏斜陽。", "可憐陌上離離草，一種逢春各短長。"]'),
('61e77dc5-36de-4a53-954d-51f1d4525745','三月二十五夜達旦不能寐二首  其一','陸游','宋','宋诗','song-poetry','','[]','愁眼已無寐，更堪衰病嬰。',48,'全唐诗/poet.song.131000.json','["愁眼已無寐，更堪衰病嬰。", "蕭蕭窗竹影，磔磔水禽聲。", "捶楚民方急，烟塵虜未平。", "一身那敢計，雪涕爲時傾。"]'),
('d3cd99c8-3337-4082-94d1-ef8355dd179c','三月二十五夜達旦不能寐二首  其二','陸游','宋','宋诗','song-poetry','','[]','憂國心常折，觀書眼欲枯。',48,'全唐诗/poet.song.131000.json','["憂國心常折，觀書眼欲枯。", "百年終坎壈，一飯且枝梧。", "忽忽殘春過，迢迢清夜徂。", "壯心空萬里，老病要人扶。"]'),
('b27b8f85-fa37-4986-af02-c2b9c5ccc2b1','園中小飲','陸游','宋','宋诗','song-poetry','','[]','此老胸中萬頃寛，小園幽徑日追歡。',64,'全唐诗/poet.song.131000.json','["此老胸中萬頃寛，小園幽徑日追歡。", "寜教酒欠尋常債，恥就人求本分官。", "高柳陰濃烟欲暝，叢花紅濕露初溥。", "要知澤國年光晚，已過清明尚淺寒。"]'),
('2f1eaa22-9a66-42c2-9518-4acb819f41a9','舟中夕望','陸游','宋','宋诗','song-poetry','','[]','船掠湖堤不入城，葛巾羽扇試春行。',64,'全唐诗/poet.song.131000.json','["船掠湖堤不入城，葛巾羽扇試春行。", "女牆迤邐横輕靄，佛閣崢嶸倚晚晴。", "樹冒藤花堆故繡，風吹鶯語送新聲。", "細思造物何由報，遣作閑人過此生。"]'),
('5514a91d-911b-4923-b134-1ef81c039a8c','四月一日作','陸游','宋','宋诗','song-poetry','','[]','桃李逢春次第開，坐看零落付蒼苔。',64,'全唐诗/poet.song.131000.json','["桃李逢春次第開，坐看零落付蒼苔。", "壓車麥穂黄雲重，食葉蠶聲白雨来。", "鏡裏頓驚年事速，天邊誰挽斗杓回。", "可憐團扇塵侵損，又見生綃月様裁。"]'),
('20b9cc7d-2911-4744-bc5a-7b7c548cdbbe','舟行過梅市','陸游','宋','宋诗','song-poetry','','[]','新換单衣細葛輕，翛然隨處得閑行。',64,'全唐诗/poet.song.131000.json','["新換单衣細葛輕，翛然隨處得閑行。", "緑陰浦口維舟處，霽日塲中打麥聲。", "醉叟卧途知酒賤，耕農滿野喜時平。", "老来無復雕龍思，遇興新詩取次成。"]'),
('e78e8472-ca4c-467c-b0c2-57cc8d0c1805','山園雜賦四首  其一','陸游','宋','宋诗','song-poetry','','[]','初夏未覺暑，微陰殊勝晴。',48,'全唐诗/poet.song.131000.json','["初夏未覺暑，微陰殊勝晴。", "藤冠稱新沐，蓴菜解餘酲。", "偶據盤陀坐，還扶楖栗行。", "平生志勛業，今日一毫輕。"]'),
('8cf414c8-c605-4476-8e13-95d8decefee0','山園雜賦四首  其二','陸游','宋','宋诗','song-poetry','','[]','藤陰初覆架，菱蔓漸穿萍。',48,'全唐诗/poet.song.131000.json','["藤陰初覆架，菱蔓漸穿萍。", "水繞籬根緑，山從樹罅青。", "長辭帝所夢，不愧草堂靈。", "賴有黄醅法，終年任醉醒。"]'),
('84d994b3-c7e1-4c70-b057-648bee40f019','山園雜賦四首  其三','陸游','宋','宋诗','song-poetry','','[]','一日老一日，一年貧一年。',48,'全唐诗/poet.song.131000.json','["一日老一日，一年貧一年。", "元無肉食相，且作地行仙。", "本不營三窟，何須直一錢。", "村墟櫻筍閙，剩放醉中顛。"]'),
('e3445df3-4166-4d55-ba1b-70d789d0749e','山園雜賦四首  其四','陸游','宋','宋诗','song-poetry','','[]','芳荃真妙士，霜菊亦奇才。',48,'全唐诗/poet.song.131000.json','["芳荃真妙士，霜菊亦奇才。", "邂逅心生敬，慇懃手自培。", "扶持新長桂，護惜欲殘梅。", "此意何人解，頹然付酒杯。"]'),
('bc518951-7631-47ab-84cd-5811f0f91d81','西窗','陸游','宋','宋诗','song-poetry','','[]','西窗偏受夕陽明，好事能来慰此情。',64,'全唐诗/poet.song.131000.json','["西窗偏受夕陽明，好事能来慰此情。", "看畫客無寒具手，論書僧有折釵評。", "薑宜山茗留閑啜，豉下湖蓴喜共烹。", "酒朱門非我事，諸君小住聴松聲。"]'),
('f5228829-a0bb-4873-9738-7cb8f70b33a2','山頭鹿','陸游','宋','宋诗','song-poetry','','[]','呦呦山頭鹿，毛角自媚好。',108,'全唐诗/poet.song.131000.json','["呦呦山頭鹿，毛角自媚好。", "渴飲澗底泉，饑齧林間草。", "漢家方和親，將軍灞陵老。", "天寒弓力勁，木落霜氣早。", "短衣日馳射，逐鹿應弦倒。", "金槃犀筯命有繫，翠壁蒼崖迹如掃。", "何時詔下北擊胡，却起將軍遠征討。", "泉甘草茂上林中，使我母子常相保。"]'),
('faf92c46-ed51-4020-949f-587ed85b37b6','夏四月渴雨恐害布種代鄉鄰作插秧歌','陸游','宋','宋诗','song-poetry','','[]','浸種二月初，插秧四月中。',96,'全唐诗/poet.song.131000.json','["浸種二月初，插秧四月中。", "小舟載秧把，往来疾於鴻。", "吳鹽雪花白，村酒粥面濃。", "長歌相贈答，宛轉含豳風。", "日暮飛槳歸，小市鼓鼕鼕。", "起居問尊老，勤儉教兒童。", "何人采此謡，爲我告相公。", "不必賜民租，但願常年豐。"]'),
('d514dea1-ba0a-45c7-ab43-64e712457b2e','雲童童行','陸游','宋','宋诗','song-poetry','','[]','雲童童，挟雨来。',40,'全唐诗/poet.song.131000.json','["雲童童，挟雨来。", "雨未濡土雲已開，不能爲人斂浮埃。", "山南山北空聞雷，青秧欲槁吁可哀。"]'),
('e3ae9067-9c57-49f0-8de4-13a226428d23','董逃行','陸游','宋','宋诗','song-poetry','','[]','漢末盜賊如牛毛，千戈萬槊更相鏖。',128,'全唐诗/poet.song.131000.json','["漢末盜賊如牛毛，千戈萬槊更相鏖。", "兩都宫殿摩雲高，坐見霜露生蓬蒿。", "渠魁赫赫起臨洮，僵屍自照臍中膏。", "危難繼作如崩濤，王朝荒穢誰復薅。", "逾城散走墜空壕，扶老將幼山中號。", "昔者群枉根株牢，衆憤不能損秋毫。", "誰知此亂亦不遭，名雖放斥實遁逃。", "平民踣死聲嗸嗸，今兹受禍乃我曹。"]'),
('5740c4bf-6e35-4f21-8e44-7c272b1439b6','閔雨二首  其一','陸游','宋','宋诗','song-poetry','','[]','黄沙白霧晝常昏，嗣歲豐凶詎易論。',64,'全唐诗/poet.song.131000.json','["黄沙白霧晝常昏，嗣歲豐凶詎易論。", "寂寂不聞秧鼓動，啞啞實厭水車翻。", "粟囷久盡無遺粒，泪席嘗沾有舊痕。", "聞道憂民又傳詔，蒼生何以報君恩。"]'),
('4b2d2ffe-a7eb-4f62-919a-127a3bdc9600','閔雨二首  其二','陸游','宋','宋诗','song-poetry','','[]','赤日黄塵江上村，徴租惟有吏過門。',64,'全唐诗/poet.song.131000.json','["赤日黄塵江上村，徴租惟有吏過門。", "微風敢喜北窗卧，大旱恐非東海寃。", "千載傅巖疑可致，一篇洪範向誰論。", "青蔬半畝垂生死，且喚鄰翁共灌園。"]'),
('06d608bf-e1af-4ed5-9f38-23386669d362','喜雨','陸游','宋','宋诗','song-poetry','','[]','楚巫奔走畏天慳，變化寜知轉盼間。',64,'全唐诗/poet.song.131000.json','["楚巫奔走畏天慳，變化寜知轉盼間。", "初夜電光揺北斗，平明雲氣冒南山。", "坐令沃野新秧徧，已覺豐年舊觀還。", "白首老農愁破處，夢回高枕聽潺潺。"]'),
('f2c98483-5ca9-4811-8997-817f8f5de5c7','初夏','陸游','宋','宋诗','song-poetry','','[]','已作梅黄雨，猶餘麥秀寒。',48,'全唐诗/poet.song.131000.json','["已作梅黄雨，猶餘麥秀寒。", "穿林紅練带，拔地碧琅玕。", "酒向愁邊薄，衣從病後寛。", "所欣消渴減，乳酪正甘酸。"]'),
('c308e6c9-33b0-4018-aa8e-341a46d706b9','村舍','陸游','宋','宋诗','song-poetry','','[]','門巷桑麻暗，庖厨筍豉香。',48,'全唐诗/poet.song.131000.json','["門巷桑麻暗，庖厨筍豉香。", "僮奴課鉏菜，婢子學燒糠。", "貧任青春過，閑知白日長。", "非關愛疏懶，無事可成忙。"]'),
('69487d06-1678-4424-a0d6-65ae5e27a9ee','鳥啼','陸游','宋','宋诗','song-poetry','','[]','野人無曆日，鳥啼知四時。',116,'全唐诗/poet.song.131000.json','["野人無曆日，鳥啼知四時。", "二月聞子規，春耕不可遲。", "三月聞黄鸝，幼婦閔蠶饑。", "四月鳴布穀，家家蠶上簇。", "五月鳴鴉舅，苗稚憂草茂。", "人言農家苦，望晴復望雨。", "樂處誰得知，生不識官府。", "葛衫麥飯有即休，湖橋小市酒如油。", "夜夜扶歸常爛醉，不怕行逢灞陵尉。"]'),
('ed792958-4c22-493f-873c-cc889af4b12d','感舊','陸游','宋','宋诗','song-poetry','','[]','廢隴荒陂浥浥耕，生無勲業死無名。',32,'全唐诗/poet.song.131000.json','["廢隴荒陂浥浥耕，生無勲業死無名。", "衰頹日甚君休問，三十年前白髮生。"]'),
('d5c39345-b7e0-4ea3-97e1-44bab7029b49','讀書至夜半燈盡欲睡慨然有感','陸游','宋','宋诗','song-poetry','','[]','白髮蕭蕭老空谷，人嘆厄窮心自足。',96,'全唐诗/poet.song.131000.json','["白髮蕭蕭老空谷，人嘆厄窮心自足。", "東郊曉射墮錦雉，北崦春耕叱黄犢。", "區區世事何足論，未死斷知常閉門。", "關河好在萬里路，理亂不至三家村。", "夜分燈暗月入户，賦詩肯道儒冠誤。", "饑鷹勁翮高有聲，横截陂湖正南去。"]'),
('ade4d56f-b811-42c5-ac37-8b9451a209d9','遣興','陸游','宋','宋诗','song-poetry','','[]','壯歲元多病，長年敢自期。',48,'全唐诗/poet.song.131000.json','["壯歲元多病，長年敢自期。", "賤貧交易絕，憂患夢常悲。", "續食叨微祿，寛心賴小兒。", "平生鏡湖上，天乞小茆茨。"]'),
('71a00671-bda3-43a1-9e6b-3a3e11edebfc','農舍','陸游','宋','宋诗','song-poetry','','[]','農舍雖云苦，君恩詎可忘。',48,'全唐诗/poet.song.131000.json','["農舍雖云苦，君恩詎可忘。", "繭稠初滿簇，麥熟已登場。", "渺渺開村路，登登築野塘。", "但須時雨足，擊壤詠時康。"]'),
('23ac55d5-f972-4ad6-913a-ced211304a94','四月晦日小雨','陸游','宋','宋诗','song-poetry','','[]','霏霏亂點暗朝光，蓛蓛奇聲度野塘。',64,'全唐诗/poet.song.131000.json','["霏霏亂點暗朝光，蓛蓛奇聲度野塘。", "一浦未輸新漲緑，四郊聊壓旱塵黄。", "風生團扇清無暑，衣覆熏籠潤有香。", "竹屋茆簷得奇趣，不須殿閣詠微涼。"]'),
('56c01545-4211-406f-85b6-ac8963470839','泛舟過吉澤','陸游','宋','宋诗','song-poetry','','[]','蕭蕭菰蒲如荻林，五月已覺秋意深。',64,'全唐诗/poet.song.131000.json','["蕭蕭菰蒲如荻林，五月已覺秋意深。", "烟波滅沒有漁艇，浦溆飛鳴多水禽。", "稽山出雲極奇變，陸子岸幘方微吟。", "一聲菱唱起何許，洗盡萬里功名心。"]'),
('59c2b23a-8916-45ca-9539-d31cc7cad02d','書嘆','陸游','宋','宋诗','song-poetry','','[]','高廟衣冠月出遊，中原父老泪交流。',64,'全唐诗/poet.song.131000.json','["高廟衣冠月出遊，中原父老泪交流。", "諸公誰効回天力，散吏空懷恤緯憂。", "雨細漁庵晨舉網，月明耕隴夜驅牛。", "神州克復知何日，北望飛蓬萬里秋。"]'),
('fbadc580-f316-4f50-9ff0-4d9463f98d62','五月得雨稻苗盡立','陸游','宋','宋诗','song-poetry','','[]','城郭迎龍鼓吹喧，甘膏三夕慰黎元。',64,'全唐诗/poet.song.131000.json','["城郭迎龍鼓吹喧，甘膏三夕慰黎元。", "草荒常日經行路，水到前村舊漲痕。", "黄犢盡耕稀曠土，緑苗無際接旁村。", "家家足食山無盜，安枕何勞夜閉門。"]'),
('6bc5dccc-7961-4aed-891d-6db998bccb7b','薄醉遣懷','陸游','宋','宋诗','song-poetry','','[]','跼蹐蝸廬迮，蕭條鶴髮新。',48,'全唐诗/poet.song.131000.json','["跼蹐蝸廬迮，蕭條鶴髮新。", "途窮貧入夢，身老病欺人。", "带索忘三組，羮藜抵八珍。", "蓬窗一杯酒，自覺膽輪囷。"]'),
('ef2176d1-4547-45e0-8fc7-aaef70306952','五月十一日夜坐達旦','陸游','宋','宋诗','song-poetry','','[]','莫笑耽書不計年，寒儒業定幾生前。',64,'全唐诗/poet.song.131000.json','["莫笑耽書不計年，寒儒業定幾生前。", "讀經今日韋編絕，作賦當時鐵硯穿。", "公路晚悲身至此，令威歸嘆冢纍然。", "三更聽雨蓬窗底，又作鰥魚夜不眠。"]'),
('301d28f4-c6db-471a-8cbd-14fac24a7e23','題陽關圖','陸游','宋','宋诗','song-poetry','','[]','誰畫陽關贈別詩，斷腸如在渭橋時。',64,'全唐诗/poet.song.131000.json','["誰畫陽關贈別詩，斷腸如在渭橋時。", "荒城孤驛夢千里，遠水斜陽天四垂。", "青史功名常蹭蹬，白頭襟抱足乖離。", "山河未復胡塵暗，一寸孤愁只自知。"]'),
('acaa2abd-8a43-4ea2-b9c3-554dd3e2f958','新暑書事','陸游','宋','宋诗','song-poetry','','[]','城中五月汗霑衣，吾愛吾廬喜氣微。',64,'全唐诗/poet.song.131000.json','["城中五月汗霑衣，吾愛吾廬喜氣微。", "珍簟含風來遠餉，輕羅疊雪出鳴機。", "艾人當戶佳時過，筒黍堆盤舊俗非。", "漫欲題詩還懶去，老來百事與心違。"]'),
('01f60651-28d1-46d6-83bf-ae1ec0cef8d8','時雨','陸游','宋','宋诗','song-poetry','','[]','時雨及芒種，四野皆插秧。',96,'全唐诗/poet.song.131000.json','["時雨及芒種，四野皆插秧。", "家家麥飯美，處處菱歌長。", "老我成惰農，永日付竹床。", "衰髮短不櫛，愛此一雨凉。", "庭木集奇聲，架藤發幽香。", "鶯衣溼不去，勸我持一觴。", "即今幸無事，際海皆農桑。", "野老固不窮，擊壤歌虞唐。"]'),
('bc84516d-f89b-4c50-a79b-5045cb58c248','示客','陸游','宋','宋诗','song-poetry','','[]','桑柘成陰百草香，繅車聲裏午風凉。',32,'全唐诗/poet.song.131000.json','["桑柘成陰百草香，繅車聲裏午風凉。", "客來莫說人間事，且共山林夏日長。"]'),
('e8184829-3037-4cb9-a4a1-0818d0bda1fe','南堂默坐','陸游','宋','宋诗','song-poetry','','[]','日日樹頭鵯鵊鳴，夜夜溪邊姑惡聲。',64,'全唐诗/poet.song.131000.json','["日日樹頭鵯鵊鳴，夜夜溪邊姑惡聲。", "堂中老子獨無語，寂然似可終吾生。", "大鵬一舉九萬程，下視海內徒營營。", "秋蟲春鳥非我類，何至伴渠鳴不平。"]'),
('f41a8ad5-3527-43a3-bccf-2ff3914d5dc2','夏日','陸游','宋','宋诗','song-poetry','','[]','燕子生雛梅子黄，斷雲殘雨過林塘。',64,'全唐诗/poet.song.131000.json','["燕子生雛梅子黄，斷雲殘雨過林塘。", "孤舟正作笭箵夢，九陌難隨褦襶忙。", "團扇興來閑弄筆，寒泉漱罷獨焚香。", "太平處處熏風好，不獨宮中愛日長。"]'),
('a9635fb7-281b-42de-8e22-a41c066dbdf0','小酌','陸游','宋','宋诗','song-poetry','','[]','白髮蕭然海上村，猶能草草置清樽。',32,'全唐诗/poet.song.131000.json','["白髮蕭然海上村，猶能草草置清樽。", "今年項里楊梅熟，綠李來禽不足言。"]'),
('93243e74-b605-458a-a88a-2988e3a7039d','夏夜二首  其一','陸游','宋','宋诗','song-poetry','','[]','露溼芙蕖冷，月明薝蔔香。',48,'全唐诗/poet.song.131000.json','["露溼芙蕖冷，月明薝蔔香。", "殘醉吹欲無，颼颼髮根凉。", "豈惟棄世事，形影亦相忘。", "空憶南山下，新秋射虎場。"]'),
('14b94969-6a7f-4d41-aff9-1710d051e2c9','夏夜二首  其二','陸游','宋','宋诗','song-poetry','','[]','我昔在南鄭，夜過東駱谷。',48,'全唐诗/poet.song.131000.json','["我昔在南鄭，夜過東駱谷。", "平川月如霜，萬馬皆露宿。", "思從六月師，關輔談笑復。", "那知二十年，秋風枯苜蓿。"]'),
('35e4a9a6-471b-468f-be05-3c5878af5cee','看鏡二首  其一','陸游','宋','宋诗','song-poetry','','[]','凋盡朱顔白盡頭，神仙富貴兩悠悠。',32,'全唐诗/poet.song.131000.json','["凋盡朱顔白盡頭，神仙富貴兩悠悠。", "胡塵遮斷陽關路，空聽琵琶奏石州。"]'),
('2deac8d7-8950-4305-8156-7ca0a30ce125','看鏡二首  其二','陸游','宋','宋诗','song-poetry','','[]','七十衰翁卧故山，鏡中無復舊朱顔。',32,'全唐诗/poet.song.131000.json','["七十衰翁卧故山，鏡中無復舊朱顔。", "一聯輕甲流塵積，不爲君王戍玉關。"]'),
('88eadf4b-a772-41b0-8c67-9119b49852dc','明妃曲','陸游','宋','宋诗','song-poetry','','[]','漢家和親成故事，萬里風塵妾何罪。',96,'全唐诗/poet.song.131000.json','["漢家和親成故事，萬里風塵妾何罪。", "掖庭終有一人行，敢道君王棄憔悴。", "雙駝駕車夷樂悲，公卿誰悟和戎非。", "蒲桃宮中顔色慘，雞鹿塞外行人稀。", "沙磧茫茫天四圍，一片雲生雪即飛。", "太古以來無寸草，借問春從何處歸。"]'),
('e0a2a419-bc65-4520-8722-e7dcfcaf76a9','思遠遊','陸游','宋','宋诗','song-poetry','','[]','我志日已衰，詩亦無傑句。',72,'全唐诗/poet.song.131000.json','["我志日已衰，詩亦無傑句。", "正如隨翅鶴，悵望遼海路。", "雖云須藥物，幸未迫霜露。", "裂裳裹兩踵，此詩亦已屢。", "嵯峨青城雲，慘淡嶓冢樹。", "秋風吹短裘，萬里入芒屨。"]'),
('289b0c2d-9fee-4d4c-980d-0bf4b4794d4e','太息','陸游','宋','宋诗','song-poetry','','[]','太息重太息，吾生誰與歸。',48,'全唐诗/poet.song.131000.json','["太息重太息，吾生誰與歸。", "那知暮景迫，但覺故人稀。", "避禍歸猶困，憂讒默亦非。", "今年貧徹底，擬賣舊漁磯。"]'),
('8c3cecab-b83e-41b5-a670-e7a314e2fd45','六月二十六日夜夢赴季長招飲','陸游','宋','宋诗','song-poetry','','[]','少城駿馬逐春風，二十年間萬事空。',64,'全唐诗/poet.song.131000.json','["少城駿馬逐春風，二十年間萬事空。", "清夢都忘雙鬢改，繡筵還喜一尊同。", "烏巾掩冉簪花重，羯鼓敲鏗列炬紅。", "安得此歡真入眼，碧油幢擁主人翁。"]'),
('8293bfef-b04e-4c83-8a43-8e42647a56d1','夜分不寐起坐園中至旦','陸游','宋','宋诗','song-poetry','','[]','凉氣蘇衰疾，幽情入杖藜。',48,'全唐诗/poet.song.131000.json','["凉氣蘇衰疾，幽情入杖藜。", "月驚孤鵲起，天带眾星西。", "松菊今彭澤，山川古會稽。", "清吟殊未愜，喔喔已晨雞。"]'),
('e28bb474-ec61-49f3-9eda-eaefb52fd38c','露坐','陸游','宋','宋诗','song-poetry','','[]','此手乃可憐，經月不把酒。',96,'全唐诗/poet.song.131000.json','["此手乃可憐，經月不把酒。", "著書又苦晚，何以圖不朽。", "空庭坐三更，磊落垂北斗。", "向來歷關河，萬里空回首。", "豈知三十年，竟作越中叟。", "後生雖滿眼，非復舊交友。", "形體迫衰謝，妻子亦何有。", "悵望懷古人，吞聲死農畝。"]'),
('120bf676-98b0-4fa5-b928-53d2a0b57918','晨起','陸游','宋','宋诗','song-poetry','','[]','心安已到無心處，病去渾如未病前。',32,'全唐诗/poet.song.131000.json','["心安已到無心處，病去渾如未病前。", "晨起更知秋色好，一庭風露聽鳴蟬。"]'),
('47057023-ccb6-4c0d-873a-1e0658a2a957','散步東村','陸游','宋','宋诗','song-poetry','','[]','偶從北崦繚東崗，曳杖行歌踏夕陽。',64,'全唐诗/poet.song.131000.json','["偶從北崦繚東崗，曳杖行歌踏夕陽。", "一徑入雲多鹿迹，數家臨水共漁梁。", "野風蕭瑟知秋早，社酒淋漓喜歲穰。", "鄰曲不須憐老憊，尚能尋句答年光。"]'),
('94a08b91-41ac-41b9-80c4-53deaf8dd3be','早秋四首  其一','陸游','宋','宋诗','song-poetry','','[]','凉颸淅淅撼庭柯，微雨蕭蕭集浦荷。',64,'全唐诗/poet.song.131000.json','["凉颸淅淅撼庭柯，微雨蕭蕭集浦荷。", "草閣簷虛覺山近，蓬窗地迮得香多。", "謀身自拙窮無鬼，閉戶長閑睡有魔。", "臺省諸公盛冠劍，固應老子得婆娑。"]'),
('a2f87486-c64e-4653-a570-863faa0200d6','早秋四首  其二','陸游','宋','宋诗','song-poetry','','[]','秋入房櫳夜漸長，紗厨笛簟怯新凉。',64,'全唐诗/poet.song.131000.json','["秋入房櫳夜漸長，紗厨笛簟怯新凉。", "螢光得意穿簾隙，桐葉知時拂井床。", "世事本來誰得鹿，人生何處不亡羊。", "燈前笑向吾兒說，又過銅匜半篆香。"]'),
('757cc873-6e73-4ff2-aed3-4db472479251','早秋四首  其三','陸游','宋','宋诗','song-poetry','','[]','落魄巴江號放翁，斯名歲晚亦成空。',64,'全唐诗/poet.song.131000.json','["落魄巴江號放翁，斯名歲晚亦成空。", "酒醒遥夜孤舟雨，睡美清秋一榻風。", "駭浪千重無死地，神丹九轉有新功。", "雲端不遇飛仙過，誰顧幽人寂寞中。"]'),
('95bee03b-5a58-4b02-b910-60e8b67eacdb','早秋四首  其四','陸游','宋','宋诗','song-poetry','','[]','貂裘塵土憶東周，瓜隴風霜隱故侯。',64,'全唐诗/poet.song.131000.json','["貂裘塵土憶東周，瓜隴風霜隱故侯。", "懶似老雞頻失旦，衰如蠹葉早知秋。", "壺觴非復平生友，歲月空添客子愁。", "病起筆端猶健在，未妨揮灑賦登樓。"]'),
('a5d8cbbe-e1f9-4a43-88ea-0f1ba32f7834','七月二十一日午睡夢泛江風濤甚壯覺而有賦','陸游','宋','宋诗','song-poetry','','[]','夢中不記適何邦，風飽蒲颿入大江。',32,'全唐诗/poet.song.131000.json','["夢中不記適何邦，風飽蒲颿入大江。", "久矣眼中無此快，蹴天雪浪濺船窗。"]'),
('0365a7af-2801-4f04-8ebc-5edc0c94a454','幽居戲贈鄰曲','陸游','宋','宋诗','song-poetry','','[]','暮年遠屏天所借，落佩倒冠如得謝。',128,'全唐诗/poet.song.131000.json','["暮年遠屏天所借，落佩倒冠如得謝。", "雖無壺酒助歌呼，幸有蠹書供枕藉。", "市聲不聞耳差靜，車轍掃空身轉暇。", "雨慳葵葉未吐甲，露重榴房初坼罅。", "深紅菱角密覆水，爛紫蒲桃重垂架。", "直令掩關避世俗，未害煎茶喚鄰舍。", "蕭蕭雞犬衡門晚，寂寂燈火幽窗夜。", "勸君切勿縱高談，性命如絲不禁嚇。"]'),
('afa3fb83-31aa-4171-9c68-692d4f3a13ff','遣興二首  其一','陸游','宋','宋诗','song-poetry','','[]','失馬真成福，移山未必愚。',48,'全唐诗/poet.song.131000.json','["失馬真成福，移山未必愚。", "故園三徑廢，餘俸一錢無。", "望道心常渴，觀書眼欲枯。", "宦遊歸自好，不必爲蓴鱸。"]'),
('78605540-529c-4311-ae45-4f8a875f1d39','遣興二首  其二','陸游','宋','宋诗','song-poetry','','[]','療饑惟恃粥，動步已須人。',48,'全唐诗/poet.song.131000.json','["療饑惟恃粥，動步已須人。", "欲午猶支枕，經旬不過鄰。", "鵲棲寒自穩，鷗沒遠難馴。", "莫笑謀身拙，黄冠學季真。"]'),
('be60de72-fdc6-42be-b1bc-f1870b4b68ed','步至湖上寓小舟還舍五首  其一','陸游','宋','宋诗','song-poetry','','[]','凄凉懷古地，慘澹暮秋天。',48,'全唐诗/poet.song.131000.json','["凄凉懷古地，慘澹暮秋天。", "紅樹秦馳道，青山禹廟壖。", "湖風飄斷角，墟日起孤烟。", "老恨功名晚，無人共著鞭。"]'),
('82567162-08fb-410c-a69d-a1f47255e890','步至湖上寓小舟還舍五首  其二','陸游','宋','宋诗','song-poetry','','[]','山居苦無事，携稚出門行。',48,'全唐诗/poet.song.131000.json','["山居苦無事，携稚出門行。", "酒賤逢人醉，農閑到處耕。", "巷牛聽晚笛，池鶩唼枯萍。", "東望生秋興，樓臺壓繚城。"]'),
('d6dbb4ed-acb5-41fd-bad9-2f26784a5fac','步至湖上寓小舟還舍五首  其三','陸游','宋','宋诗','song-poetry','','[]','病墮支離境，閑尋漫浪遊。',48,'全唐诗/poet.song.131000.json','["病墮支離境，閑尋漫浪遊。", "湖平天鏡曉，山峭石帆秋。", "賒酒家家許，看花處處留。", "歸途倦扶杖，却上釣魚舟。"]'),
('a122ca61-5d24-4ed4-94e7-88e46786200c','步至湖上寓小舟還舍五首  其四','陸游','宋','宋诗','song-poetry','','[]','萬壑爭流地，身閑得縱觀。',48,'全唐诗/poet.song.131000.json','["萬壑爭流地，身閑得縱觀。", "未能容蟹舍，聊得寄漁竿。", "遠浦樵風急，空山窆石寒。", "踟躕不知晚，磔磔有歸翰。"]'),
('60264d95-835e-4d76-84b1-6afba9bc828c','步至湖上寓小舟還舍五首  其五','陸游','宋','宋诗','song-poetry','','[]','細浪隨摇檝，新凉入岸巾。',48,'全唐诗/poet.song.131000.json','["細浪隨摇檝，新凉入岸巾。", "斷行初到雁，空擔暮歸人。", "漫道貧非病，誰知懶是真。", "疏鐘起詩思，迢遞度烟津。"]'),
('cc507fb4-6f0c-4b20-93c2-8ee3193eb890','送王仲言倅泰州絕句二首  其一','陸游','宋','宋诗','song-poetry','','[]','汝陰太史萬籤藏，酸棗先生六世芳。',32,'全唐诗/poet.song.131000.json','["汝陰太史萬籤藏，酸棗先生六世芳。", "豹尾屬車留不住，却尋陳迹海陵倉。"]'),
('46c8a879-9050-4fd9-9d88-2a15247f69d0','送王仲言倅泰州絕句二首  其二','陸游','宋','宋诗','song-poetry','','[]','紫薇傑作傳千載，物色分留待下車。',32,'全唐诗/poet.song.131000.json','["紫薇傑作傳千載，物色分留待下車。", "老病難陪曳裾客，因來時寄一行書。"]'),
('5b25a9e0-d516-4e5f-a3f2-1c5665a79315','醉中作','陸游','宋','宋诗','song-poetry','','[]','舴艋爲家雲作友，流年盡付樽中酒。',64,'全唐诗/poet.song.131000.json','["舴艋爲家雲作友，流年盡付樽中酒。", "清嘯穿林鸞鳳吟，草書落紙龍蛇走。", "人間無復王景略，千載風雲常寂寞。", "安得熊羆十萬師，蹴踏幽并洗河洛。"]'),
('c702b611-b666-420d-ba0d-1720a0971624','秋夜書感','陸游','宋','宋诗','song-poetry','','[]','闌干斗插酉，慘淡河絡角。',96,'全唐诗/poet.song.131000.json','["闌干斗插酉，慘淡河絡角。", "開歲財屬爾，草木忽摇落。", "平生歷畏塗，赤手犯蛟鰐。", "幸收垂盡日，歸卧一丘壑。", "鄉鄰怪此老，骯髒尚如昨。", "使無湖海寬，朝市何處著。", "諸公方衮衮，一士要諤諤。", "謀食古所羞，終身美藜藿。"]'),
('38bb7991-9396-4f62-960a-99f70067ab95','八月三日驟凉有感','陸游','宋','宋诗','song-poetry','','[]','殘暑侵人畏汗霑，清秋乍見月纖纖。',64,'全唐诗/poet.song.131000.json','["殘暑侵人畏汗霑，清秋乍見月纖纖。", "自燒熟火添香獸，旋把寒泉注硯蟾。", "佳客誤占螢入戶，遠書空喜鵲鳴簷。", "悠然獨對清燈卧，誰念柴門老病兼。"]'),
('b7538681-ea19-4e56-9952-49b1497f0984','南堂與兒輩夜坐','陸游','宋','宋诗','song-poetry','','[]','殘暑初歸肺病蘇，胡床清夜集前除。',64,'全唐诗/poet.song.131000.json','["殘暑初歸肺病蘇，胡床清夜集前除。", "風高木葉危將脫，月上天河淡欲無。", "鵲影繞枝棲未穩，荷盤擎露重相扶。", "凄然又起流年感，兩鬢如蓬日夜枯。"]'),
('cb8e7d16-5c34-44da-a4f8-22a792fa5c11','泛舟至魯墟','陸游','宋','宋诗','song-poetry','','[]','南蕩東陂弄夕霏，葛巾鶴氅試秋衣。',64,'全唐诗/poet.song.131000.json','["南蕩東陂弄夕霏，葛巾鶴氅試秋衣。", "纖纖新月迎船出，兩兩珍禽背水飛。", "病思漸蘇開酒戒，宦情已絕謝塵鞿。", "郊居是處堪乘興，不怕城笳苦喚歸。"]'),
('131032df-79b9-4f78-bdeb-5b55e451ac4f','園蔬薦村酒戲作','陸游','宋','宋诗','song-poetry','','[]','身入今年老，囊從早歲空。',48,'全唐诗/poet.song.131000.json','["身入今年老，囊從早歲空。", "元無擊鮮事，常作啜醨翁。", "菹有秋菰白，羹惟野莧紅。", "何人萬錢筯，一笑對西風。"]'),
('1159af92-3ecc-4a36-94d9-5e1057245c5e','雨夕排悶二首  其一','陸游','宋','宋诗','song-poetry','','[]','買牛耕剡曲，舉世笑迂疏。',48,'全唐诗/poet.song.131000.json','["買牛耕剡曲，舉世笑迂疏。", "流落愈憂國，衰殘猶讀書。", "滔滔安稅駕，耿耿獨愁余。", "破屋秋多雨，情懷用底攄。"]'),
('bb828a20-b8d5-4808-b942-e4cc1b24ac1e','雨夕排悶二首  其二','陸游','宋','宋诗','song-poetry','','[]','烟雨暗郊墟，頹然卧草廬。',48,'全唐诗/poet.song.131000.json','["烟雨暗郊墟，頹然卧草廬。", "蟲喧夢回枕，燈伴讀殘書。", "短褐頻關念，荒畦久廢鋤。", "更堪湖水漲，累日食無魚。"]'),
('43b08de2-1cb5-400b-bfd9-ac5bbc14c598','雨中作','陸游','宋','宋诗','song-poetry','','[]','社甕醅香燕子歸，陰風吹雨暗郊扉。',64,'全唐诗/poet.song.131000.json','["社甕醅香燕子歸，陰風吹雨暗郊扉。", "疏溝園叟方携鍤，采藥蠻童已溼衣。", "山雉尾垂衝靄去，水雞翅重蹋波飛。", "憑闌一笑君知否，肺渴秋來勢漸微。"]'),
('16e5cfd5-9a0a-4e4c-88ff-440c576eb1a7','讀易','陸游','宋','宋诗','song-poetry','','[]','揖遜干戈兩不知，巢居穴處各熙熙。',32,'全唐诗/poet.song.131000.json','["揖遜干戈兩不知，巢居穴處各熙熙。", "無端鑿破乾坤秘，禍始羲皇一畫時。"]'),
('13da5bf5-d18c-4a79-b208-2bbb2505bcea','郊行夜歸有感','陸游','宋','宋诗','song-poetry','','[]','小市歌呼散，幽人悄獨行。',48,'全唐诗/poet.song.131000.json','["小市歌呼散，幽人悄獨行。", "斷鴻沙際冷，重露草根明。", "信古癡常絕，酬恩命本輕。", "還家掩屏卧，衰涕浩縱橫。"]'),
('1e599480-4009-43db-9c89-7152e42235fd','醉歌','陸游','宋','宋诗','song-poetry','','[]','三十六策醉特奇，竹林諸公端可師。',96,'全唐诗/poet.song.131000.json','["三十六策醉特奇，竹林諸公端可師。", "秋風蕭蕭吹鬢絲，蟹螯正可左手持。", "醉倒村路兒扶歸，瞠兒不識問是誰。", "浩歌起舞夜何其，北斗磊落明河移。", "貴人惜醉渠自癡，黄金絡馬誇市兒。", "一朝禍來莫支持，新州如山不可移。"]'),
('dd707604-8b5a-45f4-a8d5-4a63937a74b7','買酒','陸游','宋','宋诗','song-poetry','','[]','放翁病起不禁愁，買酒看山自獻酬。',32,'全唐诗/poet.song.131000.json','["放翁病起不禁愁，買酒看山自獻酬。", "八月吳中未摇落，誰令衰鬢早知秋。"]'),
('2fca9d62-0300-433e-b357-62aeb2a8d29c','秋雨嘆','陸游','宋','宋诗','song-poetry','','[]','淙淙雨聲瀉高秋，稻粱浸瀾雨不休。',128,'全唐诗/poet.song.131000.json','["淙淙雨聲瀉高秋，稻粱浸瀾雨不休。", "志士仁人萬行泪，孤臣孽子無窮憂。", "一身窮困未暇恤，如此無事理有不。", "聖言古訓舉不驗，簡編可用汗馬牛。", "嗚呼有粟吾得食，夜睡何時得安席。", "我生猶及宣和年，建炎以來身所歷。", "高皇一言感天地，盜賊千群掃無迹。", "疽囊雖慘固可醫，誰爲聖代施鍼石。"]'),
('3de3468b-fc3a-4f87-ae9a-d6048cdfc9f8','憂國','陸游','宋','宋诗','song-poetry','','[]','恩許還山已六年，誓憑耕稼餞華顛。',64,'全唐诗/poet.song.131000.json','["恩許還山已六年，誓憑耕稼餞華顛。", "養心雖若冰將釋，憂國猶虞火未然。", "議論孰能忘忌諱，人材正要越拘攣。", "群公亦采芻蕘否，貞觀開元在目前。"]'),
('cb3f36f4-0ecb-43cf-88da-ee582bdd2025','夜意','陸游','宋','宋诗','song-poetry','','[]','居家元是客，在俗亦如僧。',48,'全唐诗/poet.song.131000.json','["居家元是客，在俗亦如僧。", "點滴簷間雨，青熒帳外燈。", "壯心終蹭蹬，去日捷飛騰。", "不及寒沙雁，來時下杜陵。"]'),
('853553ca-321a-473b-bff5-fcd4697e809f','大風雨中作','陸游','宋','宋诗','song-poetry','','[]','風如拔山怒，雨如决河傾。',96,'全唐诗/poet.song.131000.json','["風如拔山怒，雨如决河傾。", "屋漏不可支，窗戶俱有聲。", "烏鳶墮地死，雞犬噤不鳴。", "老病無避處，起坐徒嘆驚。", "三年稼如雲，一旦敗垂成。", "夫豈或使之，憂乃及躬耕。", "鄰曲無人色，婦子泪縱橫。", "且抽架上書，洪範推五行。"]'),
('5b738e47-4b51-4cd9-98bc-e502c8b45e68','題齋壁二首  其一','陸游','宋','宋诗','song-poetry','','[]','閉門無事不勝閑，心境超然一室寬。',64,'全唐诗/poet.song.131000.json','["閉門無事不勝閑，心境超然一室寬。", "香岫火深生細靄，硯池風過起微瀾。", "睡餘但欲依書几，坐久還思弄釣竿。", "擾擾平生成底事，鏡湖歸隱老黄冠。"]'),
('e8a269e5-4584-4455-b8fc-b1d8a68f66ca','題齋壁二首  其二','陸游','宋','宋诗','song-poetry','','[]','手斸雲根結草廬，平生心事滿無餘。',64,'全唐诗/poet.song.131000.json','["手斸雲根結草廬，平生心事滿無餘。", "二升菰米晨炊飯，一碗松燈夜讀書。", "天理直須閑處看，人謀常向巧中疏。", "烟波有趣君知否，裂網伸鈎也得魚。"]'),
('104a21dc-7c80-414a-8c9a-45138848af4b','窮途','陸游','宋','宋诗','song-poetry','','[]','窮途多感慨，老境少知聞。',48,'全唐诗/poet.song.131000.json','["窮途多感慨，老境少知聞。", "酒裏閑消日，書中自策勳。", "全軀希碌碌，掃軌厭紛紛。", "每愧吾鄉老，頭童念致君。"]'),
('3d350ee9-d9b5-4b48-9519-b6ce4789b4b7','貧病','陸游','宋','宋诗','song-poetry','','[]','行年七十尚携鉏，貧悴還如白紵初。',64,'全唐诗/poet.song.131000.json','["行年七十尚携鉏，貧悴還如白紵初。", "好事鄰僧勤送米，過門谿友强留魚。", "客來旋過牆頭酒，睡起閑抽架上書。", "要信榮枯元不動，胸中浩浩著空虛。"]'),
('2c8bd7db-b264-46fe-8d1f-1c612bac0124','秋晚四首  其一','陸游','宋','宋诗','song-poetry','','[]','舂粳入甑香炊玉，壓酒鳴槽滴碎珠。',32,'全唐诗/poet.song.131000.json','["舂粳入甑香炊玉，壓酒鳴槽滴碎珠。", "甲第朱門漫豪侈，山家風味定應無。"]'),
('e100ecb7-f978-4548-802d-d58d65721d19','秋晚四首  其二','陸游','宋','宋诗','song-poetry','','[]','新筑場如鏡面平，家家歡喜賀秋成。',32,'全唐诗/poet.song.131000.json','["新筑場如鏡面平，家家歡喜賀秋成。", "老來懶惰慚丁壯，美睡中聞打稻聲。"]'),
('9db409f7-6800-4498-8da2-9f4dfb3df7a8','秋晚四首  其三','陸游','宋','宋诗','song-poetry','','[]','秋菰出水白於玉，寒薺繞牆甘若飴。',32,'全唐诗/poet.song.131000.json','["秋菰出水白於玉，寒薺繞牆甘若飴。", "正是長齋豈不可，凜然大節固難移。"]'),
('9618dd7d-7ac9-44c1-b8fc-f6290d706789','秋晚四首  其四','陸游','宋','宋诗','song-poetry','','[]','竹竿坡面老別駕，飯顆山頭瘦拾遺。',32,'全唐诗/poet.song.131000.json','["竹竿坡面老別駕，飯顆山頭瘦拾遺。", "自古詩人例如此，放翁窮死未須悲。"]'),
('4b69c66b-960c-4fe1-b044-46d6de8728de','山村書所見二首  其一','陸游','宋','宋诗','song-poetry','','[]','老枳垂藤晝常黑，雛鷹聲作嬰兒啼。',32,'全唐诗/poet.song.131000.json','["老枳垂藤晝常黑，雛鷹聲作嬰兒啼。", "伐薪歸來遇急雨，石路下山如踏梯。"]'),
('39ae40d0-8bcf-40d9-961b-ca31e274e828','山村書所見二首  其二','陸游','宋','宋诗','song-poetry','','[]','荒坡茫茫牧牛童，扳角上背捷如風。',32,'全唐诗/poet.song.131000.json','["荒坡茫茫牧牛童，扳角上背捷如風。", "腰間一枝搢枯竹，橫吹短笛過村東。"]'),
('881fcbf9-628c-47c0-a8f3-6c45379098d8','三年前與兒輩步過東涇小嶺得勝處可營別墅貧不能成偶復至其地悵然有感','陸游','宋','宋诗','song-poetry','','[]','前年度嶺踏斜陽，曾卜松陰置草堂。',64,'全唐诗/poet.song.131000.json','["前年度嶺踏斜陽，曾卜松陰置草堂。", "只倚氣吞雲夢澤，竟無錢買雪堆莊。", "烟脂菱角空頻摘，火齊楊梅已再嘗。", "事不如心居十九，往來常羨捕魚郎。"]'),
('537a57ae-69d9-4855-a2f0-b505941e3a6b','園中秋夕','陸游','宋','宋诗','song-poetry','','[]','季秋哉生明，風露正凄冷。',96,'全唐诗/poet.song.131000.json','["季秋哉生明，風露正凄冷。", "放翁澹無事，樂此清夜永。", "饑鷹棲不穩，勁翅起東嶺。", "湖邊千樹柳，何處寄幽影。", "人生寓宇內，俯仰一炊頃。", "此心無愧負，簞食均五鼎。", "許身輩稷卨，終亦輸箕潁。", "天風倘可乘，采蓮登玉井。"]'),
('92aa5f0c-686d-41c1-a9be-7a33651d01d1','秋晴每至園中輒抵暮戲示兒子','陸游','宋','宋诗','song-poetry','','[]','老翁七十如童兒，置書不觀事遊嬉。',96,'全唐诗/poet.song.131000.json','["老翁七十如童兒，置書不觀事遊嬉。", "園中壘瓦强名塔，庭下埋盆聊作池。", "青蒲紅蓼共掩映，病棕瘦竹相扶持。", "衰頹已作老驥卧，來往尚如黄犢馳。", "但知身存百無害，莫問老健能幾時。", "汝勤挾筴乃堪笑，且共飯豆羹秋葵。"]'),
('2edc0058-cedc-439b-af38-88012fc2dbcc','醉睡初覺偶作','陸游','宋','宋诗','song-poetry','','[]','小圃醒還醉，幽窗起復眠。',48,'全唐诗/poet.song.131000.json','["小圃醒還醉，幽窗起復眠。", "虛明炷香地，清潤斸花天。", "老去才雖盡，窮來志益堅。", "阿瞞那可語，平日笑橋玄。"]'),
('3219622e-a3ce-4f90-bafb-769aa4aece36','汪茂南提舉挽詞二首  其一','陸游','宋','宋诗','song-poetry','','[]','學已三冬富，書猶萬卷藏。',48,'全唐诗/poet.song.131000.json','["學已三冬富，書猶萬卷藏。", "名場雖蹭蹬，朝論極揄揚。", "小試襦袴詠，遂辭鵷鷺行。", "秋風九原路，挽鐸倍凄凉。"]'),
('28b85a21-3e7f-4b50-8b4d-eb9413163aee','汪茂南提舉挽詞二首  其二','陸游','宋','宋诗','song-poetry','','[]','往者紹興末，江淮聞戰鼙。',48,'全唐诗/poet.song.131000.json','["往者紹興末，江淮聞戰鼙。", "上流煩舊德，下客辱深知。", "陳迹成今古，追懷每涕櫂。", "郎君雖不識，撫事亦增悲。"]'),
('6668c3d6-8926-4710-bf88-cf324bcc995e','謝徐居厚汪叔潜携酒見訪','陸游','宋','宋诗','song-poetry','','[]','我雖生亂離，猶及見前輩。',144,'全唐诗/poet.song.131000.json','["我雖生亂離，猶及見前輩。", "衣冠方南奔，文獻往往在。", "幸供掃灑役，迹忝諸生內。", "話言猶在耳，造次敢不佩。", "殘年趨死近，孤學與時背。", "妄出更何求，終老事耕耒。", "史君稽古學，力大障橫潰。", "廣文亦偉士，名字震當代。", "同舟肯過我，凜與前修配。", "憂時抱忠鯁，論事極慷慨。", "嗟予雖益衰，耳目幸未廢。", "何當卜鄰牆，早暮聆謦欬。"]'),
('712ef252-106c-4d1a-aad7-4927ccca4832','喜鄭唐老相過','陸游','宋','宋诗','song-poetry','','[]','鄭子有書癖，對書百事忘。',144,'全唐诗/poet.song.131000.json','["鄭子有書癖，對書百事忘。", "頭亂不暇櫛，炙冷不暇嘗。", "持此金石心，力求古文章。", "吟哦屈宋作，蚤夜聲琅琅。", "方揮却日戈，耻窺及肩牆。", "不見今六年，所得非復常。", "扁舟夜過我，劇論神激揚。", "徐出二三篇，稊米於太倉。", "已足起衰懦，黑絲生鬢霜。", "使得盡見之，殆可鍼膏肓。", "願子繼自今，勿惜傾錦囊。", "因來數爲寄，歲晚慰所望。"]'),
('90c0c715-53f6-49bf-82ba-b461961caa9a','秋晚散步門外','陸游','宋','宋诗','song-poetry','','[]','栗里歸栽菊，青門隱賣瓜。',48,'全唐诗/poet.song.131000.json','["栗里歸栽菊，青門隱賣瓜。", "羸軀病天色，衰鬢怯年華。", "野曠烏聲樂，溪清雁影斜。", "門前秋潦退，也擬筑堤沙。"]'),
('aa63adae-cf2c-45ba-a014-3180640acd9a','寄徐秀才斯遠并呈莊賢良器之','陸游','宋','宋诗','song-poetry','','[]','徐子作別十年餘，無人可寄一紙書。',96,'全唐诗/poet.song.131000.json','["徐子作別十年餘，無人可寄一紙書。", "閑門美睡畏剝啄，自怪一念常關渠。", "西風蕭蕭吹槁葉，秋光正滿蝸牛廬。", "讀書易倦出無友，撫几惝恍空愁予。", "蜀莊之孫住南郭，亦復迹遠非情疏。", "何時同載過老子，共飯赤米羹青蔬。"]'),
('bd07bcd9-caaa-4dc0-a0cf-7e6ab6e40924','閑中','陸游','宋','宋诗','song-poetry','','[]','閑中高趣傲羲皇，身卧維摩示病床。',64,'全唐诗/poet.song.131000.json','["閑中高趣傲羲皇，身卧維摩示病床。", "活眼硯凹宜墨色，長毫甌小聚茶香。", "門無客至惟風月，案有書存但老莊。", "問我東歸今幾日，坐看庭樹六番黄。"]'),
('bb68cea4-5518-4aae-8781-9db721ec412e','秋霽','陸游','宋','宋诗','song-poetry','','[]','驅除雲霧極知難，敢意天公不作慳。',64,'全唐诗/poet.song.131000.json','["驅除雲霧極知難，敢意天公不作慳。", "汛掃中庭待明月，攀躋危榭望青山。", "取琴理曲茶烟畔，看鶴梳翎竹影間。", "不爲新晴宜著句，擬將幽事破除閑。"]'),
('f6231a6e-f9d5-47de-9ee9-2b848cb4fdd2','晨起','陸游','宋','宋诗','song-poetry','','[]','晨起梳頭拂面絲，行年七十豈前期。',64,'全唐诗/poet.song.131000.json','["晨起梳頭拂面絲，行年七十豈前期。", "此生猶著幾兩屐，長日惟消一局棋。", "空釜生魚忍貧慣，閑門羅雀與秋宜。", "區區名義真當勉，正是先師戒得時。"]'),
('37ab4686-83eb-42db-a969-4d7c200ab49c','箜篌謠二首寄季長少卿  其一','陸游','宋','宋诗','song-poetry','','[]','庭樹非不榮，霜霣萬葉枯。',72,'全唐诗/poet.song.131000.json','["庭樹非不榮，霜霣萬葉枯。", "朋友豈我棄，漸遠勢自疏。", "中夜起太息，發篋覓舊書。", "塵昏蠹蝕損，行缺字欲無。", "一讀色已變，再讀涕泪濡。", "卷書置篋中，寧使飽蠹魚。"]'),
('3452621d-dabb-47b6-8b50-a60a8a2fd663','箜篌謠二首寄季長少卿  其二','陸游','宋','宋诗','song-poetry','','[]','少壯離別時，回顧日月長。',72,'全唐诗/poet.song.131000.json','["少壯離別時，回顧日月長。", "會合終有期，何恨天一方。", "我齒如敗屐，君髮如新霜。", "餘日復幾何，萬里遥相望。", "欲泣老無泪，欲夢不可常。", "寄書何時到，江漢春茫茫。"]'),
('f00fca33-8742-45e1-a707-4ae5259aec76','悶極有作','陸游','宋','宋诗','song-poetry','','[]','貴已不如賤，狂應又勝癡。',48,'全唐诗/poet.song.131000.json','["貴已不如賤，狂應又勝癡。", "新寒壓酒夜，微雨種花時。", "堂下藤成架，門邊枳作籬。", "老人無日課，有興即題詩。"]'),
('5816fbc2-b7a7-4e34-9373-dad059d11dc4','自詠','陸游','宋','宋诗','song-poetry','','[]','常記當年入洛初，華燈百萬擲樗蒲。',64,'全唐诗/poet.song.131000.json','["常記當年入洛初，華燈百萬擲樗蒲。", "平生意薄刀筆吏，投老身爲山澤臞。", "已罷向空書咄咄，尚能擊缶和嗚嗚。", "今朝客至無尋處，正伴園丁斸芋區。"]'),
('103e2962-0830-453d-a273-6e30e0e4d51f','夢范參政','陸游','宋','宋诗','song-poetry','','[]','夢中不知何歲月，長亭慘淡天飛雪。',128,'全唐诗/poet.song.131000.json','["夢中不知何歲月，長亭慘淡天飛雪。", "酒肉如山鼓吹喧，車馬結束有行色。", "我起持公不得語，但道不料今遽別。", "平生故人端有幾，長號頓足泪迸血。", "生存相別尚如此，何况一旦泉壤隔。", "欲懷雞黍病爲重，千里關河阻臨穴。", "速死從公尚何憾，眼中寧復見此傑。", "青燈耿耿山雨寒，援筆詩成心欲裂。"]'),
('e2735a66-f8c5-4f54-8f50-b09b11049df3','乞奉祠未報食且不繼','陸游','宋','宋诗','song-poetry','','[]','富貴常求繫日繩，阨窮却羨棄家僧。',64,'全唐诗/poet.song.131000.json','["富貴常求繫日繩，阨窮却羨棄家僧。", "强顔始覺貧爲害，對鏡方嗟老可憎。", "出戶風霜欺短褐，讀書父子共昏燈。", "聖師夢奠二千載，一卷遺言終可憑。"]'),
('6410e40d-fb14-456b-874f-e27b1620b2e1','山寺','陸游','宋','宋诗','song-poetry','','[]','信步得佳寺，入門吹斷香。',48,'全唐诗/poet.song.131000.json','["信步得佳寺，入門吹斷香。", "林深栗鼠健，屋老瓦松長。", "吊古增凄愴，憑高寄慨慷。", "匆匆興未盡，新月映方塘。"]'),
('896a608d-e762-4175-ba36-ef7f30f36909','太師魏國史公挽歌詞五首  其一','陸游','宋','宋诗','song-poetry','','[]','早擅淵源學，常懷懇款忠。',48,'全唐诗/poet.song.131000.json','["早擅淵源學，常懷懇款忠。", "雲龍際千載，典冊冠三公。", "論諫寧中止，謀謨不苟同。", "此心誰復識，志士泣秋風。"]'),
('7b807a72-6328-439c-aa07-d8ad16a5021d','太師魏國史公挽歌詞五首  其二','陸游','宋','宋诗','song-poetry','','[]','位歷公卿貴，身兼將相榮。',48,'全唐诗/poet.song.131000.json','["位歷公卿貴，身兼將相榮。", "珥貂儀一品，錫带價連城。", "入告推忠厚，躬行本志誠。", "斯民何以報，萬里徧春耕。"]'),
('9cb4669f-1c82-44c4-a5b6-61d73a57727b','太師魏國史公挽歌詞五首  其三','陸游','宋','宋诗','song-poetry','','[]','道德補天石，勛勞夾日龍。',48,'全唐诗/poet.song.131000.json','["道德補天石，勛勞夾日龍。", "犯顔無不盡，造膝略皆從。", "歲貢來戎幣，秋防滅塞烽。", "畫圖麟閣上，猶足折遐衝。"]'),
('7b9a815c-f6c1-44c9-b0d4-292dd30dac39','太師魏國史公挽歌詞五首  其四','陸游','宋','宋诗','song-poetry','','[]','舊弼初收召，惟公力贊揚。',48,'全唐诗/poet.song.131000.json','["舊弼初收召，惟公力贊揚。", "都亭移供帳，全魏徹封疆。", "大度寧猜阻，群言自中傷。", "拳拳虛左意，猶可質穹蒼。"]'),
('a6c5edef-6453-401d-a75e-6ff518ccb7d5','太師魏國史公挽歌詞五首  其五','陸游','宋','宋诗','song-poetry','','[]','壟干勞久戍，大將未班師。',48,'全唐诗/poet.song.131000.json','["壟干勞久戍，大將未班師。", "抗議回天意，忘身爲聖時。", "人心嶮莫測，時事遠難知。", "汗簡方傳信，孤生欲語誰。"]'),
('7113f628-0916-4c02-bcfa-6769bd1326ed','三峽歌九首  其一','陸游','宋','宋诗','song-poetry','','[]','神女廟前秋月明，黄牛峽裏暮猿聲。',32,'全唐诗/poet.song.131000.json','["神女廟前秋月明，黄牛峽裏暮猿聲。", "危途性命不容恤，百丈牽船侵夜行。"]'),
('3e1c1054-0e22-4e4a-a814-76130603fba2','三峽歌九首  其二','陸游','宋','宋诗','song-poetry','','[]','不怕灘如竹節稠，新灘已過可無憂。',32,'全唐诗/poet.song.131000.json','["不怕灘如竹節稠，新灘已過可無憂。", "古妝峨峨一尺髻，木盎銀杯邀客舟。"]'),
('af0dedbf-e5a7-4c61-aaf1-0c1cd6bb62f1','三峽歌九首  其三','陸游','宋','宋诗','song-poetry','','[]','十二巫山見九峰，船頭彩翠滿秋空。',32,'全唐诗/poet.song.131000.json','["十二巫山見九峰，船頭彩翠滿秋空。", "朝雲暮雨渾虛語，一夜猿啼明月中。"]'),
('f57b5ba7-efff-429d-82d0-a16e28fd983d','三峽歌九首  其四','陸游','宋','宋诗','song-poetry','','[]','錦繡樓前看賣花，麝香山下摘新茶。',32,'全唐诗/poet.song.131000.json','["錦繡樓前看賣花，麝香山下摘新茶。", "長安卿相多憂畏，老向夔州不用嗟。"]'),
('1a5e7a2a-c88d-4767-979a-4a43545cc4f2','三峽歌九首  其五','陸游','宋','宋诗','song-poetry','','[]','險詐沾沾不愧天，交情回首薄如烟。',32,'全唐诗/poet.song.131000.json','["險詐沾沾不愧天，交情回首薄如烟。", "東遊萬里雖堪樂，灧澦瞿唐要放船。"]'),
('46554ebd-0d9b-4a34-9dc0-06e248c272d8','三峽歌九首  其六','陸游','宋','宋诗','song-poetry','','[]','蠻江水碧瘴花紅，白舫黄旗無便風。',32,'全唐诗/poet.song.131000.json','["蠻江水碧瘴花紅，白舫黄旗無便風。", "涪萬四時常避水，棚居高出亂雲中。"]'),
('5d4f26ff-1ae2-4b67-910a-32135e4a7d69','三峽歌九首  其七','陸游','宋','宋诗','song-poetry','','[]','亂插山花篢子紅，蠻歌相和瀼西東。',32,'全唐诗/poet.song.131000.json','["亂插山花篢子紅，蠻歌相和瀼西東。", "忽然四散不知處，踏月捫蘿歸峒中。"]'),
('63bc2a52-cc4b-4a2b-8c93-cdb64315e17a','三峽歌九首  其八','陸游','宋','宋诗','song-poetry','','[]','萬州溪西花柳多，四鄰相應竹枝歌。',32,'全唐诗/poet.song.131000.json','["萬州溪西花柳多，四鄰相應竹枝歌。", "問君今夕不痛飲，奈此滿川明月何。"]'),
('52363dca-bfc7-454b-8b4b-9d782eb1b676','三峽歌九首  其九','陸游','宋','宋诗','song-poetry','','[]','我遊南賓春暮時，蜀船曾繫挂猿枝。',32,'全唐诗/poet.song.131000.json','["我遊南賓春暮時，蜀船曾繫挂猿枝。", "雲迷江岸屈原塔，花落空山夏禹祠。"]'),
('e207b2ad-fbec-4ddd-bdf8-24c9b82ba4b0','十月三日泛舟湖中作','陸游','宋','宋诗','song-poetry','','[]','桑落可釀酒，草枯可呼鷹。',96,'全唐诗/poet.song.131000.json','["桑落可釀酒，草枯可呼鷹。", "平生當此時，意氣十倍增。", "即今境界別，千錢買短篷。", "鏡湖三百里，往來寒日中。", "小甑炊雕胡，玉食無此美。", "卧聞水鳥聲，世念去如洗。", "知此恨太晚，享此恐不足。", "南山忽已昏，更就漁村宿。"]'),
('b9c48e4a-9ba0-4240-8e1e-e22d993442a7','早行','陸游','宋','宋诗','song-poetry','','[]','寒漏參差斷，晨雞次第鳴。',48,'全唐诗/poet.song.131000.json','["寒漏參差斷，晨雞次第鳴。", "匆匆半枕夢，草草一杯羹。", "澤國多逢雨，閑人不計程。", "雲間出寸塔，迎我有餘情。"]'),
('e23bfcab-e369-4fd6-9ce3-f96a10b16c35','晚泊','陸游','宋','宋诗','song-poetry','','[]','樓上嗚嗚角，橋邊點點燈。',49,'全唐诗/poet.song.131000.json','["樓上嗚嗚角，橋邊點點燈。", "聚沙新到雁，趁渡獨歸僧。", "日隱山光暗，天低海氣蒸。", "居人笑老子，醉髮亂鬅鬙）。"]'),
('d8f912b2-add7-4586-8780-423e97bf9f09','遣懷','陸游','宋','宋诗','song-poetry','','[]','暮年世事轉悠悠，攬涕凄然類楚囚。',32,'全唐诗/poet.song.131000.json','["暮年世事轉悠悠，攬涕凄然類楚囚。", "不道渾無排遣處，病觀周易悶梳頭。"]'),
('be28a6a1-0c5c-4103-a44a-8a96e72ee8cf','舟行戲書','陸游','宋','宋诗','song-poetry','','[]','世事無窮膏火煎，羈魂病骨久羸然。',64,'全唐诗/poet.song.131000.json','["世事無窮膏火煎，羈魂病骨久羸然。", "覺時不及夢差樂，死去始嗟生可憐。", "慷慨知非請纓日，推移忽及挂冠年。", "揚帆海浦差强意，卧看秋濤蹴遠天。"]'),
('b2c04366-d828-427f-b22e-6aec4695a9dd','久雨','陸游','宋','宋诗','song-poetry','','[]','黄葉雨中盡，饑鴻烟際來。',48,'全唐诗/poet.song.131000.json','["黄葉雨中盡，饑鴻烟際來。", "時艱歲仍惡，身死病相催。", "西埭無行路，南山有疾雷。", "囊空罷沽酒，一醉轉悠哉。"]'),
('c7a4db0e-fdd6-409c-8d12-512043324591','偶得長魚巨蟹命酒小飲蓋久無此舉也','陸游','宋','宋诗','song-poetry','','[]','老生日日困鹽齏，異味椶魚與楮雞。',64,'全唐诗/poet.song.131000.json','["老生日日困鹽齏，異味椶魚與楮雞。", "敢望槎頭分縮項，况當霜後得團臍。", "堪憐妄出緣香餌，尚想橫行向草泥。", "東崦夜來梅已動，一樽芳醞徑須携。"]'),
('8d7412b2-078a-4c88-a145-fcbccade48d7','泛舟湖山間有感','陸游','宋','宋诗','song-poetry','','[]','我似人間不繫舟，好風好月亦閑遊。',64,'全唐诗/poet.song.131000.json','["我似人間不繫舟，好風好月亦閑遊。", "歸來華表千年鶴，滅沒烟波萬里鷗。", "歲晚客貂那復嘆，時艱嫠緯未忘憂。", "野人只欲安耕釣，江左夷吾可見不。"]'),
('d92bcf5f-977f-426b-a311-1a09c8673e79','望永思陵二首  其一','陸游','宋','宋诗','song-poetry','','[]','綠衣迎拜屬車塵，草木曾霑雨露春。',32,'全唐诗/poet.song.131000.json','["綠衣迎拜屬車塵，草木曾霑雨露春。", "三十五年身未死，却爲天下最窮人。"]'),
('85802d6c-78ca-4a1d-95b1-7b2611f7823d','望永思陵二首  其二','陸游','宋','宋诗','song-poetry','','[]','旰食憂民宴樂疏，太倉幾有九年儲。',32,'全唐诗/poet.song.131000.json','["旰食憂民宴樂疏，太倉幾有九年儲。", "賈生未解人間事，北闕猶陳痛哭書。"]'),
('58527b31-6d59-4204-a751-aad464633a43','糟蟹','陸游','宋','宋诗','song-poetry','','[]','舊交髯簿久相忘，公子相從獨味長。',32,'全唐诗/poet.song.131000.json','["舊交髯簿久相忘，公子相從獨味長。", "醉死糟丘終不悔，看來端的是無腸。"]'),
('cb3a0a88-b7b2-479e-9efa-420a6edf25e1','霜夜三首  其一','陸游','宋','宋诗','song-poetry','','[]','梅花欲動夢魂狂，橙子閑搓指爪香。',32,'全唐诗/poet.song.131000.json','["梅花欲動夢魂狂，橙子閑搓指爪香。", "莫怪草堂清到骨，一梳殘月伴新霜。"]'),
('275fde31-fbd2-4a41-8b69-d1bd2eb320ba','霜夜三首  其二','陸游','宋','宋诗','song-poetry','','[]','黄甘磊落圍三寸，赤蟹輪囷可一斤。',32,'全唐诗/poet.song.131000.json','["黄甘磊落圍三寸，赤蟹輪囷可一斤。", "更喚東陽麴道士，與君霜夜策奇勳。"]'),
('5f387a6e-decb-4005-a225-b681fc45aae3','霜夜三首  其三','陸游','宋','宋诗','song-poetry','','[]','澹月窺窗似有情，更堪梅影向人橫。',32,'全唐诗/poet.song.131000.json','["澹月窺窗似有情，更堪梅影向人橫。", "放翁不受天魔惱，獨擁青氈睡到明。"]'),
('072c2a97-6372-4b4d-b4d9-0aaf700dd181','書室明暖終日婆娑其間倦則扶杖至小園戲作長句二首  其一','陸游','宋','宋诗','song-poetry','','[]','放翁老手竟超然，俗子何由與作緣。',64,'全唐诗/poet.song.131000.json','["放翁老手竟超然，俗子何由與作緣。", "百榼舊曾誇席地，一窗今復幻壺天。", "夢回橙在屏風曲，雨霽梅迎拄杖前。", "吾愛吾廬得安卧，笑人思潁憶平泉。"]'),
('5731ef5b-d445-414f-b735-4d4ed5dd9cd7','書室明暖終日婆娑其間倦則扶杖至小園戲作長句二首  其二','陸游','宋','宋诗','song-poetry','','[]','美睡宜人勝按摩，江南十月氣猶和。',64,'全唐诗/poet.song.131000.json','["美睡宜人勝按摩，江南十月氣猶和。", "重簾不捲留香久，古硯微凹聚墨多。", "月上忽看梅影出，風高時送雁聲過。", "一杯太淡君休笑，牛背吾方扣角歌。"]'),
('f7ba887f-b9a2-4a36-99ee-2825204a90f6','初冬','陸游','宋','宋诗','song-poetry','','[]','老客人間百事慵，樂哉閉戶過今冬。',64,'全唐诗/poet.song.131000.json','["老客人間百事慵，樂哉閉戶過今冬。", "朝爐獸炭騰紅焰，夜榻蠻氈擁紫茸。", "猬刺坼蓬新栗熟，鵝雛弄色凍醅濃。", "題詩正自消閑日，本不爭先萬戶封。"]'),
('62565d1b-c0c3-4fd5-96ef-89ef138e93a4','買屐','陸游','宋','宋诗','song-poetry','','[]','一雨三日泥，泥乾雨還作。',72,'全唐诗/poet.song.131000.json','["一雨三日泥，泥乾雨還作。", "出門每有礙，使我慘不樂。", "百錢買木屐，日日繞村行。", "東阡與北陌，不間陰與晴。", "青鞋豈不佳，要是欠耐久。", "何當踏深雪，就飲湖橋酒。"]'),
('228dfcf8-2669-4051-9921-ed6d5451171b','十月晦日作','陸游','宋','宋诗','song-poetry','','[]','藤疏不覆架，桐落欲平溝。',48,'全唐诗/poet.song.131000.json','["藤疏不覆架，桐落欲平溝。", "閏歲風霜晚，衰年日月遒。", "觀書方坐石，把釣又登舟。", "不是無羈束，閑人得自由。"]'),
('e220ce1b-9525-4c2f-96b0-95bfae028bb3','贈道友五首  其一','陸游','宋','宋诗','song-poetry','','[]','凡骨已蛻身自輕，勃落葉上行無聲。',32,'全唐诗/poet.song.131000.json','["凡骨已蛻身自輕，勃落葉上行無聲。", "華陰市樓醉舞罷，却上蓬峰看月明。"]'),
('0f2641a6-8f6f-413c-996e-0332a29e859c','贈道友五首  其二','陸游','宋','宋诗','song-poetry','','[]','憶在長安爛漫遊，大明宮闕與雲浮。',32,'全唐诗/poet.song.131000.json','["憶在長安爛漫遊，大明宮闕與雲浮。", "今朝偶上慈恩塔，北望茫茫禾黍秋。"]'),
('55ab2346-5906-4d82-8fc1-d814b5412136','贈道友五首  其三','陸游','宋','宋诗','song-poetry','','[]','當時辛苦學長生，準擬中原看太平。',32,'全唐诗/poet.song.131000.json','["當時辛苦學長生，準擬中原看太平。", "今日醉遊心已足，一瓢歸去隱青城。"]'),
('a526c5e3-3922-4a33-8328-7ce0b0fd026e','贈道友五首  其四','陸游','宋','宋诗','song-poetry','','[]','二杯兀兀復騰騰，服氣燒丹總不能。',32,'全唐诗/poet.song.131000.json','["二杯兀兀復騰騰，服氣燒丹總不能。", "借問生涯在何許，孤舟風雨伴漁燈。"]'),
('96b57690-3c8b-45a2-8321-38e9040f4ead','贈道友五首  其五','陸游','宋','宋诗','song-poetry','','[]','零落殘碑草棘中，北邙蕭瑟又秋風。',32,'全唐诗/poet.song.131000.json','["零落殘碑草棘中，北邙蕭瑟又秋風。", "舊時憶在鵷行裏，幾見宣麻拜相公。"]'),
('42db712a-8e8f-4037-a2d4-55341fb68efa','示子聿','陸游','宋','宋诗','song-poetry','','[]','儒林早歲竊虛名，白首何曾負短檠。',32,'全唐诗/poet.song.131000.json','["儒林早歲竊虛名，白首何曾負短檠。", "堪嘆一衰今至此，夢回聞汝讀書聲。"]'),
('7d14b5ff-0ecd-4d0e-8307-5fe618adaf5d','老境','陸游','宋','宋诗','song-poetry','','[]','平生百不遂，惟有老如期。',48,'全唐诗/poet.song.131000.json','["平生百不遂，惟有老如期。", "眼澀觀書夜，心衰把酒時。", "僧分新掘藥，客誦舊題詩。", "四十年前我，回看定是誰。"]'),
('54a537e3-d7fa-4ef2-94fc-53a897108eab','予所居三山在鏡湖上近取舍東地一畝種花數十株彊名小園因戲作長句','陸游','宋','宋诗','song-poetry','','[]','出郭西南十里過，小園風月得婆娑。',64,'全唐诗/poet.song.131000.json','["出郭西南十里過，小園風月得婆娑。", "翠屏三扇恰相倚，玉鏡一奩誰爲磨。", "投鑷未嫌衰鬢白，插花聊喜醉顔酡。", "耶溪更盡青鞋興，免使將軍怒脫靴。"]'),
('509b19c4-c005-4828-89d1-21885b73a218','被命再領沖佑有感','陸游','宋','宋诗','song-poetry','','[]','殘骸日益衰，晨夜抱疾痛。',72,'全唐诗/poet.song.131000.json','["殘骸日益衰，晨夜抱疾痛。", "地爐得微火，終日不憙動。", "讀書舊成癖，今但坐作夢。", "未能追鴻冥，乃復分鶴俸。", "風霜舍邊柳，合抱皆手種。", "眼中人盡非，欲話誰與共。"]'),
('123b3be4-4deb-47d8-bc03-a2d98fb1e0e6','冬夜戲書三首  其一','陸游','宋','宋诗','song-poetry','','[]','東歸剡曲寄彷徉，閑日雖冬亦自長。',64,'全唐诗/poet.song.131000.json','["東歸剡曲寄彷徉，閑日雖冬亦自長。", "梅瘦有情橫淡月，雲輕無力護清霜。", "長魚通印鹽花白，珍鮓披綿麴糝香。", "一飽喟然還自憫，彊顔垂老食官倉。"]'),
('283a3611-44be-46ba-a14b-3f4d2c8e21ed','冬夜戲書三首  其二','陸游','宋','宋诗','song-poetry','','[]','將挂衣冠彊小留，期年畢竟是歸休。',64,'全唐诗/poet.song.131000.json','["將挂衣冠彊小留，期年畢竟是歸休。", "青氈獨擁欺霜夜，濁酒頻傾洗客愁。", "鶴影冷翻丹井月，雁聲遥带玉關秋。", "一生自笑閑中過，不爲功名也白頭。"]'),
('769019e3-e042-4733-b4cc-f1a8c8fde88b','冬夜戲書三首  其三','陸游','宋','宋诗','song-poetry','','[]','老樹霜餘已盡紅，縱橫落葉滿庭中。',64,'全唐诗/poet.song.131000.json','["老樹霜餘已盡紅，縱橫落葉滿庭中。", "一鈎澹澹西南月，萬鼓憑憑東北風。", "賒酒每慚添舊券，讀書何計策新功。", "蓬窗坐睡摧頹甚，隔竹敲茶賴小童。"]'),
('4e845bf7-ef79-4acc-9f8b-263db5735d32','幽居二首  其一','陸游','宋','宋诗','song-poetry','','[]','落葉紛可掃，幽花寒自開。',48,'全唐诗/poet.song.131000.json','["落葉紛可掃，幽花寒自開。", "囷空無雀噪，門靜有僧來。", "孤學時方棄，窮途勢莫回。", "呼兒了租賦，莫待縣符催。"]'),
('33b97626-85cc-4219-a9f2-b41d8de70371','幽居二首  其二','陸游','宋','宋诗','song-poetry','','[]','雨霽雞栖早，風高雁陣斜。',48,'全唐诗/poet.song.131000.json','["雨霽雞栖早，風高雁陣斜。", "園丁刈霜稻，村女賣秋茶。", "缺井磨樵斧，枯桑繫釣槎。", "客來那用問，此是放翁家。"]'),
('01b76b32-93f4-435f-b2b5-1e5606d48509','送蘇召叟秀才入蜀效宛陵先生體','陸游','宋','宋诗','song-poetry','','[]','士勇赴知己，義重身固輕。',96,'全唐诗/poet.song.131000.json','["士勇赴知己，義重身固輕。", "尊公况有命，子得辭此行。", "結廬出門去，迢迢過蠻荆。", "泝江卜風色，入峽聽猿聲。", "萬里一紙書，南寄孤雁征。", "山陰在何處，計子難爲情。", "願言早來歸，鄰曲當出迎。", "檥舟柯橋市，一榼手自傾。"]'),
('179a1b5d-866a-4fa7-b8d3-1b5101ccc57e','寄題哲上人漫堂','陸游','宋','宋诗','song-poetry','','[]','老子從來任運行，愛君堂以漫爲名。',32,'全唐诗/poet.song.131000.json','["老子從來任運行，愛君堂以漫爲名。", "北邙大有英雄骨，枉用工夫過一生。"]'),
('1a3b2122-e752-41bc-bf5e-fb4e788716d1','冬夜獨酌','陸游','宋','宋诗','song-poetry','','[]','寒水茫茫浸月明，疏鐘杳杳带霜清。',64,'全唐诗/poet.song.131000.json','["寒水茫茫浸月明，疏鐘杳杳带霜清。", "一樽濁酒有妙理，十里荒雞非惡聲。", "物外雖增新跌宕，胸中未洗舊崢嶸。", "頹然坐睡蒲團穩，殘火昏燈伴五更。"]'),
('ca97c29d-fe6e-47d8-8177-105a61afa4ad','夜坐燈滅戲作','陸游','宋','宋诗','song-poetry','','[]','冷飯黄齏傲太平，鬢絲原不爲愁生。',32,'全唐诗/poet.song.131000.json','["冷飯黄齏傲太平，鬢絲原不爲愁生。", "忽因燈死得奇觀，明月滿窗梅影橫。"]'),
('a11204c1-8f56-46ff-92fc-5cc7e728b6b9','艾如張','陸游','宋','宋诗','song-poetry','','[]','錦膺繡羽名山雞，清泉可飲林可栖。',96,'全唐诗/poet.song.131000.json','["錦膺繡羽名山雞，清泉可飲林可栖。", "稻粱滿野棄不啄，雖有奇禍無階梯。", "東村西村烟雨晚，蕭艾離離林薄淺。", "翩然一下駭機發，汝雖知悔安能免。", "漢家天子南山下，萬騎合圍窮日夜。", "犬牙鷹爪死不辭，觸機折頸吁可悲。"]'),
('8e43527b-a024-4091-8227-d50b1726a379','上之回','陸游','宋','宋诗','song-poetry','','[]','咸陽宮闕天下壯，五更衛士傳雞唱。',96,'全唐诗/poet.song.131000.json','["咸陽宮闕天下壯，五更衛士傳雞唱。", "重門洞開鑾駕出，回中更在雲霄上。", "雲霄一路蟠青冥，車聲隱轔馳雷霆。", "宓妃穿仗王母下，何必軒皇居大庭。", "君王遊幸無終極，萬年盡是歡娛日。", "文成已死方不讎，茂陵松柏秋蕭瑟。"]'),
('a76c128f-ac36-46c7-83cc-a1889b468180','雜詠園中果子四首  其一','陸游','宋','宋诗','song-poetry','','[]','不酸金橘種初成，無核枇杷接亦生。',32,'全唐诗/poet.song.131000.json','["不酸金橘種初成，無核枇杷接亦生。", "珍產已從幽圃得，濁醪仍就小槽傾。"]'),
('94ce2a98-cba5-465b-831d-793abf486431','雜詠園中果子四首  其二','陸游','宋','宋诗','song-poetry','','[]','漿石榴隨糕作節，蠟櫻桃與酪同時。',32,'全唐诗/poet.song.131000.json','["漿石榴隨糕作節，蠟櫻桃與酪同時。", "兩株偶向池邊種，可喜今年墜折枝。"]'),
('76b1b418-8d57-476c-b41f-c4950582ed22','雜詠園中果子四首  其三','陸游','宋','宋诗','song-poetry','','[]','架垂馬乳收論斛，港種雞頭采滿船。',32,'全唐诗/poet.song.131000.json','["架垂馬乳收論斛，港種雞頭采滿船。", "黿鼎若爲占食指，麴車未用墮饞涎。"]'),
('535f466b-7833-41b1-8852-3aa3586b9999','雜詠園中果子四首  其四','陸游','宋','宋诗','song-poetry','','[]','山杏谿桃本看花，纍纍成實亦堪誇。',32,'全唐诗/poet.song.131000.json','["山杏谿桃本看花，纍纍成實亦堪誇。", "鹽收蜜漬饒風味，送與山僧下夜茶。"]'),
('561df2dd-542b-4aaf-a434-8b9c98c7fb60','閉戶二首  其一','陸游','宋','宋诗','song-poetry','','[]','聲利能令智者愚，放翁閉戶養迂疏。',64,'全唐诗/poet.song.131000.json','["聲利能令智者愚，放翁閉戶養迂疏。", "地爐枯葉夜煨芋，竹筧寒泉晨灌蔬。", "狥俗不如翻著襪，愛山只合倒騎驢。", "今朝更有欣然處，萬里知心一紙書。"]'),
('5cad3046-1e5a-41c0-a787-d277169ca3a4','閉戶二首  其二','陸游','宋','宋诗','song-poetry','','[]','冠蓋長安幾番新，放翁只似向來貧。',64,'全唐诗/poet.song.131000.json','["冠蓋長安幾番新，放翁只似向來貧。", "滿窗紅日價無敵，半榼新醅香動人。", "宴坐心光無蔽障，橫眠踵息自清勻。", "世間不用詢名字，身是無懷上古民。"]'),
('fef6cd88-9b77-4dae-ae77-0f32fceab8a9','連日大寒夜坐復苦饑戲作短歌','陸游','宋','宋诗','song-poetry','','[]','翁饑不能具小餐，兒凍何由成複褌。',96,'全唐诗/poet.song.131000.json','["翁饑不能具小餐，兒凍何由成複褌。", "藏書充棟讀至老，固願少出蘇黎元。", "念當萬事度可否，肯使一恨彌乾坤。", "古來賢達多晚謬，千載遺笑綺與園。", "老翁肝心等鐵石，他年骨朽此固存。", "村沽雖薄亦取醉，起看江月傾金盆。"]'),
('4857052c-8c02-473a-8960-b37a5cb92e15','園中對酒作','陸游','宋','宋诗','song-poetry','','[]','傴僂衰翁雪滿顛，愛花耽酒似當年。',64,'全唐诗/poet.song.131000.json','["傴僂衰翁雪滿顛，愛花耽酒似當年。", "雖無錦障七十里，也有青銅三百錢。", "數掩竹籬分小徑，一泓沙井貯寒泉。", "栽紅接白株株活，坐擁春工太半權。"]'),
('9b3cdd69-6028-4ec9-99e5-dbf71c189a13','孝宗皇帝挽詞三首  其一','陸游','宋','宋诗','song-poetry','','[]','大道本生知，崇高志不移。',48,'全唐诗/poet.song.131000.json','["大道本生知，崇高志不移。", "凝神超事物，觀妙極希夷。", "訪藥三山遠，遺弓萬國悲。", "神孫昔鍾愛，天作太平基。"]'),
('3276ee75-1301-490a-943c-075f5360d122','孝宗皇帝挽詞三首  其二','陸游','宋','宋诗','song-poetry','','[]','代邸膺圖日，臨朝涕泗橫。',48,'全唐诗/poet.song.131000.json','["代邸膺圖日，臨朝涕泗橫。", "誠心非外飾，至孝化群生。", "高廟聯龍衮，思陵接柏城。", "平生奉親意，一理貫幽明。"]'),
('2a465367-0e6e-4f24-9e91-7cabc8bb7025','孝宗皇帝挽詞三首  其三','陸游','宋','宋诗','song-poetry','','[]','便殿諮詢早，深宮宴樂稀。',48,'全唐诗/poet.song.131000.json','["便殿諮詢早，深宮宴樂稀。", "欲頒傳位詔，猶索未明衣。", "壽損名方永，身癯國愈肥。", "孤臣泣陵柏，心折九虞歸。"]'),
('f1315371-693e-43c4-9a5f-52ff2a5476c4','小兒入城','陸游','宋','宋诗','song-poetry','','[]','小兒破帽出求師，老父寒爐夜畫詩。',64,'全唐诗/poet.song.131000.json','["小兒破帽出求師，老父寒爐夜畫詩。", "不耐青燈寫孤影，聊呼薄酒慰長饑。", "我今僅守詩書業，汝勿輕捐少壯時。", "但恨北風如許惡，湖橋歸路想流澌。"]'),
('ff1bd705-5971-4e0f-8cb9-e8a46a297f45','夜坐二首  其一','陸游','宋','宋诗','song-poetry','','[]','萬螘披書卷，孤螢引篆香。',48,'全唐诗/poet.song.131000.json','["萬螘披書卷，孤螢引篆香。", "病思無事樂，老悔少年狂。", "南渡衣冠盛，西征道路長。", "如今俱夢破，高枕看人忙。"]'),
('e1c79694-76a3-4774-a771-e6a9e2eaf225','夜坐二首  其二','陸游','宋','宋诗','song-poetry','','[]','葉盡木無聲，天高夜自明。',48,'全唐诗/poet.song.131000.json','["葉盡木無聲，天高夜自明。", "映窗燈半滅，掠野雁孤征。", "瓦裂人間事，雲浮身後名。", "惟應托長鑱，寂寞送浮生。"]'),
('cb31cb0d-2f9a-4eca-9995-3184deedfaa0','縱筆五首  其一','陸游','宋','宋诗','song-poetry','','[]','惰游不能耕，心愧新舂白。',24,'全唐诗/poet.song.131000.json','["惰游不能耕，心愧新舂白。", "嘯傲茅三間，主人終勝客。"]'),
('ad8914ff-a1f2-4f8b-9634-a5c2f6ad2df8','縱筆五首  其二','陸游','宋','宋诗','song-poetry','','[]','朝士腰下黄，山僧鼻端白。',24,'全唐诗/poet.song.131000.json','["朝士腰下黄，山僧鼻端白。", "放翁俱笑汝，飽飯作閑客。"]'),
('ee011de5-f57a-464c-8cad-f372552fda45','縱筆五首  其三','陸游','宋','宋诗','song-poetry','','[]','溫溫地爐紅，皎皎紙窗白。',24,'全唐诗/poet.song.131000.json','["溫溫地爐紅，皎皎紙窗白。", "忽聞啄木聲，疑是敲門客。"]'),
('9dfc2008-f415-4f8b-b73b-78b01839db86','縱筆五首  其四','陸游','宋','宋诗','song-poetry','','[]','雪晴蓼甲紅，雨足韭頭白。',24,'全唐诗/poet.song.131000.json','["雪晴蓼甲紅，雨足韭頭白。", "雖無萬錢具，野飯可留客。"]'),
('267c7029-3e5a-48dd-a251-6d57a4fd56b6','縱筆五首  其五','陸游','宋','宋诗','song-poetry','','[]','小兒勿大勤，使汝髮早白。',24,'全唐诗/poet.song.131000.json','["小兒勿大勤，使汝髮早白。", "長爲南畝民，殊勝東閤客。"]'),
('154ae68c-6347-409a-a548-8c08e7c64960','郊行夜歸書觸目','陸游','宋','宋诗','song-poetry','','[]','老翁病起厭端居，隨意東西不問途。',64,'全唐诗/poet.song.131000.json','["老翁病起厭端居，隨意東西不問途。", "霜野草枯鷹欲下，江天雲溼雁相呼。", "空垣破竈逃租屋，青帽紅燈賣酒爐。", "未畏還家踏泥潦，園丁持炬小兒扶。"]'),
('a1ca0401-9221-468d-b049-1b0c1e2ab210','閉戶','陸游','宋','宋诗','song-poetry','','[]','老人閉戶動經月，懶就東家借蹇驢。',64,'全唐诗/poet.song.131000.json','["老人閉戶動經月，懶就東家借蹇驢。", "身後有名豈如酒，體中不佳聊讀書。", "秦王開圖見匕首，漢相狥市載厨車。", "人間憂怖古如此，莫怪荒畦常荷鋤。"]'),
('e561817d-52cd-4bd4-8315-569934b9aff2','十一月五日夜半偶作','陸游','宋','宋诗','song-poetry','','[]','草徑江村人迹絕，白頭病卧一書生。',64,'全唐诗/poet.song.131000.json','["草徑江村人迹絕，白頭病卧一書生。", "窗間月出見梅影，枕上酒醒聞雁聲。", "寂寞已甘千古笑，馳驅猶望兩河平。", "後生誰記當年事，泪濺龍床請北征。"]'),
('12e78ed7-fca8-45e8-9cd6-e2bbd48a3273','晴和出遊湖山間','陸游','宋','宋诗','song-poetry','','[]','日出氣稍和，呼船渡烟津。',96,'全唐诗/poet.song.131000.json','["日出氣稍和，呼船渡烟津。", "微風西南來，水面生魚鱗。", "適此一日佳，聊娛百年身。", "捋鬚俯船舷，一笑彼何人。", "閏餘春事早，已覺陽和新。", "梅花處處開，幽香襲衣巾。", "久病喜我出，問訊傾鄉鄰。", "舟回不須速，看涌白玉輪。"]'),
('b9cfe20f-1dbf-46be-b315-b9dfee5823fa','病思','陸游','宋','宋诗','song-poetry','','[]','賣劍還山學老農，不堪衰與病交攻。',64,'全唐诗/poet.song.131000.json','["賣劍還山學老農，不堪衰與病交攻。", "將軍閉戶方鋤菜，處士携家欲賃舂。", "殘齒彊留終臲卼，病腰扶拜苦龍鍾。", "壯遊誰信梁州日，大雪登城望夕烽。"]'),
('c4475bb8-985a-437d-b48d-945e66995521','寄子虡','陸游','宋','宋诗','song-poetry','','[]','老自安故鄉，况復觸罪罟。',120,'全唐诗/poet.song.131000.json','["老自安故鄉，况復觸罪罟。", "五年三奉祠，每請幸聽許。", "貧家似破屋，隨事且撐拄。", "雖殊乞墦肉，已近掘野鼠。", "平生膽力薄，不敢犯張禹。", "有時一言失，恐懼氣如縷。", "念此思挂冠，白首冀安處。", "吾兒哀乃翁，歲暮忍羈旅。", "何時得斗粟，歸舍聊共煮。", "便草北關書，乞骸歸卒伍。"]'),
('eeb5184e-ac91-4630-9935-ba2faf2c211c','紙閣午睡二首  其一','陸游','宋','宋诗','song-poetry','','[]','紙閣磚爐火一杴，斷香欲出礙蒲簾。',32,'全唐诗/poet.song.131000.json','["紙閣磚爐火一杴，斷香欲出礙蒲簾。", "放翁不管人間事，睡味無窮似蜜甜。"]'),
('0b612dcb-597e-40f3-9c99-a030203aca82','紙閣午睡二首  其二','陸游','宋','宋诗','song-poetry','','[]','黄紬被暖青氈穩，紙閣油窗晚更妍。',32,'全唐诗/poet.song.131000.json','["黄紬被暖青氈穩，紙閣油窗晚更妍。", "一飽無營睡終日，自疑身在結繩前。"]'),
('60239234-3237-4dc6-b5eb-8202480da041','夜分復起讀書','陸游','宋','宋诗','song-poetry','','[]','愁極不成寐，起開窗下書。',48,'全唐诗/poet.song.131000.json','["愁極不成寐，起開窗下書。", "似囚逢縱釋，如癢得爬梳。", "燈火夜過半，風霜歲欲除。", "平生濟時意，却作愛吾廬。"]'),
('efc673dd-cfce-45c9-9499-50c60a14a8c7','效蜀人煎茶戲作長句','陸游','宋','宋诗','song-poetry','','[]','午枕初回夢蝶床，紅絲小磑破旗槍。',64,'全唐诗/poet.song.131000.json','["午枕初回夢蝶床，紅絲小磑破旗槍。", "正須山石龍頭鼎，一試風爐蟹眼湯。", "巖電已能開倦眼，春雷不許殷枯腸。", "飯囊酒甕紛紛是，誰賞蒙山紫筍香。"]'),
('a8ef1ae1-e4c8-4db5-9264-6762589fda81','書逆旅壁','陸游','宋','宋诗','song-poetry','','[]','百憂襲暮年，懷抱日騷屑。',120,'全唐诗/poet.song.131000.json','["百憂襲暮年，懷抱日騷屑。", "雖云歸故鄉，何異萬里客。", "窮冬迫寒餓，凜有在陳厄。", "駕言適近村，慘慘天欲雪。", "人沽村市酒，馬齧山坡麥。", "旅炊雜沙土，得飽何暇擇。", "手皸若龜兆，面槁無人色。", "士窮自其分，所幸全大節。", "功名已甑墮，身世真瓦裂。", "不學玉關人，饑鷹方夜掣。"]'),
('025bb679-e442-4f35-bfc2-3bcf6346ab4e','懶趣','陸游','宋','宋诗','song-poetry','','[]','謝病掩柴荆，年來懶趣成。',48,'全唐诗/poet.song.131000.json','["謝病掩柴荆，年來懶趣成。", "舌根茶味永，鼻觀酒香清。", "已矣馳驅息，悠然磊磈平。", "高眠得三昧，夢斷已窗明。"]'),
('55160ffe-5999-4363-89eb-356b83bb07b3','閑中富貴二首  其一','陸游','宋','宋诗','song-poetry','','[]','要信人生各有緣，閑中富貴亦關天。',64,'全唐诗/poet.song.131000.json','["要信人生各有緣，閑中富貴亦關天。", "綠窗靜對千梢竹，翠竇新疏一脈泉。", "愛百衲琴常鎖匣，買雙鈎帖不論錢。", "箇中得意君知否，不換金貂與玉蟬。"]'),
('78049f16-805c-4bc2-a205-f63e9a4ccf26','閑中富貴二首  其二','陸游','宋','宋诗','song-poetry','','[]','天爲疏慵剩與閑，一庵青嶂白雲間。',64,'全唐诗/poet.song.131000.json','["天爲疏慵剩與閑，一庵青嶂白雲間。", "衲僧過別歸廬阜，羽客來尋說華山。", "冬筍生林龍𧥄𧥄，寒泉落磵佩珊珊。", "俗人自是無因到，雖設柴門不上關。"]'),
('9e966e5c-f13d-4f64-be1d-9a89e152f58a','書近况寄蜀中道舊','陸游','宋','宋诗','song-poetry','','[]','遺事復遺榮，空齋一榻橫。',48,'全唐诗/poet.song.131000.json','["遺事復遺榮，空齋一榻橫。", "宿酲投未正，新句煅初成。", "山崦傳梅信，天窗送雪聲。", "戲題勻碧紙，遣鶴報青城。"]'),
('3d2c155a-a4b7-40ac-afe4-612c72982c9b','醉中自贈','陸游','宋','宋诗','song-poetry','','[]','富貴猶宜早退休，一生齟齬更何求。',64,'全唐诗/poet.song.131000.json','["富貴猶宜早退休，一生齟齬更何求。", "賦形未至欠壬甲，語命寧須增斗牛。", "栗里收身貧亦樂，平陵埋骨死無憂。", "狂歌醉舞真當勉，剩折梅花插滿頭。"]'),
('c5f75b29-847b-41c1-9ac6-6c8421d8508d','明日自和','陸游','宋','宋诗','song-poetry','','[]','二頃元知未易求，不如馬磨學文休。',64,'全唐诗/poet.song.131000.json','["二頃元知未易求，不如馬磨學文休。", "正令未死有幾日，那得殘年叢百憂。", "霜野挾弓朝射雁，烟陂吹笛暮呼牛。", "興來醉倒尋常事，莫信兒童笑白頭。"]'),
('6281880d-84df-4ae8-aacd-d0e1c6e0ed3f','雪中至近村','陸游','宋','宋诗','song-poetry','','[]','荒山風雪歲將殘，貸粟迢迢犯苦寒。',64,'全唐诗/poet.song.131000.json','["荒山風雪歲將殘，貸粟迢迢犯苦寒。", "急燎征裘憩牛屋，旋沽村酒挂驢鞍。", "清貧徹骨初無憾，老健逢人彊自寬。", "深夜還家未能睡，解囊吹火取詩看。"]'),
('d4b67a41-44f1-42e8-ad72-61693d63d13c','歲暮感懷十首以餘年諒無幾休日愴已迫爲韵  其一','陸游','宋','宋诗','song-poetry','','[]','昨暮送客歸，短櫂過魯墟。',72,'全唐诗/poet.song.131000.json','["昨暮送客歸，短櫂過魯墟。", "故廬有遺趾，青山繞牆隅。", "桑竹雖鬰然，舊植已無餘。", "瓦礫不可求，而况屋壁書。", "繫舟問鄰人，搔首久躊躇。", "行當挂朝衣，躬耕返吾初。"]'),
('0279cbf2-171c-4ba5-bc03-ac8b0cd50202','歲暮感懷十首以餘年諒無幾休日愴已迫爲韵  其二','陸游','宋','宋诗','song-poetry','','[]','我家釋耒起，遠自東封前。',72,'全唐诗/poet.song.131000.json','["我家釋耒起，遠自東封前。", "詩書守素業，蟬聯二百年。", "長老日零落，念之心惕然。", "每恐後生輩，或爲利欲遷。", "我少亦知學，蹭蹬及華顛。", "訟過豈不力，壽非金石堅。"]'),
('9e77bf04-8199-43f9-9164-8a85b79a2a37','歲暮感懷十首以餘年諒無幾休日愴已迫爲韵  其三','陸游','宋','宋诗','song-poetry','','[]','我壯已早衰，晨鏡每惆悵。',72,'全唐诗/poet.song.131000.json','["我壯已早衰，晨鏡每惆悵。", "藥物姑自持，耆老曷敢望。", "造物有乘除，貧悴博無恙。", "歸鄉更多感，朋舊盡凋喪。", "客來多避席，謂我丈人行。", "此意詎敢忘，報子以直諒。"]'),
('f6e68395-3987-460e-b2d2-85e07dc0a604','歲暮感懷十首以餘年諒無幾休日愴已迫爲韵  其四','陸游','宋','宋诗','song-poetry','','[]','士生始志學，固爲聖人徒。',72,'全唐诗/poet.song.131000.json','["士生始志學，固爲聖人徒。", "人人可稷卨，世世皆唐虞。", "仰事與俯育，治道無絕殊。", "孔孟之所傳，世俗顧謂迂。", "申韓尚刻薄，老莊競虛無。", "爾車非不良，盍行九軌途。"]'),
('f77138d4-d7aa-43c3-98c6-7d26d5541e92','歲暮感懷十首以餘年諒無幾休日愴已迫爲韵  其五','陸游','宋','宋诗','song-poetry','','[]','江左謝太傅，高卧頗自喜。',72,'全唐诗/poet.song.131000.json','["江左謝太傅，高卧頗自喜。", "東山豈不佳，惜也終一起。", "阿堅偶自敗，元子亦適死。", "區區疑謗中，勳業端有幾。", "當時嘲小草，雖戲實中理。", "所以山中人，至今笑園綺。"]'),
('36d61dd4-d390-4fce-821b-144bdc32285e','歲暮感懷十首以餘年諒無幾休日愴已迫爲韵  其六','陸游','宋','宋诗','song-poetry','','[]','家世本無年，甲子近一周。',72,'全唐诗/poet.song.131000.json','["家世本無年，甲子近一周。", "小子獨何幸，七十今平頭。", "往者收朝迹，亟欲求歸休。", "厚恩許奉祠，得祿歲愈憂。", "三釜不及親，顧爲妻子留。", "何由洗此愧，欲挽天河流。"]'),
('e27a87b4-7b77-4a54-998c-22d5335c4c50','歲暮感懷十首以餘年諒無幾休日愴已迫爲韵  其七','陸游','宋','宋诗','song-poetry','','[]','高皇昔中興，風雨躬沐櫛。',72,'全唐诗/poet.song.131000.json','["高皇昔中興，風雨躬沐櫛。", "一士未嘗遺，萬里皆馳馹。", "廉聽闢言路，虛懷詢得失。", "孤臣實草芥，亦獲對宣室。", "龍顔宛在目，德不報萬一。", "橋山松柏寒，泪盡史臣筆。"]'),
('b132c0ca-f1f8-4fb4-b4b6-b332442fb4f0','歲暮感懷十首以餘年諒無幾休日愴已迫爲韵  其八','陸游','宋','宋诗','song-poetry','','[]','王師宿梁益，行臺護諸將。',72,'全唐诗/poet.song.131000.json','["王師宿梁益，行臺護諸將。", "腐儒忝辟書，萬里至渭上。", "旌旗照關路，風雪暗戎帳。", "堂堂鐵馬陣，亹亹木牛餉。", "誰知骨相薄，空負心膽壯。", "回首二十年，撫事增悲愴。"]'),
('688fbb2e-ae8d-46d9-b65a-43af8585d981','歲暮感懷十首以餘年諒無幾休日愴已迫爲韵  其九','陸游','宋','宋诗','song-poetry','','[]','在昔祖宗時，風俗極粹美。',72,'全唐诗/poet.song.131000.json','["在昔祖宗時，風俗極粹美。", "人材兼南北，議論忘彼此。", "誰令各植黨，更仆而迭起。", "中更夷狄禍，此風猶未已。", "臣不難負君，生者固賣死。", "儻筑太平基，請自厚俗始。"]'),
('92c2ccbc-f0ab-472a-b70f-d30f304e34c7','歲暮感懷十首以餘年諒無幾休日愴已迫爲韵  其一○','陸游','宋','宋诗','song-poetry','','[]','井地以養民，整整若棋畫。',72,'全唐诗/poet.song.131000.json','["井地以養民，整整若棋畫。", "初無甚貧富，家有五畝宅。", "哀哉古益遠，禍始開阡陌。", "富豪役千奴，貧老無寸帛。", "困窮禮義廢，盜賊起蹙迫。", "誰能講古制，壽我太平脈。"]'),
('e0252d63-dd83-458b-a412-f4fc3e190610','桐江哲上人以端硯遺子聿纔寸餘而質甚奇天將雨輒先流甕予爲效宛陵先生體作詩一首','陸游','宋','宋诗','song-poetry','','[]','吾兒得巖硯，其徑甫踰寸。',48,'全唐诗/poet.song.131000.json','["吾兒得巖硯，其徑甫踰寸。", "奇哉掌握物，乃有琮璧潤。", "器寶備才德，初不以形論。", "汝能志山林，懷之可嘉遯。"]'),
('752bd504-9829-41db-a020-401bde6918b7','立春前三日作','陸游','宋','宋诗','song-poetry','','[]','春近寒尤苦，先生不下堂。',48,'全唐诗/poet.song.131000.json','["春近寒尤苦，先生不下堂。", "烏皮蒙燕几，白拂挂禪床。", "書架斜斜設，梅花細細香。", "悠然睡還起，已覺日微長。"]'),
('103fc083-b0b2-4286-ac89-1bbf608821e9','贈應秀才','陸游','宋','宋诗','song-poetry','','[]','過宋不見元城公，渡淮不見陳了翁。',96,'全唐诗/poet.song.131000.json','["過宋不見元城公，渡淮不見陳了翁。", "當時人人皆太息，至今海內傾高風。", "老夫七十居鄉縣，齷齪龍鍾何足見。", "辱君雪裏來叩門，自說辛勤求識面。", "我得茶山一轉語，文章切忌參死句。", "知君此外無他求，有求寧踏三山路。"]'),
('cc77591a-1781-4f12-82df-9bb96686eb84','春耕','陸游','宋','宋诗','song-poetry','','[]','今年液水滿西疇，父老人人卜有秋。',32,'全唐诗/poet.song.131000.json','["今年液水滿西疇，父老人人卜有秋。", "只要耕犁及時節，裹茶買餅去租牛。"]'),
('65f4d0a8-0567-4da6-8880-ce30fb380fe0','首春連陰','陸游','宋','宋诗','song-poetry','','[]','入春十日九日陰，積雪未解雨復霪。',96,'全唐诗/poet.song.131000.json','["入春十日九日陰，積雪未解雨復霪。", "西家船漏湖水漲，東家驢病街泥深。", "去秋宿麥不入土，今年米貴如黄金。", "老嫗哭子那可聽，僵死不覆黔婁衾。", "州家遣騎饋春酒，欲飲復止吾何心。", "出門空嘆歲華速，已見微綠生高林。"]'),
('540a070d-35bc-4055-8873-f10a52457e17','夜坐','陸游','宋','宋诗','song-poetry','','[]','衰翁不出門，歲月過電雹。',72,'全唐诗/poet.song.131000.json','["衰翁不出門，歲月過電雹。", "窗明地爐暖，袖手坐寂寞。", "可憐瓶中梅，爛漫幾開落。", "小園亦數樹，曾未破一萼。", "三更北風急，雨雪恐復作。", "且當勤舉杯，莫恨浮蟻濁。"]'),
('ef4e8885-c291-4d9a-bbf4-20dea9fcb95b','新春','陸游','宋','宋诗','song-poetry','','[]','老境三年病，新元十日陰。',48,'全唐诗/poet.song.131000.json','["老境三年病，新元十日陰。", "疏籬枯蔓綴，壞壁綠苔侵。", "憂國孤臣泪，平胡壯士心。", "吾非兒女輩，肯賦白頭吟。"]'),
('e7fcfbd4-0df5-4eea-b3ec-b6f71368807b','得季長書追懷南鄭幕府慨然有作','陸游','宋','宋诗','song-poetry','','[]','從戎昔在山南日，彊半春光醉裏銷。',64,'全唐诗/poet.song.131000.json','["從戎昔在山南日，彊半春光醉裏銷。", "綠樹啼鶯窺帽影，畫橋飛絮逐鞭梢。", "花經小雨開差晚，笙怯餘寒澀未調。", "惆悵流年又如許，羈魂欲仗楚詞招。"]'),
('f295cdf0-4ab4-4639-a9c4-2122334bb901','正月十一日夜夢與亡友譚德稱相遇於成都小東門外既覺慨然有作','陸游','宋','宋诗','song-poetry','','[]','當年與子別江干，漸老心知後會難。',32,'全唐诗/poet.song.131000.json','["當年與子別江干，漸老心知後會難。", "豈料今宵清夢裏，東門交轡說春寒。"]'),
('cb9b342e-f2f0-4bfa-aba8-310446734243','送陳吏部還朝','陸游','宋','宋诗','song-poetry','','[]','邂逅稽山許攬鬚，塵埃時得近冰壺。',64,'全唐诗/poet.song.131000.json','["邂逅稽山許攬鬚，塵埃時得近冰壺。", "不辭我老雞豚社，且喜公歸櫻筍厨。", "滿室琴書懷燕几，一川風雨送行艫。", "勉哉早了功名債，要畫騎牛第二圖。"]'),
('c7f258d6-74c0-4e72-9f7b-e63aeb1c54a5','觀棋','陸游','宋','宋诗','song-poetry','','[]','一枰翻覆戰枯棋，慶吊相尋喜復悲。',64,'全唐诗/poet.song.131000.json','["一枰翻覆戰枯棋，慶吊相尋喜復悲。", "失馬翁言良可信，牧豬奴戲未妨爲。", "白蛇斷處真成快，黑幟空時又一奇。", "斂付兩奩來對酒，泠泠聽我誦新詩。"]'),
('ed0082d0-6eaf-432b-8383-abfa7574d838','春行','陸游','宋','宋诗','song-poetry','','[]','篛帽絲絲雨，芒鞋策策泥。',48,'全唐诗/poet.song.131000.json','["篛帽絲絲雨，芒鞋策策泥。", "柳斜風带北，花斂日平西。", "社酒誇新壓，春蕪喜遍犁。", "深村無客過，父子自扶携。"]'),
('55f8d8c1-1d5a-4eff-8b6f-8b5efd94ad3a','雨霽春色粲然喜而有賦','陸游','宋','宋诗','song-poetry','','[]','應接年光老漸慵，猶能一飲百分空。',64,'全唐诗/poet.song.131000.json','["應接年光老漸慵，猶能一飲百分空。", "半霑蝶粉簾櫳雨，遠送鶯聲巷陌風。", "千縷麴塵楊柳綠，萬枝猩血海棠紅。", "從來造物陶甄手，却在閑人詩句中。"]'),
('e0a92533-c021-4962-8a7b-34467daf3592','幽思','陸游','宋','宋诗','song-poetry','','[]','雲際茅茨一兩間，春來幽事日相關。',64,'全唐诗/poet.song.131000.json','["雲際茅茨一兩間，春來幽事日相關。", "臨窗靜試下巖硯，欹枕卧看靈壁山。", "紅練带飛俱意得，錦熏籠暖尚香慳。", "今朝社過添惆悵，高棟巢空燕未還。"]'),
('a13d4ad5-662c-44b7-8087-0ccc8eb1d68f','贈持鉢道人','陸游','宋','宋诗','song-poetry','','[]','青鐵作小冠，白紵縫短褐。',72,'全唐诗/poet.song.131000.json','["青鐵作小冠，白紵縫短褐。", "右扶九節杖，左執七綴鉢。", "何嘗有定止，到處可生活。", "惟有烈士心，白刃不能奪。", "相逢一笑粲，滯思得披豁。", "揮袂去若飛，跂望已天末。"]'),
('4a4ba7d0-402d-427a-91e2-2d6fd005f36d','柳二首  其一','陸游','宋','宋诗','song-poetry','','[]','楊柳春風綠萬條，憑鞍一望已魂消。',32,'全唐诗/poet.song.131000.json','["楊柳春風綠萬條，憑鞍一望已魂消。", "當年鳳集城邊路，曾愛纖纖拂畫橋。"]'),
('c2d98615-d209-4579-92c7-8684d08f9593','柳二首  其二','陸游','宋','宋诗','song-poetry','','[]','西園雨打杏花稀，便面章臺事已非。',32,'全唐诗/poet.song.131000.json','["西園雨打杏花稀，便面章臺事已非。", "只恐無情堤上柳，又將風絮送春歸。"]'),
('62ebfbbf-fad9-432b-894a-6bab23a4ae78','山園雜詠五首  其一','陸游','宋','宋诗','song-poetry','','[]','祠祿留人未挂冠，山園三畝著身寬。',64,'全唐诗/poet.song.131000.json','["祠祿留人未挂冠，山園三畝著身寬。", "百年竟向愁邊老，萬事元輸靜處看。", "花徑糝紅供晚醉，月天生暈作春寒。", "汗青事業都忘盡，時賴吾兒舉話端。"]'),
('a5f3f60a-2854-43f7-aa87-bc39c24e1f29','山園雜詠五首  其二','陸游','宋','宋诗','song-poetry','','[]','殘春終日在林亭，散髮披衣醉復醒。',64,'全唐诗/poet.song.131000.json','["殘春終日在林亭，散髮披衣醉復醒。", "科斗已成蛙閤閤，櫻桃初結子青青。", "魚遊滄海寧濡沫，禽慕雕籠即翦翎。", "薄晚東風吹小雨，笑携長鑱伴畦丁。"]'),
('9e7add14-c9b0-4545-bb63-32dc4b7f73f4','山園雜詠五首  其三','陸游','宋','宋诗','song-poetry','','[]','桃花爛熳杏花稀，春色撩人不忍違。',64,'全唐诗/poet.song.131000.json','["桃花爛熳杏花稀，春色撩人不忍違。", "俗客年來真掃迹，清樽日暮獨忘歸。", "魚行池面紅雲散，鵲起枝頭絳雪飛。", "莫道顛狂無訴處，卧看香篆掩齋扉。"]'),
('175a05ca-92c7-4a50-9dab-845441ac5f00','山園雜詠五首  其四','陸游','宋','宋诗','song-poetry','','[]','已過社雨尚春寒，小醉初醒怯倚欄。',64,'全唐诗/poet.song.131000.json','["已過社雨尚春寒，小醉初醒怯倚欄。", "柳带花移宜土潤，鶴和雛養要籠寬。", "孤翁白首投村社，諸彥青雲接羽翰。", "誰信幽居多樂事，晚窗兒女話團圞。"]'),
('cd444e35-023f-4b15-9ed9-843f5731ca7c','山園雜詠五首  其五','陸游','宋','宋诗','song-poetry','','[]','春光何止二分空，寒食都無數日中。',64,'全唐诗/poet.song.131000.json','["春光何止二分空，寒食都無數日中。", "密葉成陰花寂寂，舊巢添土燕匆匆。", "紙鳶收線愁風惡，秧馬掀泥喜雨濛。", "堪嘆今年衰更甚，蒼顔縱醉不成紅。"]'),
('1c22332f-23f3-400d-b158-c93775e756e9','雨夜書感二首  其一','陸游','宋','宋诗','song-poetry','','[]','宦遊四十年，歸逐桑榆暖。',96,'全唐诗/poet.song.131000.json','["宦遊四十年，歸逐桑榆暖。", "皇恩念黎老，一官猶置散。", "春殘桃李盡，風雨閉空館。", "有懷無與陳，萬事付酒碗。", "近代固多賢，吾意終不滿。", "可憐杜拾遺，冒死明房琯。", "慷慨詎非奇，經綸恨才短。", "群胡穴中原，令人嘆微管。"]'),
('91a5b61d-faae-47fc-8f94-b3ac0c54cf0f','雨夜書感二首  其二','陸游','宋','宋诗','song-poetry','','[]','儒生不自貴，執藝等卜祝。',96,'全唐诗/poet.song.131000.json','["儒生不自貴，執藝等卜祝。", "詩書定何物，爲汝市爵祿。", "唐虞雖日遠，凜凜猶在目。", "誰能舉其要，治功端可復。", "平生粗知此，俛仰髮已禿。", "一豪不獲施，老病死巖谷。", "安知萬世後，終無可封俗。", "願廣稽古心，端拱咨嶽牧。"]'),
('278c3bef-e65e-44f1-b75b-6e7531df2e26','鏡湖','陸游','宋','宋诗','song-poetry','','[]','躬耕蘄一飽，閔閔望有年。',96,'全唐诗/poet.song.131000.json','["躬耕蘄一飽，閔閔望有年。", "水旱適繼作，斗米幾千錢。", "鏡湖泆已久，造禍初非天。", "孰能求其故，遺迹猶隱然。", "增卑以爲高，培薄使之堅。", "坐復千載利，名託亡窮傳。", "民愚不能知，仕者苟目前。", "吾言固應棄，悄愴夜不眠。"]'),
('eb6fadfb-9892-4b54-9d5b-4932dda91b30','舟中戲書','陸游','宋','宋诗','song-poetry','','[]','平生萬事付之天，百折猶能氣浩然。',64,'全唐诗/poet.song.131000.json','["平生萬事付之天，百折猶能氣浩然。", "試問軟塵金絡馬，何如柔櫓月侵船。", "英雄到底是癡絕，富貴但能妨醉眠。", "三百里湖隨意住，人間真有地行仙。"]'),
('0f53c1fb-21b3-4d14-b1be-e6fa5e554692','春晚懷山南四首  其一','陸游','宋','宋诗','song-poetry','','[]','梨花堆雪柳吹綿，常記梁州古驛前。',32,'全唐诗/poet.song.131000.json','["梨花堆雪柳吹綿，常記梁州古驛前。", "二十四年成昨夢，每逢春晚即凄然。"]'),
('17e7248b-bae1-4ea0-8f74-667d565eaf1d','春晚懷山南四首  其二','陸游','宋','宋诗','song-poetry','','[]','壯歲從戎不憶家，梁州裘馬鬭豪華。',32,'全唐诗/poet.song.131000.json','["壯歲從戎不憶家，梁州裘馬鬭豪華。", "至今夜夜尋春夢，猶在吳園藉落花。"]'),
('ecb7f00e-a321-4aa8-87ea-59d9c242e048','春晚懷山南四首  其三','陸游','宋','宋诗','song-poetry','','[]','梁州一別幾清明，常憶西郊信馬行。',32,'全唐诗/poet.song.131000.json','["梁州一別幾清明，常憶西郊信馬行。", "桃李成塵總閑事，梨花楊柳最關情。"]'),
('2148aac0-24c7-45c8-8e97-eb427bf0cabc','春晚懷山南四首  其四','陸游','宋','宋诗','song-poetry','','[]','身寄江湖兩鬢霜，金鞭朱彈夢猶狂。',32,'全唐诗/poet.song.131000.json','["身寄江湖兩鬢霜，金鞭朱彈夢猶狂。", "遥知南鄭城西路，月與梨花共斷腸。"]'),
('2e01b19f-4d04-43d5-8e0f-2519aaf85e8f','春晚書齋壁','陸游','宋','宋诗','song-poetry','','[]','海棠已成雪，桃李不足言。',96,'全唐诗/poet.song.131000.json','["海棠已成雪，桃李不足言。", "纖纖麥被野，鬰鬰桑連村。", "稚蠶細如螘，杜宇號朝昏。", "展墓秫餌美，坐社黍酒渾。", "早筍漸上市，青韭初出園。", "老夫下箸喜，盡屏雞與豚。", "幽居亦何樂，且洗兩耳喧。", "呼兒燒柏子，悠然坐東軒。"]'),
('1df15a39-6aca-4abb-a085-3c4e98b578b0','七十一翁吟','陸游','宋','宋诗','song-poetry','','[]','七十一翁心事闌，坐叨祠祿養衰殘。',64,'全唐诗/poet.song.131000.json','["七十一翁心事闌，坐叨祠祿養衰殘。", "樽中無酒但清坐，架上有書猶縱觀。", "吏部齒摇心悵望，將軍髀滿泪汍瀾。", "客來共飯增羞澀，小摘山蔬不掩盤。"]'),
('119b3c54-e995-4a7d-a80c-8ce2c5386529','山茶一樹自冬至清明後著花不已','陸游','宋','宋诗','song-poetry','','[]','東園三日雨兼風，桃李飄零掃地空。',32,'全唐诗/poet.song.131000.json','["東園三日雨兼風，桃李飄零掃地空。", "惟有山茶偏耐久，綠叢又放數枝紅。"]'),
('3972831c-39fe-47e9-bc3e-c6fd9bbb945f','晨起','陸游','宋','宋诗','song-poetry','','[]','初日破蒼烟，零亂松竹影。',48,'全唐诗/poet.song.131000.json','["初日破蒼烟，零亂松竹影。", "老夫起燒香，童子行汲井。", "平生水雲身，不墮車馬境。", "願言學龐公，全家事幽屏。"]'),
('264e8703-821c-4d40-8b29-834f6c549992','春晚雜興六首  其一','陸游','宋','宋诗','song-poetry','','[]','寂寂野人家，柴扉傍水斜。',48,'全唐诗/poet.song.131000.json','["寂寂野人家，柴扉傍水斜。", "僧分晨鉢筍，客共午甌茶。", "燕戶添新土，蛛絲罥落花。", "悠然便終日，惟此送年華。"]'),
('fbae2c40-81cb-4f6d-a041-738671866ea1','春晚雜興六首  其二','陸游','宋','宋诗','song-poetry','','[]','澤國固多雨，暮春猶薄寒。',48,'全唐诗/poet.song.131000.json','["澤國固多雨，暮春猶薄寒。", "兒童葺茶舍，婦女賽蠶官。", "閱世年雖往，爲農興未闌。", "窮途得一飽，亦足慰艱難。"]'),
('7a0a788c-6f91-45f2-a5d9-daaeddc77fc0','春晚雜興六首  其三','陸游','宋','宋诗','song-poetry','','[]','池面萍初紫，牆頭杏已青。',48,'全唐诗/poet.song.131000.json','["池面萍初紫，牆頭杏已青。", "携兒撐小艇，留客坐孤亭。", "相法無侯骨，生年直酒星。", "正須遺萬事，莫遣片時醒。"]'),
('a4f67f6f-7a76-4559-96e9-b16582dd3869','春晚雜興六首  其四','陸游','宋','宋诗','song-poetry','','[]','小市湖橋北，幽居石埭西。',48,'全唐诗/poet.song.131000.json','["小市湖橋北，幽居石埭西。", "蒲深姑惡哭，樹密秭歸啼。", "山茗封青箬，村酤坼赤泥。", "平生汗簡手，投老慣扶犁。"]'),
('75eb5ec5-318e-4eb5-817b-b0588b7390df','春晚雜興六首  其五','陸游','宋','宋诗','song-poetry','','[]','病瘍無意緒，閉戶作生涯。',48,'全唐诗/poet.song.131000.json','["病瘍無意緒，閉戶作生涯。", "草草半盂飯，悠悠一碗茶。", "笑穿居士屩，閑看女郎花。", "莫問明朝事，忘家即出家。"]'),
('c4389427-bfb3-4a74-97eb-c17207697e7a','春晚雜興六首  其六','陸游','宋','宋诗','song-poetry','','[]','青梅薦煮酒，綠樹變鳴禽。',48,'全唐诗/poet.song.131000.json','["青梅薦煮酒，綠樹變鳴禽。", "處世已如客，傷春無復心。", "焚香惟默坐，曳杖亦幽尋。", "一日悠然過，深慚惜寸陰。"]'),
('440f2ecf-ad9e-432c-b669-7ee65d71e3f9','齋中雜題四首  其一','陸游','宋','宋诗','song-poetry','','[]','列屋蛾眉不足誇，可齋別自是生涯。',32,'全唐诗/poet.song.131000.json','["列屋蛾眉不足誇，可齋別自是生涯。", "閑將西蜀團窠錦，自背南唐落墨花。"]'),
('2eda8b6d-1c26-4e7a-a9d5-ad913b8f20c2','齋中雜題四首  其二','陸游','宋','宋诗','song-poetry','','[]','小醉微吟過一春，人間儂是最閑人。',32,'全唐诗/poet.song.131000.json','["小醉微吟過一春，人間儂是最閑人。", "龜毛拂子長三尺，拈起風光處處新。"]'),
('7b00e321-ece7-4cbf-9171-d57e9150a5f0','齋中雜題四首  其三','陸游','宋','宋诗','song-poetry','','[]','棐几硯涵鸜鵒眼，古奩香斮鷓鴣斑。',32,'全唐诗/poet.song.131000.json','["棐几硯涵鸜鵒眼，古奩香斮鷓鴣斑。", "絕知造物殷勤意，成就衰翁到死閑。"]'),
('d0c962c2-481e-475b-bf59-e6b91701ad9e','齋中雜題四首  其四','陸游','宋','宋诗','song-poetry','','[]','幽居厭見凡花草，紅紫紛紛不復栽。',32,'全唐诗/poet.song.131000.json','["幽居厭見凡花草，紅紫紛紛不復栽。", "自斸蒼苔換黄土，南山移得玉芝來。"]'),
('970c98cd-0643-4e2a-a5df-9907237e93a6','老疾戲自贈','陸游','宋','宋诗','song-poetry','','[]','年過七十日夜衰，羸然骨立不支持。',96,'全唐诗/poet.song.131000.json','["年過七十日夜衰，羸然骨立不支持。", "一身百病作無時，飯且不足那論醫。", "鏡中之人定是誰，面骨突兀鬢成絲。", "買棺作冢計已遲，一旦寧免累諸兒。", "門前湖山可遨嬉，心雖欲往力不隨。", "左車牙脫吁可悲，問汝何不食肉糜。"]'),
('ca6f37d5-6c82-48d0-b989-baaefeaeed03','夜坐聞湖中漁歌','陸游','宋','宋诗','song-poetry','','[]','少年嗜書竭目力，老去觀書澀如棘。',64,'全唐诗/poet.song.131000.json','["少年嗜書竭目力，老去觀書澀如棘。", "短檠油盡固自佳，坐守一窗如漆黑。", "漁歌裊裊起三更，哀而不怨非凡聲。", "明星已高聲未已，疑是湖中隱君子。"]'),
('11d8c360-fb23-4fb8-bfcb-424dc21b45b6','上巳書事','陸游','宋','宋诗','song-poetry','','[]','單衣初著下湖天，飛蓋相隨出郭船。',64,'全唐诗/poet.song.131000.json','["單衣初著下湖天，飛蓋相隨出郭船。", "得雨人人喜秧信，祈蠶戶戶斂神錢。", "黄雞煮𦞦無停筯，青韭淹葅欲墮涎。", "丞相傳聞又三押，衡茅未改日高眠。"]'),
('2f05584c-ba7f-4cd7-9533-78753c1490a8','對酒','陸游','宋','宋诗','song-poetry','','[]','手摘酴醿翦牡丹，山家草草亦杯盤。',32,'全唐诗/poet.song.131000.json','["手摘酴醿翦牡丹，山家草草亦杯盤。", "溪頭一夜風吹雨，又作殘春幾日寒。"]'),
('ccd2569d-9d84-421e-89bc-462b6524f813','自規','陸游','宋','宋诗','song-poetry','','[]','陸君拙自謀，七十猶糲食。',72,'全唐诗/poet.song.131000.json','["陸君拙自謀，七十猶糲食。", "著書雖如山，身不一錢直。", "默自觀我生，困弱良得力。", "轉喉畏或觸，唾面敢自拭。", "世路方未夷，機阱寧有極。", "但能常閉門，尊拳貸雞肋。"]'),
('3ead5999-6be6-47da-9161-62f3471430e1','窮居有感','陸游','宋','宋诗','song-poetry','','[]','孤村烟草暮凄迷，笠子蓑衣自架犁。',64,'全唐诗/poet.song.131000.json','["孤村烟草暮凄迷，笠子蓑衣自架犁。", "生計似蛛聊補網，弊廬如燕旋添泥。", "人亡耆舊多時學，地廢陂湖失古堤。", "迂闊自知無著處，敢因窮厄怨推擠。"]'),
('f4a14cd2-6210-4ec2-b686-d8a76bc84de5','春夏之交風日清美欣然有賦三首  其一','陸游','宋','宋诗','song-poetry','','[]','日鑄珍芽開小缶，銀波煮酒湛華觴。',64,'全唐诗/poet.song.131000.json','["日鑄珍芽開小缶，銀波煮酒湛華觴。", "槐陰漸長簾櫳暗，梅子初嘗齒頰香。", "戶戶祈蠶喧鼓笛，村村乘雨筑陂塘。", "年光何預衰翁事，伴蝶隨鶯也解狂。"]'),
('99169cab-b37c-441d-ac10-0fe3d93fb27d','春夏之交風日清美欣然有賦三首  其二','陸游','宋','宋诗','song-poetry','','[]','天遣殘年脫馽鞿，功名不恨與心違。',64,'全唐诗/poet.song.131000.json','["天遣殘年脫馽鞿，功名不恨與心違。", "綠陂細雨移秧罷，朱舫斜陽擘紙歸。", "花市丹青賣團扇，象床刀尺製單衣。", "白頭曳杖人爭看，共嘆浮生七十稀。"]'),
('6005f795-908e-4db7-ab6b-4c45efee9b58','春夏之交風日清美欣然有賦三首  其三','陸游','宋','宋诗','song-poetry','','[]','芳潤園林不似貧，年光無盡逐番新。',64,'全唐诗/poet.song.131000.json','["芳潤園林不似貧，年光無盡逐番新。", "來禽顔色不禁雨，摶黍語言如惜春。", "身外豈關吾輩事，鏡中已換昔時人。", "神僊定未超塵俗，猶插金貂侍帝晨。"]'),
('2c293f6d-2c59-48af-97d4-597072980af6','夜歸','陸游','宋','宋诗','song-poetry','','[]','疏鐘渡水來，素月依林上。',24,'全唐诗/poet.song.131000.json','["疏鐘渡水來，素月依林上。", "烟火認茅廬，故倚船篷望。"]'),
('5d73944d-f9c2-44ce-a99b-53443b7f36bf','農家嘆','陸游','宋','宋诗','song-poetry','','[]','有山皆種麥，有水皆種秔。',96,'全唐诗/poet.song.131000.json','["有山皆種麥，有水皆種秔。", "牛領瘡見骨，叱叱猶夜耕。", "竭力事本業，所願樂太平。", "門前誰剝啄，縣吏徵租聲。", "一身入縣庭，日夜窮笞搒。", "人孰不憚死，自計無由生。", "還家欲具說，恐傷父母情。", "老人儻得食，妻子鴻毛輕。"]'),
('d59db481-f580-40a8-ac19-44a4160e8b33','三月十一日郊行','陸游','宋','宋诗','song-poetry','','[]','到處人家可乞漿，槐陰巷陌午風凉。',64,'全唐诗/poet.song.131000.json','["到處人家可乞漿，槐陰巷陌午風凉。", "水陂漫漫新秧綠，山壟離離大麥黄。", "父子力耕春漸老，婦姑共績夜猶長。", "堯民擊壤雖難繼，芹美懷君未敢忘。"]'),
('e2ca101e-7d81-42f9-ba43-ad1cd9aaa5b4','初夏行平水道中','陸游','宋','宋诗','song-poetry','','[]','老去人間樂事稀，一年容易又春歸。',64,'全唐诗/poet.song.131000.json','["老去人間樂事稀，一年容易又春歸。", "市橋壓擔蓴絲滑，村店堆盤豆莢肥。", "傍水風林鶯語語，滿原烟草蝶飛飛。", "郊行已覺侵微暑，小立桐陰換夾衣。"]'),
('36d1a381-7680-4cb2-a33e-86bb0803f676','初夏幽居偶題四首  其一','陸游','宋','宋诗','song-poetry','','[]','放逐還家一老翁，癡頑自笑更誰同。',64,'全唐诗/poet.song.131000.json','["放逐還家一老翁，癡頑自笑更誰同。", "倚欄風月黄昏後，携杖園林綠潤中。", "泳水小魚依藻荇，覓巢輕燕拂簾櫳。", "此身要豈堅牢物，莫遣須臾酒盞空。"]'),
('2b12c9f6-daaf-41d0-b583-beeafde605bb','初夏幽居偶題四首  其二','陸游','宋','宋诗','song-poetry','','[]','展盡高槐日漸長，了無蜂蝶爲花忙。',64,'全唐诗/poet.song.131000.json','["展盡高槐日漸長，了無蜂蝶爲花忙。", "青梅旋摘宜鹽白，煮酒初嘗带臘香。", "林下光陰無一事，水邊窗戶有餘凉。", "應門不用辭衰疾，車馬何由到野堂。"]'),
('71fda2d0-8c6c-47ba-be86-37df1e9b134e','初夏幽居偶題四首  其三','陸游','宋','宋诗','song-poetry','','[]','昔如轉戰墮重圍，今幸鶱翔脫駭機。',64,'全唐诗/poet.song.131000.json','["昔如轉戰墮重圍，今幸鶱翔脫駭機。", "曉樹好風鶯獨語，夜窗細雨燕相依。", "安居不恨蝸廬迮，得食寧論鶴料微。", "更喜暮年彊健在，又看刀尺製縑衣。"]'),
('1e623fd3-355b-4a64-abf8-25d58a92dc53','初夏幽居偶題四首  其四','陸游','宋','宋诗','song-poetry','','[]','朱櫻羊酪喜新嘗，碧井桐陰轉午凉。',64,'全唐诗/poet.song.131000.json','["朱櫻羊酪喜新嘗，碧井桐陰轉午凉。", "書几得晴宜試墨，衣篝因潤稱熏香。", "枯龜自覺支床穩，老馬安能試草長。", "半世學騷終不近，空餘清夢上沅湘。"]'),
('192e3fe4-8351-496d-b2a2-963f40cb787f','晨起','陸游','宋','宋诗','song-poetry','','[]','青青水中萍，粲粲牆下草。',96,'全唐诗/poet.song.131000.json','["青青水中萍，粲粲牆下草。", "開歲纔幾時，已嘆春事老。", "鳴禽傍窗戶，怪我倦幽討。", "長吟感人懷，病枕起亦早。", "下床呼獠奴，浩蕩恣灑掃。", "綠陰列蒼石，芳樽得頻倒。", "客來但與飲，談天有何好。", "亦莫雕肺肝，吟哦學郊島。"]'),
('8ee6a059-ea36-4655-b6f2-9dfe56cd5855','小圃','陸游','宋','宋诗','song-poetry','','[]','剡曲西邊筑草堂，小園聊復寄相羊。',64,'全唐诗/poet.song.131000.json','["剡曲西邊筑草堂，小園聊復寄相羊。", "魚行水際汀蘋動，麝過林中野草香。", "覓句有時携筆硯，遣懷隨事具杯觴。", "少年朋舊凋零盡，不獨思人亦自傷。"]'),
('7b013b5a-93a5-48cd-8bb4-ab7abc85352d','幽居','陸游','宋','宋诗','song-poetry','','[]','青門不種故侯瓜，揀得湖山便寄家。',64,'全唐诗/poet.song.131000.json','["青門不種故侯瓜，揀得湖山便寄家。", "老境一廛依水竹，壯遊萬里犯風沙。", "氣衰那辦飲無算，病著更知生有涯。", "莫道吾廬全索寞，牆東新補數株花。"]'),
('d72d7f5b-e782-46c3-ac3b-eb872042e0a1','夜賦','陸游','宋','宋诗','song-poetry','','[]','小齋寂寂似禪寮，卧數更籌覺夜遥。',64,'全唐诗/poet.song.131000.json','["小齋寂寂似禪寮，卧數更籌覺夜遥。", "帳外殘燈欺不寐，梁間棲燕伴無聊。", "江湖蹭蹬朱顔改，憂患侵凌壯志消。", "挂旆天山少年事，此身終負聖明朝。"]'),
('38806b0e-cf93-4a1b-8c1e-f435281c7d0c','閑中書事二首  其一','陸游','宋','宋诗','song-poetry','','[]','病過新年逐日添，清愁殘醉兩厭厭。',64,'全唐诗/poet.song.131000.json','["病過新年逐日添，清愁殘醉兩厭厭。", "惜花萎去常遮日，待燕歸來始下簾。", "堂上清風生玉麈，澗中寒溜注銅蟾。", "一生留滯君休嘆，意望天公本自廉。"]'),
('82b213b9-2a53-4d33-8e03-bc026bf8035a','閑中書事二首  其二','陸游','宋','宋诗','song-poetry','','[]','一畝山園半畝池，流年忽逮挂冠期。',64,'全唐诗/poet.song.131000.json','["一畝山園半畝池，流年忽逮挂冠期。", "賣花醉叟剝紅桂，種藥高僧寄玉芝。", "午枕爲兒哦舊句，晚窗留客算殘棋。", "登庸策免多新報，老子癡頑總不知。"]'),
('d7b096b6-345f-4e84-a5ea-5ae6010a445f','初夏十首  其一','陸游','宋','宋诗','song-poetry','','[]','紛紛紅紫已成塵，布穀聲中夏令新。',32,'全唐诗/poet.song.131000.json','["紛紛紅紫已成塵，布穀聲中夏令新。", "夾路桑麻行不盡，始知身是太平人。"]'),
('7f60eacc-83b6-45bc-9acb-89b243e6eb33','初夏十首  其二','陸游','宋','宋诗','song-poetry','','[]','翦韭腌齏粟作漿，新炊麥飯滿村香。',32,'全唐诗/poet.song.131000.json','["翦韭腌齏粟作漿，新炊麥飯滿村香。", "先生醉後騎黄犢，北陌東阡看戲場。"]'),
('e557180a-2ed0-429c-a639-6559ac7460be','初夏十首  其三','陸游','宋','宋诗','song-poetry','','[]','稻未分秧麥已秋，豚蹄不用祝甌窶。',32,'全唐诗/poet.song.131000.json','["稻未分秧麥已秋，豚蹄不用祝甌窶。", "老翁七十猶彊健，沒膝春泥夜叱牛。"]'),
('3bb34237-2966-4043-b5a6-790e4ef6ede7','初夏十首  其四','陸游','宋','宋诗','song-poetry','','[]','買得新船疾似飛，蠶饑遥望采桑歸。',32,'全唐诗/poet.song.131000.json','["買得新船疾似飛，蠶饑遥望采桑歸。", "越羅蜀錦吾何用，且備豳人卒歲衣。"]'),
('20895315-acfe-4258-aba5-8e6acf5745fe','初夏十首  其五','陸游','宋','宋诗','song-poetry','','[]','槐柳成陰雨洗塵，櫻桃乳酪併嘗新。',32,'全唐诗/poet.song.131000.json','["槐柳成陰雨洗塵，櫻桃乳酪併嘗新。", "古來江左多佳句，夏淺勝春最可人。"]'),
('04000228-ad7f-41f3-953d-7da4e6e91b23','初夏十首  其六','陸游','宋','宋诗','song-poetry','','[]','杜鵑血盡啼未歇，蝴蝶夢殘心更狂。',32,'全唐诗/poet.song.131000.json','["杜鵑血盡啼未歇，蝴蝶夢殘心更狂。", "我自人間少情者，老來十倍惜年光。"]'),
('ff328163-b067-4218-8f6d-7542b788801e','初夏十首  其七','陸游','宋','宋诗','song-poetry','','[]','賜食金盤出寶閨，玄熊掌映紫駝蹄。',32,'全唐诗/poet.song.131000.json','["賜食金盤出寶閨，玄熊掌映紫駝蹄。", "侯家但詫承恩澤，豈識山厨苦荬齏。"]'),
('32d27d5a-8a4d-49b2-9ab7-ada68765e72b','初夏十首  其八','陸游','宋','宋诗','song-poetry','','[]','隋家古寺郡西南，寺廢殘僧只二三。',32,'全唐诗/poet.song.131000.json','["隋家古寺郡西南，寺廢殘僧只二三。", "藜藿滿庭塵闇佛，時聞鐃鼓賽春蠶。"]'),
('134f7da7-c685-449e-9289-7fdf3780f88b','初夏十首  其九','陸游','宋','宋诗','song-poetry','','[]','渺渺荒陂古埭東，柳姑小廟柳陰中。',32,'全唐诗/poet.song.131000.json','["渺渺荒陂古埭東，柳姑小廟柳陰中。", "放翁老憊扶藜杖，也逐鄉人禱歲豐。"]'),
('050afd59-1731-49d3-99c3-47dbd02921ae','初夏十首  其一○','陸游','宋','宋诗','song-poetry','','[]','老翁賣卜古城隅，兼寫宜蠶保麥符。',32,'全唐诗/poet.song.131000.json','["老翁賣卜古城隅，兼寫宜蠶保麥符。", "日日得錢惟買酒，不愁醉倒有兒扶。"]'),
('31e27c27-a74d-4fb7-a973-a9254342d229','四月旦作時立夏已十餘日','陸游','宋','宋诗','song-poetry','','[]','京塵相值各匆忙，誰信閑人日月長。',64,'全唐诗/poet.song.131000.json','["京塵相值各匆忙，誰信閑人日月長。", "爭葉蠶饑鬧風雨，趁虛茶懶鬭旗槍。", "林中晚筍供厨美，庭下新桐覆井凉。", "堪笑山家太早計，已陳竹几與藤床。"]'),
('44ace8f0-d829-4be8-9c10-5d97a69b3b54','春夏之交鳴鳥百族惟布穀聲最悲急動人戲作十韵','陸游','宋','宋诗','song-poetry','','[]','春風捨人去，陸子嘆以驚。',120,'全唐诗/poet.song.131000.json','["春風捨人去，陸子嘆以驚。", "欲挽春使回，無奈布穀聲。", "春亦何負汝，旦暮聲不停。", "或謂布穀者，一氣感使鳴。", "春老自當去，微禽彼何情。", "上天運四時，斗柄亦崢嶸。", "奈何獨私春，欲使久不傾。", "南風吹眾綠，一掃紫與赬。", "此時豈不佳，乃爾懷不平。", "勿作兒女態，起視東郊耕。"]'),
('4d6d4768-d5de-404b-8da2-d05043ff79c7','倚杖','陸游','宋','宋诗','song-poetry','','[]','倚杖柴門外，踟躕到日斜。',48,'全唐诗/poet.song.131000.json','["倚杖柴門外，踟躕到日斜。", "兒童拾筍籜，婦女賣茶芽。", "掠岸過漁艇，隔籬聞緯車。", "年來詩料別，滿眼是桑麻。"]'),
('b79bea38-25ef-4daf-83b8-5a27c8f81b8d','野步','陸游','宋','宋诗','song-poetry','','[]','蝶舞蔬畦晚，鳩鳴麥野晴。',48,'全唐诗/poet.song.131000.json','["蝶舞蔬畦晚，鳩鳴麥野晴。", "就陰時小息，尋徑復微行。", "村婦窺籬看，山翁拂席迎。", "市朝那有此，一笑慰餘生。"]'),
('b81170ff-9d3c-4a16-a875-bca669f4a1fb','竹窗晝眠','陸游','宋','宋诗','song-poetry','','[]','初夏暑雨薄，但覺白日長。',96,'全唐诗/poet.song.131000.json','["初夏暑雨薄，但覺白日長。", "向來萬里心，盡付一竹床。", "新筍出林表，森然羽林槍。", "時聞解籜聲，靈府生清凉。", "平生喜晝眠，此志晚乃償。", "安枕了無夢，孰爲蝶與莊。", "徐起掬寒泉，中有菱絲香。", "清嘯送落日，與世永相忘。"]'),
('9194c6e0-169f-4875-8ffe-ba7cad3dc85e','騰騰','陸游','宋','宋诗','song-poetry','','[]','騰騰吾喪我，兀兀我忘吾。',48,'全唐诗/poet.song.131000.json','["騰騰吾喪我，兀兀我忘吾。", "萬事皆墮甑，一身真朽株。", "江天號鸛鶴，村巷暗楸梧。", "薄酒猶堪醉，歸來稚子扶。"]'),
('19d90340-d0ea-4113-9fc4-631a95a541df','幽棲二首  其一','陸游','宋','宋诗','song-poetry','','[]','閑人了無事，地僻稱幽棲。',51,'全唐诗/poet.song.131000.json','["閑人了無事，地僻稱幽棲。", "{臼市}米留雞食，移琴避燕泥。", "桐生窗欲暗，筍長徑還迷。", "不作容車計，門閭儘放低。"]'),
('d2b914c7-ade5-4f7a-9e73-60930d8f23ef','幽棲二首  其二','陸游','宋','宋诗','song-poetry','','[]','誰謂幽棲陋，茅茨足庇床。',48,'全唐诗/poet.song.131000.json','["誰謂幽棲陋，茅茨足庇床。", "雨便梧葉大，風度楝花香。", "浴佛兒童喜，繅絲婦女忙。", "朅來三十載，吾鬢固宜霜。"]'),
('b58d0f45-5419-4220-b87c-f8405222b0b5','睡起','陸游','宋','宋诗','song-poetry','','[]','虛堂四簷竹修修，朱夏正午如高秋。',96,'全唐诗/poet.song.131000.json','["虛堂四簷竹修修，朱夏正午如高秋。", "八尺風漪雲碧裯，一榻寬如禹九州。", "屈信展轉俱自由，息以兩踵無與喉。", "世方窘若魚吞鈎，我獨超然鷹脫韝。", "一物不向靈臺留，非睡非覺以神遊。", "青城紫閣多朋儔，相逢握手笑不休。"]'),
('ef86020a-99a1-4f03-8553-46f26850f9e0','愁坐忽思南鄭小益之間二首  其一','陸游','宋','宋诗','song-poetry','','[]','當年蜀道秦關，萬里飄然往還。',28,'全唐诗/poet.song.131000.json','["當年蜀道秦關，萬里飄然往還。", "酒病曾留西縣，眼明初見南山。"]'),
('66c90ad9-209e-44ea-b28d-627563302e92','愁坐忽思南鄭小益之間二首  其二','陸游','宋','宋诗','song-poetry','','[]','籌筆門前芳草，回龍道上青山。',28,'全唐诗/poet.song.131000.json','["籌筆門前芳草，回龍道上青山。", "萬里猶能夢到，再遊未信天慳。"]'),
('02ca6b85-580b-4733-9f2c-4ef7205b9152','四月十三夜四更起讀書','陸游','宋','宋诗','song-poetry','','[]','七十未捐書，正恐死乃息。',24,'全唐诗/poet.song.131000.json','["七十未捐書，正恐死乃息。", "起挑窗下燈，度此風雨夕。"]'),
('f7e69721-5875-4c47-b29e-7938f32ce71b','夏雨初霽題齋壁','陸游','宋','宋诗','song-poetry','','[]','楸花楝花照眼明，幽人浴罷葛衣輕。',64,'全唐诗/poet.song.131000.json','["楸花楝花照眼明，幽人浴罷葛衣輕。", "燕低去地不盈尺，鵲喜傍簷時數聲。", "對弈軒窗消永晝，曬絲院落喜新晴。", "忽驚重五無多日，采縷纏筒吊屈平。"]'),
('bccb6d70-19f2-4f6f-a3a2-e19d326cb438','東窗','陸游','宋','宋诗','song-poetry','','[]','萱草石榴相續開，數枝晚筍破蒼苔。',32,'全唐诗/poet.song.131000.json','["萱草石榴相續開，數枝晚筍破蒼苔。", "背人紅練穿林去，直是無情不再來。"]'),
('86515663-b0e2-4642-9365-8e9d247b2152','聞梟','陸游','宋','宋诗','song-poetry','','[]','兩忘堯桀自心平，此念胡爲掃復生。',32,'全唐诗/poet.song.131000.json','["兩忘堯桀自心平，此念胡爲掃復生。", "幸是安眠無一事，苦憐鶯語惡梟聲。"]'),
('9f0f7bf7-fa31-47f8-9227-5d649c51667b','雨中示子聿','陸游','宋','宋诗','song-poetry','','[]','窮閻父子自相依，寂寂茅廬映竹扉。',64,'全唐诗/poet.song.131000.json','["窮閻父子自相依，寂寂茅廬映竹扉。", "瓜蔓水生初抹岸，楝花寒動却添衣。", "吾玄自笑豈尚白，汝瘦元知能勝肥。", "苦學勿爲干祿計，宦途雖樂不如歸。"]'),
('42109f42-e58b-451d-b29e-1fe5331f6571','山園屢種楊梅皆不成枇杷一株獨結實可愛戲作長句','陸游','宋','宋诗','song-poetry','','[]','楊梅空有樹團團，却是枇杷解滿盤。',64,'全唐诗/poet.song.131000.json','["楊梅空有樹團團，却是枇杷解滿盤。", "難學權門堆火齊，且從公子拾金丸。", "枝頭不怕風摇落，地上惟憂鳥啄殘。", "清曉呼僮乘露摘，任教半熟雜甘酸。"]'),
('94f73201-124c-41be-97b8-f71c186aeacd','夢遊山寺焚香煮茗甚適既覺悵然以詩記之','陸游','宋','宋诗','song-poetry','','[]','平日居山恨不深，暫來差足慰幽尋。',64,'全唐诗/poet.song.131000.json','["平日居山恨不深，暫來差足慰幽尋。", "僧歸共說道逢虎，院靜惟聞風滿林。", "毫盞雪濤驅滯思，篆盤雲縷洗塵襟。", "此行殊勝邯鄲客，數刻清閑直萬金。"]'),
('e8934c82-09be-47e2-9385-6e12bc76d72e','夏日','陸游','宋','宋诗','song-poetry','','[]','柴扉晝掩竹林幽，坐使炎天變素秋。',64,'全唐诗/poet.song.131000.json','["柴扉晝掩竹林幽，坐使炎天變素秋。", "扇月團團似初滿，簟波細細欲平流。", "朋儕零落關河阻，疾病沉綿歲月遒。", "賴有澄湖常在眼，虎頭不用畫滄洲。"]'),
('8de474e6-9603-4f0e-8754-ce1bd3487557','巢山二首  其一','陸游','宋','宋诗','song-poetry','','[]','巢山避世紛，身隱萬重雲。',48,'全唐诗/poet.song.131000.json','["巢山避世紛，身隱萬重雲。", "半谷傳樵響，中林過鹿群。", "蟲鎪葉成篆，風蹙水生紋。", "不蹋溪橋路，僊凡自此分。"]'),
('f6b85c3c-64d2-43b7-80d6-1781c9ab67b5','巢山二首  其二','陸游','宋','宋诗','song-poetry','','[]','短髮巢山客，人知姓字誰。',48,'全唐诗/poet.song.131000.json','["短髮巢山客，人知姓字誰。", "穿林雙不借，取水一軍持。", "渴鹿群窺澗，驚猿獨裊枝。", "何曾畜筆硯，景物自成詩。"]'),
('7cf41c30-e2ab-4b40-9b55-328ac3e175a8','四月二十三日作二首  其一','陸游','宋','宋诗','song-poetry','','[]','颭颭荷離水，翩翩燕出巢。',48,'全唐诗/poet.song.131000.json','["颭颭荷離水，翩翩燕出巢。", "苔添雨後暈，筍放露中梢。", "世路千重浪，生涯一把茅。", "款門僧亦絕，無句鍊推敲。"]'),
('eb912385-0a5e-4ffd-b907-f180338df70b','四月二十三日作二首  其二','陸游','宋','宋诗','song-poetry','','[]','莫笑茅廬迮，何曾厭日長。',48,'全唐诗/poet.song.131000.json','["莫笑茅廬迮，何曾厭日長。", "飯餘餐酪滑，浴罷葛巾凉。", "落日桐陰轉，微風梔子香。", "貧家猶裹粽，隨事答年光。"]'),
('432050bc-1c05-410e-8611-4c5f3cfa24a2','觀月','陸游','宋','宋诗','song-poetry','','[]','清風發疏林，皦月上素壁。',48,'全唐诗/poet.song.131000.json','["清風發疏林，皦月上素壁。", "悠然倚庭楯，愛此風月夕。", "人間好時節，俯仰成宿昔。", "少年不痛飲，老大空嘆息。"]'),
('7972534d-489f-4eed-8a8b-a8a6b5e1ba07','溽暑','陸游','宋','宋诗','song-poetry','','[]','溽暑雨將作，南風來解圍。',48,'全唐诗/poet.song.131000.json','["溽暑雨將作，南風來解圍。", "幽花臨砌坼，乳燕傍巢飛。", "腰斧剶桑去，携籃采藥歸。", "翻憐少年老，疊雪詫宮衣。"]'),
('6c0abf72-4381-44d1-8779-f011d9de10e2','晨起','陸游','宋','宋诗','song-poetry','','[]','衰老少睡眠，睡晚覺常早。',48,'全唐诗/poet.song.131000.json','["衰老少睡眠，睡晚覺常早。", "五更攬衣起，漏鼓猶考考。", "青燈耿孤影，不睡坐亦好。", "讀盡一編書，南窗朝日杲。"]'),
('d7e6438b-5ab7-4fd7-aa71-575a748f4897','閑思二首  其一','陸游','宋','宋诗','song-poetry','','[]','溝水細無聲，窗扉晚更明。',48,'全唐诗/poet.song.131000.json','["溝水細無聲，窗扉晚更明。", "簾開燕雙入，人靜鵲群行。", "青李求初至，黄醅釀已成。", "出門無奈懶，不是傲公卿。"]'),
('b71659bb-136a-4794-81cc-4c5f63670f0a','閑思二首  其二','陸游','宋','宋诗','song-poetry','','[]','小雨時時作，幽花續續紅。',48,'全唐诗/poet.song.131000.json','["小雨時時作，幽花續續紅。", "新蟬落庭樹，癡燕集屏風。", "傍枕拋書卷，臨池下釣筒。", "閑中有真樂，那得難途窮。"]'),
('f0ae648a-c479-4f0f-b0d2-6e9ff66e28c1','梅天','陸游','宋','宋诗','song-poetry','','[]','稻隴移初遍，梅天澀未晴。',48,'全唐诗/poet.song.131000.json','["稻隴移初遍，梅天澀未晴。", "輕陰昏茗色，餘潤咽琴聲。", "時傍菱塘立，還尋沙徑行。", "杜門終此世，更誓未來生。"]'),
('74054eb8-a45c-4b2a-b741-a6034e0a10c7','夜坐','陸游','宋','宋诗','song-poetry','','[]','燈暗一室幽，鳥鳴四山靜。',72,'全唐诗/poet.song.131000.json','["燈暗一室幽，鳥鳴四山靜。", "道人坐倚壁，度此清夜永。", "少時志功名，癡絕如捕影。", "造物遺以窮，磨礱發深省。", "坐令盆盎淺，渺渺波萬頃。", "雖未造道真，南轅終至郢。"]'),
('38e40f66-b1bf-4860-aa42-d416cf2b98c6','麥熟市米價減鄰里病者亦皆愈欣然有賦','陸游','宋','宋诗','song-poetry','','[]','兇年已度麥方秋，學道從來幸寡求。',64,'全唐诗/poet.song.131000.json','["兇年已度麥方秋，學道從來幸寡求。", "荷鍤自隨身若寄，漉籬可賣飯何憂。", "鄰翁瀕死復相見，村市小凉時獨遊。", "不怕歸時又侵夜，新添略彴跨清溝。"]'),
('55b9ae21-d887-42c5-be5f-4e5b6067384c','雨中作','陸游','宋','宋诗','song-poetry','','[]','風聲如翻濤，雨點如撒菽。',72,'全唐诗/poet.song.131000.json','["風聲如翻濤，雨點如撒菽。", "皇天念此老，一爲洗煩促。", "呼童取短檠，聊展舊書讀。", "凄然對孤影，感嘆衰鬢禿。", "兀如老病馬，關河久在目。", "伏櫪雖已疲，連雲思苜蓿。"]'),
('e163a078-6c3b-46a9-9be5-846505e63f7b','夜雨','陸游','宋','宋诗','song-poetry','','[]','齒牙摇動鬢毛疏，四壁蕭然卧草廬。',64,'全唐诗/poet.song.131000.json','["齒牙摇動鬢毛疏，四壁蕭然卧草廬。", "急雨聲酣戰叢竹，孤燈焰短伴殘書。", "壯心未減從戎日，苦學猶如覓舉初。", "自笑堅頑誰得似，同儕太半已丘墟。"]'),
('7355a038-267d-4ad9-9fd8-d7b3b5546dac','乙卯重五','陸游','宋','宋诗','song-poetry','','["\u98ce\u4fd7", "\u7aef\u5348\u8282"]','重五山村好，榴花忽已繁。',48,'全唐诗/poet.song.131000.json','["重五山村好，榴花忽已繁。", "粽包分兩髻，艾束著危冠。", "舊俗方儲藥，羸軀亦點丹。", "日斜吾事畢，一笑向杯盤。"]'),
('abcfba66-557b-468c-9156-0f93470496bb','夏夜風雨極凉枕上口占','陸游','宋','宋诗','song-poetry','','[]','北窗八尺卧文藤，夜雨生凉洗鬰蒸。',64,'全唐诗/poet.song.131000.json','["北窗八尺卧文藤，夜雨生凉洗鬰蒸。", "裊裊清愁縈斷角，悠悠孤夢伴殘燈。", "羸軀垂老嗟焉往，公論猶存似可憑。", "聊向斯文圖不朽，未甘粥飯學山僧。"]'),
('f7739d3f-3522-46ee-8ed6-7d833481c227','窮居','陸游','宋','宋诗','song-poetry','','[]','半世倀倀信所之，窮居仍抱暮年悲。',64,'全唐诗/poet.song.131000.json','["半世倀倀信所之，窮居仍抱暮年悲。", "燒金術誤囊衣薄，種黍年兇酒味醨。", "大厦萬間空有志，後車千乘更無期。", "掩書常笑城南杜，麻屨還朝授拾遺。"]'),
('15cfa838-7fe2-43ff-8d35-beefd0915dd4','思蜀','陸游','宋','宋诗','song-poetry','','[]','白首躬耕遇洊饑，江南自笑欲疇依。',64,'全唐诗/poet.song.131000.json','["白首躬耕遇洊饑，江南自笑欲疇依。", "凌烟勳業無人許，濯錦園林有夢歸。", "心似遊僧思遠適，身如敗將陷重圍。", "客來彊欲相寬釋，每說人生七十稀。"]'),
('32abdd4d-19b3-4263-9a88-4ad97f86a783','五月二十三夜記夢','陸游','宋','宋诗','song-poetry','','[]','夜漏欲盡雞初唱，夢到神仙信非妄。',160,'全唐诗/poet.song.131000.json','["夜漏欲盡雞初唱，夢到神仙信非妄。", "泉流直舂碧澗底，松根橫走蒼崖上。", "徐行林際遇飛橋，峭壁驚濤臨萬丈。", "非惟履嶮足踸踔，已覺處憂神悄愴。", "空巖滴乳久化石，寶蓋珠瓔紛物象。", "鬼神慘澹疑欲搏，龍蜃蜿蜒誰敢傍。", "長眉老仙乘白雲，握手授我綠玉杖。", "三生汝有世外緣，一念已斷塵中障。", "雖云曩事不復憶，憐汝瞳子神猶王。", "何須更待熟金丹，從我歸哉住崑閬。"]'),
('e646a414-748f-4270-9cd7-5a00159f3daf','送葉尚書','陸游','宋','宋诗','song-poetry','','[]','曩歲榜扁舟，萬里歸自蜀。',192,'全唐诗/poet.song.131000.json','["曩歲榜扁舟，萬里歸自蜀。", "五月下瞿唐，六月過浮玉。", "於時始識公，一笑忘暑毒。", "羽扇臨清流，華觴跋紅燭。", "一別十五年，去日如電速。", "孤生晚還朝，斂退慚陸陸。", "要津非所冀，見公心自足。", "斥歸又七載，衰病將就木。", "造物哀其窮，公來位嶽牧。", "每見語諄諄，與世異寒燠。", "聖朝方急賢，登用及釣筑。", "如公實舊德，顧豈待夢卜。", "初聞一札下，已報四輩趣。", "懸知新天子，虛懷須啟沃。", "願公論其大，始爲天下福。", "即宣垂拱麻，寧復摛文宿。"]'),
('1a22201c-b291-49f8-ad67-5ee64bdf1b80','路傍曲三首  其一','陸游','宋','宋诗','song-poetry','','[]','冷飯雜沙礫，短褐蒙霜露。',24,'全唐诗/poet.song.131000.json','["冷飯雜沙礫，短褐蒙霜露。", "黄葉滿山郵，行人跨驢去。"]'),
('8a85734c-4df6-4065-8a4b-ab86f5c3efc4','路傍曲三首  其二','陸游','宋','宋诗','song-poetry','','[]','大道南北出，車輪無停日。',24,'全唐诗/poet.song.131000.json','["大道南北出，車輪無停日。", "彼豈皆奇才，我獨饑至夕。"]'),
('38d243c7-1a93-4ea0-a3a7-b2de444d9528','路傍曲三首  其三','陸游','宋','宋诗','song-poetry','','[]','凄凉路傍曲，朱門人不知。',24,'全唐诗/poet.song.131000.json','["凄凉路傍曲，朱門人不知。", "秋街槐葉落，正是斷腸時。"]'),
('3347307e-6f7a-4c5b-b168-ed05ba56437d','贈汪叔潜','陸游','宋','宋诗','song-poetry','','[]','火雲嵯峨如疊嶂，百病攻衰非一狀。',96,'全唐诗/poet.song.131000.json','["火雲嵯峨如疊嶂，百病攻衰非一狀。", "低簷小屋桑竹村，忽辱君來問亡恙。", "蹶然攬衣起闖門，裹飯仍煩遠相餉。", "歲饑野外無供給，羞澀餘糧不盈盎。", "我守此窮三十年，尚恐死前無力量。", "君誠不以老棄予，苦語見規宜勿讓。"]'),
('562539df-ebfd-4098-abe2-e7f62d85a008','出遊','陸游','宋','宋诗','song-poetry','','[]','莫笑衰殘百不能，一枝筇杖捷飛騰。',64,'全唐诗/poet.song.131000.json','["莫笑衰殘百不能，一枝筇杖捷飛騰。", "山空野火焚秦篆，日澹烟蕪遍禹陵。", "小浦漲潮迎釣艇，疏鐘出谷送行僧。", "踟躕不覺歸途晚，村落人家已上燈。"]'),
('7e2bf7a0-b5f5-4fcc-8697-917c8a0ba795','立秋後四日雨','陸游','宋','宋诗','song-poetry','','[]','天爲新秋故作凉，海風吹雨入虛堂。',64,'全唐诗/poet.song.131000.json','["天爲新秋故作凉，海風吹雨入虛堂。", "凉生庭樹陰陰綠，潤襲篝衣浥浥香。", "杯泛鵝兒供小啜，碓舂雲子喜新嘗。", "一年又見星橋近，未信仙家日月長。"]'),
('f8291eec-6e08-4b59-84b1-af6431703bfe','夙興','陸游','宋','宋诗','song-poetry','','[]','老眼無眠覺夜長，攬衣不復待窗光。',64,'全唐诗/poet.song.131000.json','["老眼無眠覺夜長，攬衣不復待窗光。", "明星漸淡避初日，秋露已濃生曉凉。", "出草幽花紅紫雜，穿林啼鳥去來忙。", "是中有趣君知否，喧寂年來已兩忘。"]'),
('cc8d6633-8fd4-480b-a553-bd85a5b16c56','存養堂爲汪叔潜作','陸游','宋','宋诗','song-poetry','','[]','絳帳先生見處別，少年立節如冰雪。',96,'全唐诗/poet.song.131000.json','["絳帳先生見處別，少年立節如冰雪。", "胸中凜凜萬卷書，一字不爲庸人說。", "存心養性以事天，人知不知渠晏然。", "窮經日夜廢寢飯，不怕諸生嘲腹便。", "三旌五鼎俱忘想，致一工夫在存養。", "我今老病死即休，未死尚欲從公講。"]'),
('4c58afc5-253c-4a25-ba8a-c378d30649e6','感昔二首  其一','陸游','宋','宋诗','song-poetry','','[]','三著朝冠入上都，黄封頻醉渴相如。',64,'全唐诗/poet.song.131000.json','["三著朝冠入上都，黄封頻醉渴相如。", "馬慵立仗寧辭斥，蘭偶當門敢怨鋤。", "富貴尚思還此笏，衰殘故合愛吾廬。", "燈前目力依然在，且盡山房萬卷書。"]'),
('3c10d22a-0f82-4373-a19e-ba98d45717e7','感昔二首  其二','陸游','宋','宋诗','song-poetry','','[]','五丈原頭秋色新，當時許國欲忘身。',64,'全唐诗/poet.song.131000.json','["五丈原頭秋色新，當時許國欲忘身。", "長安之西過萬里，北斗以南惟一人。", "往事已如遼海鶴，餘年空羨葛天民。", "腰間白羽凋零盡，却照清溪整角巾。"]'),
('6405c21b-bf10-49f2-823c-4cd2a5e1b104','病稍平示兒輩','陸游','宋','宋诗','song-poetry','','[]','人與鴉俱曉，天憑雁送秋。',48,'全唐诗/poet.song.131000.json','["人與鴉俱曉，天憑雁送秋。", "極知生意盡，彊爲汝曹留。", "藥餌傾殘橐，風霜迫故裘。", "倚屏搔短髮，且復寄悠悠。"]'),
('092c7421-107c-4201-8a21-bbdd8d975fd2','野堂四首  其一','陸游','宋','宋诗','song-poetry','','[]','野堂蕭颯雪侵冠，歷盡人間行路難。',64,'全唐诗/poet.song.131000.json','["野堂蕭颯雪侵冠，歷盡人間行路難。", "病馬不收烟草暝，孤桐半落井床寒。", "長瓶濁酒猶堪醉，敗篋殘編更細看。", "此興不隨年共老，未容城角動憂端。"]'),
('f9a1d75b-a6f5-4ce8-8aff-b1fcc0a3406c','野堂四首  其二','陸游','宋','宋诗','song-poetry','','[]','姓名無復世人聞，靜處何妨獨策勳。',64,'全唐诗/poet.song.131000.json','["姓名無復世人聞，靜處何妨獨策勳。", "久矣不堪東閣客，歸哉無愧北山文。", "橫林霜近有丹葉，平野雨餘多斷雲。", "更喜鸕鶿來漸熟，一溪烟水與中分。"]'),
('6e3e4cff-fb67-4fb1-b1e4-ee867dffcb46','野堂四首  其三','陸游','宋','宋诗','song-poetry','','[]','野堂地僻無車馬，草徑柴門晝亦扃。',64,'全唐诗/poet.song.131000.json','["野堂地僻無車馬，草徑柴門晝亦扃。", "栗里雖貧儲舊粟，玉川終老抱遺經。", "病身凜凜殘秋葉，故友寥寥欲旦星。", "賴有吾兒堪暖眼，夜闌常共一燈青。"]'),
('47519331-47d0-45c1-9b37-28b49be0859a','野堂四首  其四','陸游','宋','宋诗','song-poetry','','[]','鼓缶酣歌樂太平，野堂窗戶極疏明。',64,'全唐诗/poet.song.131000.json','["鼓缶酣歌樂太平，野堂窗戶極疏明。", "棄官正爲愚無用，謝客新緣病有名。", "閑入鄉人賽神社，時從長者放魚行。", "歡然更有關心處，打稻家家趁晚晴。"]'),
('4f59d040-0603-4bec-901d-9541adcdf8f7','七月下旬得疾不能出戶者十有八日病起有賦','陸游','宋','宋诗','song-poetry','','[]','秋風吹海氛，氣候頗不令。',72,'全唐诗/poet.song.131000.json','["秋風吹海氛，氣候頗不令。", "昏昏七十翁，擾擾半月病。", "著書殊未成，即死目不瞑。", "扶持賴藥物，僅得全性命。", "雨添苔暈青，風入桐枝勁。", "深巷無人聲，搘頤發孤詠。"]'),
('5be14d26-f20f-4f74-ad08-cdc3c88cb34e','夢有餉地黄者味甘如蜜戲作數語記之','陸游','宋','宋诗','song-poetry','','[]','有客餉珍草，發奩驚絕奇。',96,'全唐诗/poet.song.131000.json','["有客餉珍草，發奩驚絕奇。", "正爾取嚼齕，炮製不暇施。", "異香透崑崙，清水生玉池。", "至味不可名，何止甘如飴。", "兒稚喜語翁，雪頷生黑絲。", "老病失所在，便欲棄杖馳。", "晨雞喚夢覺，齒頰餘甘滋。", "寄聲山中友，安用求金芝。"]'),
('ae4393a5-cb79-440a-a452-ec13075d0124','秋夜二首  其一','陸游','宋','宋诗','song-poetry','','[]','燈欲殘時酒半消，斷砧疏雨共無憀。',32,'全唐诗/poet.song.131000.json','["燈欲殘時酒半消，斷砧疏雨共無憀。", "老來萬事渾非昔，惟有詩情似灞橋。"]'),
('62d5358e-ffc2-4b2c-9717-28de7f15db0e','秋夜二首  其二','陸游','宋','宋诗','song-poetry','','[]','夜雨凄凉客思迷，聞砧却是夢回時。',32,'全唐诗/poet.song.131000.json','["夜雨凄凉客思迷，聞砧却是夢回時。", "人人解說悲秋事，不似詩人徹底知。"]'),
('5f4fa05e-31f8-4d6f-89ac-c97590f03e39','病起憊甚有嘆','陸游','宋','宋诗','song-poetry','','[]','殘年迫衰謝，一病不枝梧。',48,'全唐诗/poet.song.131000.json','["殘年迫衰謝，一病不枝梧。", "書倩傍人讀，行須稚子扶。", "冥心付天地，畢世釣江湖。", "無米博佳傳，虛名那可圖。"]'),
('9fd7c947-5539-42b8-90ed-8beed0e97441','小舟晚歸二首  其一','陸游','宋','宋诗','song-poetry','','[]','扶病尋溪友，忘憂泛釣槎。',48,'全唐诗/poet.song.131000.json','["扶病尋溪友，忘憂泛釣槎。", "渚寒無宿鷺，月白有啼鴉。", "敗壁青燈暗，幽窗稚子譁。", "無生未暇說，且復議桑麻。"]'),
('51c07f54-d782-490b-94e5-764c1b7ac533','小舟晚歸二首  其二','陸游','宋','宋诗','song-poetry','','[]','秋晚吾廬好，柴門映斷山。',48,'全唐诗/poet.song.131000.json','["秋晚吾廬好，柴門映斷山。", "潮生魚箔短，木落雉媒閑。", "繚堞蒼茫外，漁舟浩蕩間。", "客來常謝病，老鈍耐嘲訕。"]'),
('8aac5618-4265-41d5-a0c3-4ee2c2f9b440','夜坐','陸游','宋','宋诗','song-poetry','','[]','老眼清無寐，孤懷默自傷。',48,'全唐诗/poet.song.131000.json','["老眼清無寐，孤懷默自傷。", "思人交舊盡，撫事歲時長。", "籬犬吠殘月，江楓凋早霜。", "放翁殊耐事，掩卷撥爐香。"]'),
('de0645f4-2a44-4158-8e5b-92b294299c1f','幽事','陸游','宋','宋诗','song-poetry','','[]','老夫病起日支離，幽事關心只自知。',64,'全唐诗/poet.song.131000.json','["老夫病起日支離，幽事關心只自知。", "社近鄰翁饋新釀，客歸童子拾殘棋。", "功名已付來生了，筆墨尤非晚歲宜。", "餘習可憐除未盡，移花引水伴兒嬉。"]'),
('c443e387-c291-4e44-92bb-1ed2a576d0d9','病後衰甚非籃輿不能出門感嘆有賦','陸游','宋','宋诗','song-poetry','','[]','酒興詩情尚自如，形骸可怪頓成疏。',64,'全唐诗/poet.song.131000.json','["酒興詩情尚自如，形骸可怪頓成疏。", "平生只倚雙鳧舄，此日常須一鹿車。", "寂寂豈惟慚鄧禹，厭厭更覺類曹蜍。", "晚窗弄筆聊湔祓，數首清詩手自書。"]'),
('e0e66744-e8fd-44e7-8d94-c08e5ce06386','秋思','陸游','宋','宋诗','song-poetry','','[]','人生四十嘆頭顱，久矣心知負壯圖。',64,'全唐诗/poet.song.131000.json','["人生四十嘆頭顱，久矣心知負壯圖。", "未死皆爲閑日月，無求儘有醉工夫。", "風凋木葉流年晚，秋入窗扉病骨蘇。", "信步出門湖萬頃，季鷹不用憶蓴鱸。"]'),
('683ff255-9786-421d-a894-b5380d579bfb','題村店壁','陸游','宋','宋诗','song-poetry','','[]','五十年來命壓頭，即今殘髮不禁愁。',64,'全唐诗/poet.song.131000.json','["五十年來命壓頭，即今殘髮不禁愁。", "亂鴉陣起霜天晚，落葉聲乾古渡秋。", "小市啜醨聊兀傲，長亭秣蹇得遲留。", "一身自處窮如許，幸是無因爲國謀。"]'),
('f817e594-959c-44db-9c07-23fca170e1db','病去','陸游','宋','宋诗','song-poetry','','[]','病去身差健，秋高氣漸寒。',48,'全唐诗/poet.song.131000.json','["病去身差健，秋高氣漸寒。", "未甘常伏几，時作一憑闌。", "玉粒炊粳軟，香塵搗藥殘。", "欣然顧兒輩，燈下語團欒。"]'),
('58b38c1b-b0e1-45cf-8df2-c0f730c25d1f','白首','陸游','宋','宋诗','song-poetry','','[]','白首稱祠吏，清時作幸民。',48,'全唐诗/poet.song.131000.json','["白首稱祠吏，清時作幸民。", "招呼林下客，遊戲夢中身。", "山路烏騾穩，烟波畫檝新。", "村村有花柳，無事即尋春。"]'),
('798c831e-9e5c-4282-98d4-d95ee1124bbf','書病','陸游','宋','宋诗','song-poetry','','[]','暮年雖病不甚劇，啜藥噉粥猶自力。',128,'全唐诗/poet.song.131000.json','["暮年雖病不甚劇，啜藥噉粥猶自力。", "今年七月風眩作，兒子在前不能識。", "杯中藥冷呼不醒，全家相顧無人色。", "昏昏但思向壁卧，蟲臂鼠肝寧暇恤。", "醫巫技殫欲斂手，天高鬼惡吁莫測。", "偶然得活出望外，扶杖下床猶屢踣。", "讀書心在目力短，袖手堅坐到窗黑。", "無功祿食四十年，嘆息此責何由塞。"]'),
('7057f9ee-6815-429a-8631-10248739e51b','舍北晚眺二首  其一','陸游','宋','宋诗','song-poetry','','[]','紅樹青林带暮烟，並橋常有賣魚船。',32,'全唐诗/poet.song.131000.json','["紅樹青林带暮烟，並橋常有賣魚船。", "樊川詩句營丘畫，盡在先生拄杖邊。"]'),
('6b030052-f77a-42c4-8c08-d9dd9fdd972c','舍北晚眺二首  其二','陸游','宋','宋诗','song-poetry','','[]','日日津頭繫小舟，老人自懶出門遊。',32,'全唐诗/poet.song.131000.json','["日日津頭繫小舟，老人自懶出門遊。", "一枝筇杖疏籬外，占斷千巖萬壑秋。"]'),
('f51d91de-e736-4c15-9046-7f8ba81de6d4','夜閱篋中書偶得李德遠數帖因思昔相從時所言後多可驗感嘆有作','陸游','宋','宋诗','song-poetry','','[]','早歲傳聞月旦評，殿門邂逅眼偏明。',64,'全唐诗/poet.song.131000.json','["早歲傳聞月旦評，殿門邂逅眼偏明。", "當時一坐推談止，今日叢林見話行。", "老卧烟村身偶在，夜開蠹紙泪如傾。", "豈知三十餘年後，河洛胡塵訖未平。"]'),
('7db7080c-38f8-4df7-b8ce-76f3d6a5a8ed','登東山','陸游','宋','宋诗','song-poetry','','[]','漆園傲吏養生主，栗里高人歸去來。',64,'全唐诗/poet.song.131000.json','["漆園傲吏養生主，栗里高人歸去來。", "俱作放翁新受用，不妨平地脫塵埃。", "松崖壁立臨樵塢，竹徑蛇蟠上嘯臺。", "送盡夕陽山更好，與君踏月浩歌回。"]'),
('ab6386d5-a847-48fd-a3dc-cba8a00260e9','貧樂','陸游','宋','宋诗','song-poetry','','[]','蕭然曲肱地，自號直心翁。',48,'全唐诗/poet.song.131000.json','["蕭然曲肱地，自號直心翁。", "拙宦三災過，勞生一笑空。", "新蔬經雨綠，晚稻得霜紅。", "飽食真無事，浩歌明月中。"]'),
('39c1f55c-df06-4d9b-ada6-3693054444c3','乙卯重九','陸游','宋','宋诗','song-poetry','','[]','九日村醅熟，逢迎不用呼。',48,'全唐诗/poet.song.131000.json','["九日村醅熟，逢迎不用呼。", "樽前狂起舞，陌上醉相扶。", "殘髮新霜白，衰顔落葉枯。", "明年何足問，且復插茱萸。"]'),
('1212d4f7-e0ca-4407-a04d-9d3bdb211022','縱步近村','陸游','宋','宋诗','song-poetry','','[]','病去身輕試杖藜，滿村蕎麥正離離。',64,'全唐诗/poet.song.131000.json','["病去身輕試杖藜，滿村蕎麥正離離。", "照溪自嘆尚微瘦，趁渡人言殊未衰。", "草塞瓶頭沽濁酒，花簪笠頂引群兒。", "裴回不恨歸差晚，正愛青燈映竹籬。"]'),
('83355d16-e255-47be-9a5e-da6cf8239f62','題齋壁','陸游','宋','宋诗','song-poetry','','[]','看盡人間利與名，歸來始覺此身輕。',64,'全唐诗/poet.song.131000.json','["看盡人間利與名，歸來始覺此身輕。", "禍機不敗漁舟興，樂事渾輸地碓聲。", "破篋雖無衣可典，寒畦已有芋堪烹。", "餘年且健貧何害，剩與鄰翁醉太平。"]'),
('32923298-d44b-45af-90e5-0f389e40f276','范參政挽詞二首  其一','陸游','宋','宋诗','song-poetry','','[]','屢出專戎閫，遄歸上政途。',48,'全唐诗/poet.song.131000.json','["屢出專戎閫，遄歸上政途。", "勳勞光竹帛，風采震羌胡。", "籤帙新藏富，園林勝事殊。", "知公僊去日，遺恨一毫無。"]'),
('d0b82aef-b0eb-406d-a7af-9af00a749ab8','范參政挽詞二首  其二','陸游','宋','宋诗','song-poetry','','[]','孤拙知心少，平生僅數公。',48,'全唐诗/poet.song.131000.json','["孤拙知心少，平生僅數公。", "凋零遂無幾，遲暮與誰同。", "瓊樹世塵外，神山雲海中。", "夢魂寧復接，慟哭向西風。"]'),
('22af4ff6-6c5d-4d11-abcc-2671f651e9dd','病後往來湖山間戲書','陸游','宋','宋诗','song-poetry','','[]','周公居東三食新，夷吾在魯丘厄陳。',128,'全唐诗/poet.song.131000.json','["周公居東三食新，夷吾在魯丘厄陳。", "聖賢憂患尚如此，况我本是羈窮人。", "今秋危病輒不死，餘業自笑堅頑身。", "結茅所幸得佳處，石帆天鏡無纖塵。", "捫蘿峭壁上采藥，腰斧長歌行負薪。", "尋僧獨泛若耶月，携友共采湘湖蓴。", "蠡亡範金陋勾踐，斯頌刻石憎嬴秦。", "不如一酹禹祠去，惡衣菲食真吾鄰。"]'),
('bbf49850-be01-40bc-becf-af88801b29b3','秋夜遣懷','陸游','宋','宋诗','song-poetry','','[]','六年歸卧水雲鄉，本自無閑可得忙。',64,'全唐诗/poet.song.131000.json','["六年歸卧水雲鄉，本自無閑可得忙。", "羸病豈知身尚健，迂疏真與世相忘。", "霜清水落年華晚，月黑梟鳴夜漏長。", "瑣瑣井蛙何足計，一篇秋水笑蒙莊。"]'),
('4d3f5240-c27b-4e62-b164-aa53ef5b4501','初冬暄甚','陸游','宋','宋诗','song-poetry','','[]','吳中十月雪霜慳，風景暄妍葉未殷。',64,'全唐诗/poet.song.131000.json','["吳中十月雪霜慳，風景暄妍葉未殷。", "杲日還看浴東海，薄雲不解冒南山。", "蛙鳴閤閤荒池曲，蠅出營營食案間。", "安得玄冥正時令，紅爐綠酒一開顔。"]'),
('912c2781-a182-4778-873b-50389b1784de','贈湖上父老十八韵','陸游','宋','宋诗','song-poetry','','[]','一鏡三百里，環以碧玉峰。',216,'全唐诗/poet.song.131000.json','["一鏡三百里，環以碧玉峰。", "天公賜我厚，極目爲提封。", "烟收見石帆，雨霽望卧龍。", "嵯峨寶林塔，迢遞天章鍾。", "興來思一出，霜晴及初冬。", "父老捨杖迎，衣冠頗嚴恭。", "語我相識久，幸未棄老農。", "間者傳伏枕，喜聞足音跫。", "貧舍有盤餐，勿責異味重。", "蕎餅新油香，黍酒甕面濃。", "已遣買撲握，亦可致噞喁。", "願公領此意，秣蹇聊從容。", "我起爲太息，厚意敢不從。", "吾生行逆境，平地九折邛。", "况今又老退，如子豈易逢。", "但願從今健，衰疾緩見攻。", "遇興即扣門，草具煩炊舂。", "但恐乘月來，妨子睡味濃。"]'),
('c91e5da5-2eaa-4bb8-8643-1fade9faf665','初冬感懷二首  其一','陸游','宋','宋诗','song-poetry','','[]','落葉掃還積，斷鴻飛更鳴。',48,'全唐诗/poet.song.131000.json','["落葉掃還積，斷鴻飛更鳴。", "羸軀得霜健，老眼向書明。", "水瘦河聲壯，萁枯馬力生。", "竟爲農父死，白首負功名。"]'),
('b91eb4d4-06a5-49a4-ab64-9bbe98097680','初冬感懷二首  其二','陸游','宋','宋诗','song-poetry','','[]','庭蕪失故綠，園樹染新丹。',48,'全唐诗/poet.song.131000.json','["庭蕪失故綠，園樹染新丹。", "病思閑支枕，詩情獨倚闌。", "带移頻覺瘦，貂弊不禁寒。", "惟有牆陰薺，離離又滿盤。"]'),
('faa05e41-de87-4cc2-b776-3c63c8baa5f6','讀杜詩','陸游','宋','宋诗','song-poetry','','[]','城南杜五少不羈，意輕造物呼作兒。',96,'全唐诗/poet.song.131000.json','["城南杜五少不羈，意輕造物呼作兒。", "一門酣法到孫子，熟視嚴武名挺之。", "看渠胸次隘宇宙，惜哉千萬不一施。", "空回英概入筆墨，生民清廟非唐詩。", "向令天開太宗業，馬周遇合非公誰。", "後世但作詩人看，使我撫几空嗟咨。"]'),
('256dc5f9-04b9-4559-93e1-d5052d6aef7d','記九月三十日夜半夢','陸游','宋','宋诗','song-poetry','','[]','一夢邯鄲亦壯哉，沙堤金轡絡龍媒。',64,'全唐诗/poet.song.131000.json','["一夢邯鄲亦壯哉，沙堤金轡絡龍媒。", "兩行畫戟森朱戶，十丈平橋夾綠槐。", "東閣群英鳴佩集，北庭大戰捷旗來。", "太平事業方施設，誰遣晨雞苦喚回。"]'),
('91ba704d-de6b-4983-84fa-dd3a0269ef89','小舟遊近村捨舟步歸四首  其一','陸游','宋','宋诗','song-poetry','','[]','數家茅屋自成村，地碓聲中晝掩門。',32,'全唐诗/poet.song.131000.json','["數家茅屋自成村，地碓聲中晝掩門。", "寒日欲沉蒼霧合，人間隨處有桃源。"]'),
('4f16e2dd-1bad-481a-bf4a-54b195e111ce','小舟遊近村捨舟步歸四首  其二','陸游','宋','宋诗','song-poetry','','[]','借得漁船泝小谿，繫船浦口却扶藜。',32,'全唐诗/poet.song.131000.json','["借得漁船泝小谿，繫船浦口却扶藜。", "莫言村落蕭條甚，也勝京塵沒馬蹄。"]'),
('b492b4d4-594f-4bf3-a5cd-9a5ecfc25d1d','小舟遊近村捨舟步歸四首  其三','陸游','宋','宋诗','song-poetry','','[]','不識如何喚作愁，東阡南陌且閑遊。',32,'全唐诗/poet.song.131000.json','["不識如何喚作愁，東阡南陌且閑遊。", "兒童共道先生醉，折得黄花插滿頭。"]'),
('6e32e312-0b7e-464b-8b7b-c82b16488fdd','小舟遊近村捨舟步歸四首  其四','陸游','宋','宋诗','song-poetry','','[]','斜陽古柳趙家莊，負鼓盲翁正作場。',32,'全唐诗/poet.song.131000.json','["斜陽古柳趙家莊，負鼓盲翁正作場。", "死後是非誰管得，滿村聽說蔡中郎。"]'),
('18a99628-2a3f-4663-8908-63d67c4f2d51','蜀僧宗傑來乞詩三日不去作長句送之','陸游','宋','宋诗','song-poetry','','[]','看遍東南數十州，寄船却泝蜀江秋。',64,'全唐诗/poet.song.131000.json','["看遍東南數十州，寄船却泝蜀江秋。", "孤雲兩角山亡恙，斗米三錢路不憂。", "萬里得詩長揖去，它年挈笠再來不。", "放翁爛醉尋常事，莫笑黄花插滿頭。"]'),
('e0dd82ee-14c7-4990-934b-50a68168431e','羲農','陸游','宋','宋诗','song-poetry','','[]','羲農去不反，釋老似而非。',48,'全唐诗/poet.song.131000.json','["羲農去不反，釋老似而非。", "太息眾皆醉，逝將誰與歸。", "經時忘肉味，盡日掩柴扉。", "安得同心者，燈前語造微。"]'),
('4d3e3829-a4c8-4d11-99b2-a90081578316','冬夜不寐','陸游','宋','宋诗','song-poetry','','[]','老眼睡眠少，空村霜露凄。',48,'全唐诗/poet.song.131000.json','["老眼睡眠少，空村霜露凄。", "錚錚聞叩鐵，喔喔數鳴雞。", "月入知窗破，衾單幸屋低。", "明晨炊米盡，吾起不容稽。"]'),
('6bdc6650-b7f2-4438-bec0-d71802f402b3','十月','陸游','宋','宋诗','song-poetry','','[]','塞向傾書槴，開爐積豆萁。',48,'全唐诗/poet.song.131000.json','["塞向傾書槴，開爐積豆萁。", "林居得溫暖，天遣養衰遲。", "甕盎藏蔬後，鉏耰下麥時。", "農家冬最樂，我老頗能知。"]'),
('def544c8-137a-481c-a0cf-9b7c53528d48','讀易二首  其一','陸游','宋','宋诗','song-poetry','','[]','羸軀抱疾時時劇，白髮乘衰日日增。',32,'全唐诗/poet.song.131000.json','["羸軀抱疾時時劇，白髮乘衰日日增。", "凈掃東窗讀周易，笑人投老欲依僧。"]'),
('743e8af9-16ae-49a9-a3bc-b75eb4aecd6b','讀易二首  其二','陸游','宋','宋诗','song-poetry','','[]','老喜杜門常謝客，病惟讀易不迎醫。',32,'全唐诗/poet.song.131000.json','["老喜杜門常謝客，病惟讀易不迎醫。", "冬來更愧乖慵甚，醉過收蕎下麥時。"]'),
('0fd13910-c240-454d-bffe-c4353650e455','聞雁','陸游','宋','宋诗','song-poetry','','[]','霜高木葉空，月落天宇黑。',72,'全唐诗/poet.song.131000.json','["霜高木葉空，月落天宇黑。", "哀哀斷行雁，來自關塞北。", "江湖稻粱少，念汝安得食。", "蘆深洲渚冷，歲晚霰雪逼。", "不知重雲外，何處避畢弋。", "我窮思遠征，羨汝有羽翼。"]'),
('fcbbca69-89f7-4f1f-877b-b0808fc8f95d','悲歌行','陸游','宋','宋诗','song-poetry','','[]','士如天馬龍爲友，雲夢胸中吞八九。',134,'全唐诗/poet.song.131000.json','["士如天馬龍爲友，雲夢胸中吞八九。", "秦皇殿上奪白璧，項羽帳中撞玉斗。", "張綱本不問狐狸，董龍何足方雞狗。", "風埃蹭蹬不自振，寶劍床頭作雷吼。", "憶遇高皇識隆準，豈意孤臣空白首。", "即今埋骨丈五墳，骨會作塵心不朽。", "胡不爲長星萬丈掃幽洲，胡不如昔人圖復九世讎。", "封侯廟食丈夫事，齪齪生死真吾羞。"]'),
('34e2f9cc-81cf-4e2a-8b19-c2deeef2758c','村飲','陸游','宋','宋诗','song-poetry','','[]','吳中霣霜晚，冬草有未衰。',72,'全唐诗/poet.song.131000.json','["吳中霣霜晚，冬草有未衰。", "坐令老病叟，遂失凋年悲。", "翩翩烏紗帽，裊裊殘菊枝。", "雖無車馬客，時與鄰翁期。", "新醅壓尚渾，雉兔亦及時。", "自覺勝淵明，但醉不賦詩。"]'),
('8755405c-8945-4de7-8e3d-ae1a48b4b29b','鏡湖西南有山曰外山民某氏居之其居少西小潭受飛泉群山環合真異境也爲作短歌','陸游','宋','宋诗','song-poetry','','[]','漢東九十九重岡，武都九十九脈泉。',96,'全唐诗/poet.song.131000.json','["漢東九十九重岡，武都九十九脈泉。", "豈如君家環翠阜，小潭佩玦聲鏘然。", "我欲從君乞庵地，開軒下看泉中天。", "金丹九轉太多事，服水自可追飛仙。", "雲孫相遇不相識，笑問塵世今何年。", "掬泉弄月清嘯罷，却折玉井秋風蓮。"]'),
('69aecb77-0067-4f6a-99a4-f69fe7a98ee3','十月十七日予生日也孤村風雨蕭然偶得二絕句  其一','陸游','宋','宋诗','song-poetry','','[]','少傅奉詔朝京師，檥船生我淮之湄。',32,'全唐诗/poet.song.131000.json','["少傅奉詔朝京師，檥船生我淮之湄。", "宣和七年冬十月，猶是中原無事時。"]'),
('7d601164-c402-4706-a478-20895d14b5ac','十月十七日予生日也孤村風雨蕭然偶得二絕句  其二','陸游','宋','宋诗','song-poetry','','[]','我生急雨暗淮天，出沒蛟鼉浪入船。',32,'全唐诗/poet.song.131000.json','["我生急雨暗淮天，出沒蛟鼉浪入船。", "白首功名無尺寸，茅簷還聽雨聲眠。"]'),
('ab33bad8-85d2-44b0-a395-618815961170','遊山舟中遇風雨戲作','陸游','宋','宋诗','song-poetry','','[]','龍驤萬斛去如鴻，巨浪惟能窘短篷。',32,'全唐诗/poet.song.131000.json','["龍驤萬斛去如鴻，巨浪惟能窘短篷。", "不是山靈嫌俗駕，一生常值打頭風。"]'),
('c911e86c-643b-421d-a714-1abec9f9819e','一齒動摇似不可復留有感','陸游','宋','宋诗','song-poetry','','[]','晚境常憂豁可憎，苦留終不受丁寧。',64,'全唐诗/poet.song.131000.json','["晚境常憂豁可憎，苦留終不受丁寧。", "主貧何恨客辭去，木老元知葉自零。", "未害朵頤臨肉俎，但妨叩齒讀仙經。", "從今有酒須勤買，莫學騷人要獨醒。"]'),
('98f48aed-ba25-4e07-8698-d290959a007e','山行','陸游','宋','宋诗','song-poetry','','[]','老翁七十亦何求，尚賴山行散百憂。',64,'全唐诗/poet.song.131000.json','["老翁七十亦何求，尚賴山行散百憂。", "擫耳帽寬新小疾，獨猿車穩正閑遊。", "酒旗滴雨村場晚，茶竈炊烟野寺秋。", "若論人間長久事，高吟何啻傲封侯。"]'),
('c56b3eae-5924-4de0-ad9e-2b83bc57a795','老學庵','陸游','宋','宋诗','song-poetry','','[]','窮冬短景苦匆忙，老學庵中日自長。',64,'全唐诗/poet.song.131000.json','["窮冬短景苦匆忙，老學庵中日自長。", "名譽不如心自肯，文辭終與道相妨。", "吾心本自同天地，俗學何知溺粃糠。", "已與兒曹相約定，勿爲無益費年光。"]'),
('1a6e9450-4b7b-4d47-8a31-9811c0ed5b23','枕上偶成','陸游','宋','宋诗','song-poetry','','[]','放臣不復望修門，身寄江頭黄葉村。',64,'全唐诗/poet.song.131000.json','["放臣不復望修門，身寄江頭黄葉村。", "酒渴喜聞疏雨滴，夢回愁對一燈昏。", "河潼形勝寧終棄，周漢規模要細論。", "自恨不如雲際雁，南來猶得過中原。"]'),
('a6f8156c-4fa7-467e-a415-0257233a9735','舍北閑望作六字絕句','陸游','宋','宋诗','song-poetry','','[]','潘岳一篇秋興，李成八幅寒林。',28,'全唐诗/poet.song.131000.json','["潘岳一篇秋興，李成八幅寒林。", "舍北偶然倚杖，盡見古人用心。"]'),
('74200951-a551-4ad7-898b-8c6633a0d637','題庵壁二首  其一','陸游','宋','宋诗','song-poetry','','[]','竹間僅有屋三楹，雖號吾廬實客亭。',64,'全唐诗/poet.song.131000.json','["竹間僅有屋三楹，雖號吾廬實客亭。", "已斷雨聲重點滴，欲殘燈影更晶熒。", "酒惟排悶難中聖，茶却名家可作經。", "頭眩減來還病蹇，何時徹底得康寧。"]'),
('87337ec8-dce9-41a8-8946-e705ad47e799','題庵壁二首  其二','陸游','宋','宋诗','song-poetry','','[]','身似蝸牛粗有廬，却緣無用得安居。',64,'全唐诗/poet.song.131000.json','["身似蝸牛粗有廬，却緣無用得安居。", "地爐封火欺寒雨，紙閣油窗見細書。", "蕎熟山僧分餺飥，船來溪友餉薪樗。", "閉門莫笑衰頹甚，讀易論詩亦未疏。"]'),
('59d98402-2ebf-432f-be72-efe60c217d52','縱筆三首  其一','陸游','宋','宋诗','song-poetry','','[]','老眼輕千乘，枯腸却八珍。',48,'全唐诗/poet.song.131000.json','["老眼輕千乘，枯腸却八珍。", "直令身潦倒，未害膽輪囷。", "酒裏遺浮世，書中見古人。", "平生笑園綺，老蹋帝城塵。"]'),
('a15c3be2-69ad-44a7-b373-15157f6227f6','縱筆三首  其二','陸游','宋','宋诗','song-poetry','','[]','壯歲志天下，崎嶇無一施。',48,'全唐诗/poet.song.131000.json','["壯歲志天下，崎嶇無一施。", "高談對鄰父，朴學付癡兒。", "補柵憐雞冷，分糧憫雀饑。", "吾生忽至此，惆悵鏡中絲。"]'),
('5353bfea-06da-4f5c-ba14-27b0d82bf583','縱筆三首  其三','陸游','宋','宋诗','song-poetry','','[]','天道何時定，人生固有涯。',48,'全唐诗/poet.song.131000.json','["天道何時定，人生固有涯。", "壯年行出塞，晚歲病還家。", "積憤憑誰豁，孤忠祇自嗟。", "今朝茅屋底，隱約聽霜笳。"]'),
('7284bc59-0d1b-4ad6-97e1-34643404adb0','十月二十八日夜雞初鳴時夢與數女仙遇其一作詩示予頗哀怨如人間語惟末句稍異予戲之曰若無此句不可爲神仙矣其一從傍戒曰汝當勿忘此規作詩者甚有愧色予頗悔之既覺賦兩絕句以解嘲  其一','陸游','宋','宋诗','song-poetry','','[]','玉姝眉黛翠連娟，弄翰閑題小碧箋。',32,'全唐诗/poet.song.131000.json','["玉姝眉黛翠連娟，弄翰閑題小碧箋。", "人世愁多無著處，故應分與蕊宮仙。"]'),
('2c4c44ac-1eb9-4a00-b6cc-f743dfff7bec','十月二十八日夜雞初鳴時夢與數女仙遇其一作詩示予頗哀怨如人間語惟末句稍異予戲之曰若無此句不可爲神仙矣其一從傍戒曰汝當勿忘此規作詩者甚有愧色予頗悔之既覺賦兩絕句以解嘲  其二','陸游','宋','宋诗','song-poetry','','[]','虹作飛橋蜃吐樓，群仙來賦海山秋。',32,'全唐诗/poet.song.131000.json','["虹作飛橋蜃吐樓，群仙來賦海山秋。", "玉姝定自多才思，更與人間替說愁。"]'),
('cf243886-1f26-4680-bb59-fd7a148143f0','山行二首  其一','陸游','宋','宋诗','song-poetry','','[]','緣崖曲曲羊腸路，傍水疏疏麂眼籬。',32,'全唐诗/poet.song.131000.json','["緣崖曲曲羊腸路，傍水疏疏麂眼籬。", "舉起短鞭成一笑，吾詩正是策勳時。"]'),
('5652e05e-4353-4ea4-b2c3-3158cadba83a','山行二首  其二','陸游','宋','宋诗','song-poetry','','[]','眼邊處處皆新句，塵務經心苦自迷。',32,'全唐诗/poet.song.131000.json','["眼邊處處皆新句，塵務經心苦自迷。", "今日偶然親拾得，亂松深處石橋西。"]'),
('f69d1935-002e-4dd0-bf4d-3a3039f34226','貧甚作短歌排悶','陸游','宋','宋诗','song-poetry','','[]','間何闊，逢諸葛，畏人常憂不得活。',96,'全唐诗/poet.song.131000.json','["間何闊，逢諸葛，畏人常憂不得活。", "事不諧，問文開，不蹋權門更可哀。", "即今白髮如霜草，一飽茫然身已老。", "惟有躬耕差可爲，賣劍買牛悔不早。", "年豐米賤身獨饑，今朝得米無薪炊。", "地上去天八萬里，空自呼天天豈知。"]'),
('ca341bec-66b1-4e56-ba74-bdb89217559f','過張王行廟','陸游','宋','宋诗','song-poetry','','[]','烈士生不遇，栖栖爲旅人。',96,'全唐诗/poet.song.131000.json','["烈士生不遇，栖栖爲旅人。", "英魂死不沒，凜凜爲明神。", "明神受帝命，廟食福我民。", "牲酒何足言，壓抑姑少伸。", "火旱千里赤，與人下雷雨。", "洚水不反壑，談笑出平土。", "善人錫之福，奸僞亦擊汝。", "豈若世上人，吞聲氣如縷。"]'),
('a6a44cfb-85e9-42ef-b8ba-39acf184358f','秋月曲','陸游','宋','宋诗','song-poetry','','[]','舊時家住長安城，萬戶千門秋月明。',128,'全唐诗/poet.song.131000.json','["舊時家住長安城，萬戶千門秋月明。", "紫陌朱樓歌吹海，酣宴不覺銀河傾。", "受降城頭更奇絕，莽莽平沙千里月。", "選兵夜出打番營，鐵馬蹴冰冰欲裂。", "塞月未落成功回，腰鼓橫笛如春雷。", "長安高樓豈不樂，與此相去何遼哉。", "丈夫志在垂不朽，漆胡骷髏持飲酒。", "舉頭雲表飛金盤，痛飲不用思長安。"]'),
('9a05516d-6b4f-4d06-bd15-2d6f340dd340','即事','陸游','宋','宋诗','song-poetry','','[]','蕭騷白髮滿綸巾，猶是人間詩酒身。',64,'全唐诗/poet.song.131000.json','["蕭騷白髮滿綸巾，猶是人間詩酒身。", "湖上悲秋新有作，眼邊敗意絕無人。", "稻粱栖畝雁初下，烟水粘天鷗自馴。", "堪笑推移成老大，時時几杖接鄉鄰。"]'),
('e8c2e427-d4c8-425c-b7fe-22488efd5517','悲歌行','陸游','宋','宋诗','song-poetry','','[]','感慨常自悲，發爲窮苦辭。',72,'全唐诗/poet.song.131000.json','["感慨常自悲，發爲窮苦辭。", "偪仄不少伸，夢中亦酸辛。", "脂車思遠道，太息令人老。", "中原宋輿圖，今仍傳胡雛。", "此責在臣子，諸公其可已。", "談笑復舊京，令人憶西平。"]'),
('3d5874c7-26b4-4253-9157-5c26b1b62a5c','讀李泌事偶書','陸游','宋','宋诗','song-poetry','','[]','莘渭當時已誤來，商山芝老更堪哀。',32,'全唐诗/poet.song.131000.json','["莘渭當時已誤來，商山芝老更堪哀。", "人生若要常無事，兩顆梨須手自煨。"]'),
('afab6e9e-ace4-41ef-8254-5cf3e9e3ad7a','晨起','陸游','宋','宋诗','song-poetry','','[]','晨起梳頭懶，披衣立草堂。',48,'全唐诗/poet.song.131000.json','["晨起梳頭懶，披衣立草堂。", "霧昏全隱樹，氣暖不成霜。", "灘急回魚隊，天低襯雁行。", "新春猶一月，已覺日微長。"]'),
('1841bcf6-3235-48b9-b72e-9470734876b5','喜雨','陸游','宋','宋诗','song-poetry','','[]','一秋未雨冬未雪，坐使肺肝生客熱。',96,'全唐诗/poet.song.131000.json','["一秋未雨冬未雪，坐使肺肝生客熱。", "不惟裘褐藏篋笥，卧毯坐氈俱未設。", "樽中有酒不敢嘗，小甕黄齏却時啜。", "新春距今一月爾，便恐蝗生殘宿麥。", "天公老手真可人，夜雨蕭蕭洗旱塵。", "北風吹雪定不晚，喜入三山湯餅碗。"]'),
('e68078ee-308a-4269-a740-2f0a758f2f6f','閑趣','陸游','宋','宋诗','song-poetry','','[]','堅閉門來又過冬，一裘且復擁龍鍾。',64,'全唐诗/poet.song.131000.json','["堅閉門來又過冬，一裘且復擁龍鍾。", "不辭陋巷如漿冷，自愛新醅似粥醲。", "迎婦橋邊燈煜煜，賽神林外鼓鼕鼕。", "豈惟自得閑中趣，要遣兒孫世作農。"]'),
('0e991c48-4ad1-47c9-b901-f8ea9ee017df','自警','陸游','宋','宋诗','song-poetry','','[]','人生非金石，壽夭不自知。',120,'全唐诗/poet.song.131000.json','["人生非金石，壽夭不自知。", "一日復一日，亦或至耄期。", "方其未死間，早夜勿自欺。", "嗟彼陷溺者，太山起毫釐。", "努力戒惰偷，堯舜可庶幾。", "我今齒髮弊，彊健復幾時。", "一寸學古心，自視猶可爲。", "雞鳴推枕起，爲善亦孳孳。", "天定終勝人，吾世或未衰。", "素業果有傳，三復吾此詩。"]'),
('053b35ec-42ac-4eb0-91ac-d1e2b03b7c75','雨後二首  其一','陸游','宋','宋诗','song-poetry','','[]','鏡湖歸隱老黄冠，布褐蕭然一室寬。',64,'全唐诗/poet.song.131000.json','["鏡湖歸隱老黄冠，布褐蕭然一室寬。", "燈影青熒人未睡，雨聲點滴夜將闌。", "四朝出處朋儕盡，半世漂流骨相寒。", "青史無名端可耻，著書留與後人看。"]'),
('2848f868-eea6-4a05-9e4e-c075f08f9063','雨後二首  其二','陸游','宋','宋诗','song-poetry','','[]','蕭蕭殘髮雪侵冠，冉冉清愁用底寬。',64,'全唐诗/poet.song.131000.json','["蕭蕭殘髮雪侵冠，冉冉清愁用底寬。", "把卷昏眸常欲閉，投床睡興却先闌。", "惟須酒沃相如渴，未分人哀范叔寒。", "雨霽定知梅已動，佩壺明日試尋看。"]'),
('fec421ea-1d18-452c-9f20-9415cc8e5f39','窗黑','陸游','宋','宋诗','song-poetry','','[]','風雨窗常黑，衰翁罷讀書。',48,'全唐诗/poet.song.131000.json','["風雨窗常黑，衰翁罷讀書。", "縱橫慚七略，廢惰失三餘。", "宴坐工夫熟，多聞習氣除。", "韓公未解此，誤誚腹空虛。"]'),
('3dfb9f48-b599-4b7b-a0d5-c6b329b0a4c6','雨止行至門外戲作','陸游','宋','宋诗','song-poetry','','[]','簷雨收殘滴，溪雲弄晚晴。',24,'全唐诗/poet.song.131000.json','["簷雨收殘滴，溪雲弄晚晴。", "出門還浩嘆，幾屐了吾生。"]'),
('44269a0c-c459-46b2-9083-b5c56e9a70b9','野飲','陸游','宋','宋诗','song-poetry','','[]','綠岸波生染麴塵，碧天雲細蹙魚鱗。',64,'全唐诗/poet.song.131000.json','["綠岸波生染麴塵，碧天雲細蹙魚鱗。", "山居剩得舒長目，野飲自無拘忌人。", "酒甕石邊孤店晚，樵風溪畔早梅春。", "懷章正可驚奴輩，未勝行歌獨負薪。"]'),
('15fc540e-f429-4927-9d23-8f11132ada12','雨夜有懷張季長少卿','陸游','宋','宋诗','song-poetry','','[]','放翁雖老未忘情，獨卧山村每自驚。',64,'全唐诗/poet.song.131000.json','["放翁雖老未忘情，獨卧山村每自驚。", "鼎鼎百年如電速，寥寥一笑抵河清。", "梅初破藟行江路，燈欲成花聽雨聲。", "正用此時思劇飲，故交零落愴餘生。"]'),
('eb05bcec-fbc8-45e2-a18e-b2502fae53be','雨中熟睡至夕二首  其一','陸游','宋','宋诗','song-poetry','','[]','擁爐聽雨生睡思，澀眼瞢瞢惟欲閉。',64,'全唐诗/poet.song.131000.json','["擁爐聽雨生睡思，澀眼瞢瞢惟欲閉。", "丈夫少壯要自力，飽食養慵真可愧。", "我今不睡欲何爲，常恐兒曹落吾事。", "蠻氈紙帳方施行，五鼎八珍無此味。"]'),
('f010652e-1cc1-4b6e-84c2-3732b529b1e6','雨中熟睡至夕二首  其二','陸游','宋','宋诗','song-poetry','','[]','少陵今雨無客至，寂寞衡門晝常閉。',64,'全唐诗/poet.song.131000.json','["少陵今雨無客至，寂寞衡門晝常閉。", "孝先酣枕夢周公，弟子雖嘲可無愧。", "世上紛紛榮辱多，不如睡中差省事。", "小兒忽報煎茶熟，起擁寒爐究餘味。"]'),
('d8b0c7c4-99c8-47b2-8c29-8d208ea8e73c','憶昔','陸游','宋','宋诗','song-poetry','','[]','憶昔輕裝萬里行，水郵山驛不論程。',64,'全唐诗/poet.song.131000.json','["憶昔輕裝萬里行，水郵山驛不論程。", "屢經漢帝燒餘棧，曾宿唐家雪外城。", "壯志可憐成昨夢，殘年惟有事春耕。", "西窗忽聽空階雨，獨對青燈意未平。"]'),
('d309c65d-56d9-4a3d-901b-3308e0c40503','燈下看梅','陸游','宋','宋诗','song-poetry','','[]','風雨經旬怯倚闌，梅花折得就燈看。',64,'全唐诗/poet.song.131000.json','["風雨經旬怯倚闌，梅花折得就燈看。", "有情應記去年別，無寐不禁清夜寒。", "病起搘筇幽興在，春遲載酒後期寬。", "籬東數樹尤奇絕，日遣蠻童候路乾。"]'),
('beb5773b-198f-4d48-ad10-0e4bd26c1d57','程泰之尚書挽詞二首  其一','陸游','宋','宋诗','song-poetry','','[]','文古唐元結，經明漢仲舒。',48,'全唐诗/poet.song.131000.json','["文古唐元結，經明漢仲舒。", "三朝八座貴，千載九丘書。", "早接遊從末，常聞議論餘。", "死生今永訣，追恨寄聲疏。"]'),
('2bbefad9-f7a5-4bd4-9db5-07a7d14463f4','程泰之尚書挽詞二首  其二','陸游','宋','宋诗','song-poetry','','[]','昔在紹興末，同趨行殿門。',48,'全唐诗/poet.song.131000.json','["昔在紹興末，同趨行殿門。", "方思尋宿好，忽已奉遺言。", "誄行曲臺議，飾終明主恩。", "高皇舊朝士，今復幾人存。"]'),
('8ab74038-736c-4580-b80b-1128e6992b8a','雨夕獨酌書感','陸游','宋','宋诗','song-poetry','','[]','數掩蘆藩常不開，饑鴉兩兩啄青苔。',64,'全唐诗/poet.song.131000.json','["數掩蘆藩常不開，饑鴉兩兩啄青苔。", "雨來十日未成雪，歲盡一枝初見梅。", "池上晚行携獨鶴，燈前夜酌撥新醅。", "漁村老景今如許，駿馬舊遊安在哉。"]'),
('c18cf86d-b94f-4b76-b54a-9c9f44c946a9','白首','陸游','宋','宋诗','song-poetry','','[]','白首元無一事成，朝來大笑絕冠纓。',64,'全唐诗/poet.song.131000.json','["白首元無一事成，朝來大笑絕冠纓。", "花飛早已知春減，漏盡寧容更夜行。", "蕭散且爲無算飲，猖狂未免不平鳴。", "玉關青海今安在，麥野桑村送此生。"]'),
('d5d82cca-1940-478d-94cc-943fcf74f540','客言來自上皋道中以其語作一絕','陸游','宋','宋诗','song-poetry','','[]','日曬霜融作淺泥，酒家却在斷橋西。',32,'全唐诗/poet.song.131000.json','["日曬霜融作淺泥，酒家却在斷橋西。", "五陵今代無豪俠，獨卧茅簷聽午雞。"]'),
('065d7760-c988-45ce-aa9d-9daf0655af62','睡起','陸游','宋','宋诗','song-poetry','','[]','老怯年華速，閑知晝漏長。',48,'全唐诗/poet.song.131000.json','["老怯年華速，閑知晝漏長。", "已回酣枕夢，未過古匜香。", "洗面宮眉綠，開茶带胯方。", "山家風味在，雖病意差彊。"]'),
('3b27649a-b775-4123-a929-250e4666f558','歲暮','陸游','宋','宋诗','song-poetry','','[]','案間官曆喜更端，鬢畔羅旛巧耐寒。',64,'全唐诗/poet.song.131000.json','["案間官曆喜更端，鬢畔羅旛巧耐寒。", "篩辣擣香篘臘酒，染紅絲綠簇春盤。", "衰容未覺餘年迫，佳日猶思一笑歡。", "太息兒童癡過我，鄉儺雖陋亦爭看。"]'),
('fbde6faa-ebd0-46bf-b613-3e6365055305','殘臘二首  其一','陸游','宋','宋诗','song-poetry','','[]','破臘春先到，微陰日易醺。',48,'全唐诗/poet.song.131000.json','["破臘春先到，微陰日易醺。", "鳥聲猶寂寂，木意已欣欣。", "雲起山分疊，風生水蹙紋。", "斷腸何處笛，偏向醉中聞。"]'),
('aa1d5548-1e18-4d2f-b07a-4faa192a7b35','殘臘二首  其二','陸游','宋','宋诗','song-poetry','','[]','殘臘無多日，吾生又一年。',48,'全唐诗/poet.song.131000.json','["殘臘無多日，吾生又一年。", "林塘明夕照，墟落淡春烟。", "山色危欄角，梅花綠酒邊。", "歲時元自好，老病獨凄然。"]'),
('7cb3f300-4acf-4d6f-95e3-79e05631f0ac','一壺歌五首  其一','陸游','宋','宋诗','song-poetry','','[]','悠悠日月沒根株，常在人間醉一壺。',32,'全唐诗/poet.song.131000.json','["悠悠日月沒根株，常在人間醉一壺。", "傾倒欲空還瀲灧，不曾教化不曾沽。"]'),
('f53ebcbd-a9bd-459b-864e-e0623cc0e624','一壺歌五首  其二','陸游','宋','宋诗','song-poetry','','[]','先生醉後即高歌，千古英雄奈我何。',32,'全唐诗/poet.song.131000.json','["先生醉後即高歌，千古英雄奈我何。", "花底一壺天所破，不曾飲盡不曾多。"]'),
('37effc0e-bfd4-4287-8bc2-778b12eac76b','一壺歌五首  其三','陸游','宋','宋诗','song-poetry','','[]','自從軒昊到隋唐，幾見中原作戰場。',32,'全唐诗/poet.song.131000.json','["自從軒昊到隋唐，幾見中原作戰場。", "三十萬年如電掣，不曾記得不曾忘。"]'),
('64f34b2f-3145-49cf-a970-2dcfdafd9f61','一壺歌五首  其四','陸游','宋','宋诗','song-poetry','','[]','耻從嶽牧立堯庭，况見商周戰血腥。',32,'全唐诗/poet.song.131000.json','["耻從嶽牧立堯庭，况見商周戰血腥。", "携得一壺閑處飲，不曾苦醉不曾醒。"]'),
('bb46cc72-98d9-42ca-9e63-9dff1ee93907','一壺歌五首  其五','陸游','宋','宋诗','song-poetry','','[]','長安市上醉春風，亂插繁花滿帽紅。',32,'全唐诗/poet.song.131000.json','["長安市上醉春風，亂插繁花滿帽紅。", "看盡人間興廢事，不曾富貴不曾窮。"]'),
('c915e60b-66c3-48d4-aae7-ade097f192ce','屬疾','陸游','宋','宋诗','song-poetry','','[]','白頭屬疾卧丘園，藥物枝梧且僅存。',64,'全唐诗/poet.song.131000.json','["白頭屬疾卧丘園，藥物枝梧且僅存。", "月黑淺山聞鵩嘯，窗明高樹送鴉翻。", "讒欺薄命深消骨，憂集窮途黯斷魂。", "回視少時真隔世，但餘一念在元元。"]'),
('83145840-8d02-46db-a0d0-11ff3398041c','新歲','陸游','宋','宋诗','song-poetry','','[]','風入鞭梢緊，春從草色深。',48,'全唐诗/poet.song.131000.json','["風入鞭梢緊，春從草色深。", "山坡卧新犢，園木轉幽禽。", "勳業少年夢，關河遊子心。", "爾來都掃盡，濁酒带醅斟。"]'),
('f6093f10-c1ce-4c8a-82f2-f428b2c29baf','早春','陸游','宋','宋诗','song-poetry','','[]','數聲屋角聽鳴禽，紅糝青梢忽滿林。',64,'全唐诗/poet.song.131000.json','["數聲屋角聽鳴禽，紅糝青梢忽滿林。", "雨過東皋一犁潤，冰消南澗半篙深。", "逢僧竹院閑評藥，携鶴山村醉擁琴。", "青史功名黄閤貴，有時應不到如今。"]'),
('f306f4d5-29fe-4510-946d-7db5e995cc3a','太古','陸游','宋','宋诗','song-poetry','','[]','太古安知虙與堯，茹毛飲血自消摇。',32,'全唐诗/poet.song.131000.json','["太古安知虙與堯，茹毛飲血自消摇。", "不須追咎爲書契，初結繩時俗已澆。"]'),
('7c70c097-a3fc-4045-8edb-852eef1f845e','春夜','陸游','宋','宋诗','song-poetry','','[]','老憊生如寄，春寒夢亦孤。',48,'全唐诗/poet.song.131000.json','["老憊生如寄，春寒夢亦孤。", "燈花時自墜，梟語迭相呼。", "萬里書難得，三年病未蘇。", "窗深不知曉，但覺動林烏。"]'),
('f55ebf36-5655-45e5-ae91-dd3556cd3c37','正月六日作','陸游','宋','宋诗','song-poetry','','[]','上天四序分寒燠，以漸相尋不相瀆。',128,'全唐诗/poet.song.131000.json','["上天四序分寒燠，以漸相尋不相瀆。", "今年立春七日耳，暖景溫風何迫促。", "群蛙怒鳴蚊蚋出，蚍蜉插翅飛滿屋。", "兒童便欲覓團扇，我亦汗垢思湯沐。", "山坡梅花常恨晚，一夕開盡如雪谷。", "籬邊已放桃蕊紅，庭下頓長萱芽綠。", "小人識淺喜欲舞，輕衫冷餅相追逐。", "春深癘鬼不貸人，此暖但憂非汝福。"]'),
('b3697b51-9181-4468-a11c-224455f2432f','寄題吳斗南玩芳亭','陸游','宋','宋诗','song-poetry','','[]','北斗以南有吳侯，人物知非第二流。',128,'全唐诗/poet.song.131000.json','["北斗以南有吳侯，人物知非第二流。", "讀書不放一字過，閉戶忽驚雙鬢秋。", "平生離騷讀千遍，屈沱秭歸要親見。", "歸來落筆愈驚人，宋玉景差俱北面。", "玩芳亭中蘭茝芳，朝回解带春晝長。", "愛君憂國有奇作，坐令壯觀還沅湘。", "老夫曩亦同此趣，甚欲閑題玩芳句。", "無奈生涯今已別，倒壑枯楠忘歲月。"]'),
('3eabe71f-98b4-4c57-9d52-40cd9368c4b8','春初驟暄一夕梅盡開明日大風花落成積戲作三首  其一','陸游','宋','宋诗','song-poetry','','[]','暖逼梅花爛漫開，飄零便恐付蒼苔。',32,'全唐诗/poet.song.131000.json','["暖逼梅花爛漫開，飄零便恐付蒼苔。", "更堪連夜風如許，似妒愁人把一杯。"]'),
('482d5045-a9c5-48e6-9b15-d9b4a692ebdf','春初驟暄一夕梅盡開明日大風花落成積戲作三首  其二','陸游','宋','宋诗','song-poetry','','[]','殘梅零落不禁吹，真是無花空折枝。',32,'全唐诗/poet.song.131000.json','["殘梅零落不禁吹，真是無花空折枝。", "堪笑老人風味減，三年不作送梅詩。"]'),
('f6191848-4c54-4f10-b904-e05ca2ed37fa','春初驟暄一夕梅盡開明日大風花落成積戲作三首  其三','陸游','宋','宋诗','song-poetry','','[]','年年爛醉萬梅中，吸酒如鯨到手空。',32,'全唐诗/poet.song.131000.json','["年年爛醉萬梅中，吸酒如鯨到手空。", "花欲過時常惜別，今年此別更匆匆。"]'),
('e47d7077-5d3b-4e7e-9ac1-a65b39528716','讀老子傳','陸游','宋','宋诗','song-poetry','','[]','巍巍闕里與天崇，禮樂詩書萬世宗。',32,'全唐诗/poet.song.131000.json','["巍巍闕里與天崇，禮樂詩書萬世宗。", "但說周公曾入夢，寧於老氏嘆猶龍。"]'),
('6980dd45-5a9f-436b-ab51-cbd9f1964136','示元用','陸游','宋','宋诗','song-poetry','','[]','德孫學語已驚人，悶裏時時一笑新。',64,'全唐诗/poet.song.131000.json','["德孫學語已驚人，悶裏時時一笑新。", "老子已應如櫪驥，此郎端恐是天麟。", "會看神授如椽筆，莫改家傳折角巾。", "汝叔不癡當愛汝，夜窗燈火勉相親。"]'),
('083a35f7-cbbc-4b7b-9d88-92f58db0b4c1','春思','陸游','宋','宋诗','song-poetry','','[]','七十老翁身退耕，可憐未減舊風情。',64,'全唐诗/poet.song.131000.json','["七十老翁身退耕，可憐未減舊風情。", "典衣取酒那論價，秉燭看花每到明。", "江浦時時逢畫檝，寺樓處處聽新鶯。", "此生無復陽關夢，不怕樽前唱渭城。"]'),
('4aec2d02-6d02-4502-b47a-fc3ca656987f','春望','陸游','宋','宋诗','song-poetry','','[]','天地回春律，山川掃積陰。',48,'全唐诗/poet.song.131000.json','["天地回春律，山川掃積陰。", "波光迎日動，柳色向人深。", "霑灑憂時泪，飛騰滅虜心。", "人扶上危榭，未廢一長吟。"]'),
('720db9d3-7dd7-4f45-916d-6db9ba9cf97c','丙辰上元前一日','陸游','宋','宋诗','song-poetry','','[]','弊裘破帽髮鬅鬙，宛似山房罷講僧。',64,'全唐诗/poet.song.131000.json','["弊裘破帽髮鬅鬙，宛似山房罷講僧。", "身病不禁連夜雨，家貧只挂舊年燈。", "修椽柳外掀樓角，危檻雲間露塔層。", "自笑閑遊本無定，興闌隨處倚枯藤。"]'),
('15730150-e921-41bb-96c5-b9f6e2f39bad','夜雨思括蒼遊','陸游','宋','宋诗','song-poetry','','[]','道心退惰如風鷁，世念堅彊似火牛。',32,'全唐诗/poet.song.131000.json','["道心退惰如風鷁，世念堅彊似火牛。", "安得短篷湖海去，夜深聽雨琵琶洲。"]'),
('9e2b05d4-ddde-4205-9daa-19a46e83df1a','春陰','陸游','宋','宋诗','song-poetry','','[]','麴塵柳色正遮門，石黛江流曲抱村。',64,'全唐诗/poet.song.131000.json','["麴塵柳色正遮門，石黛江流曲抱村。", "小院春光方盎盎，遠山雨氣又昏昏。", "傍簷林鳥驚幽夢，極目烟蕪捲燒痕。", "只道餘寒尚如許，不知生意滿乾坤。"]'),
('6eac7708-33b0-4c9c-8d66-4f63bbd52fd9','寒夜歌','陸游','宋','宋诗','song-poetry','','[]','陸子七十猶窮人，空山度此冰雪晨。',158,'全唐诗/poet.song.131000.json','["陸子七十猶窮人，空山度此冰雪晨。", "既不能挺長劍以抉九天之雲，又不能持斗魁以回萬物之春。", "食不足以活妻子，化不足以行鄉鄰。", "忍饑讀書忽白首，行歌拾穗將終身。", "論事憤叱目若炬，望古踴躍心生塵。", "三萬里之黄河入東海，五千仞之太華磨蒼旻。", "坐令此地沒胡虜，兩京宮闕悲荆榛。", "誰施赤手驅蛇龍，誰恢天網致鳳麟。", "君看煌煌藝祖業，志士豈得空酸辛。"]'),
('a647b251-c122-42cf-9fc1-cf1a1d195d0e','正月十六日園中偶賦','陸游','宋','宋诗','song-poetry','','[]','又向柴荆過上元，豪華前事不須論。',64,'全唐诗/poet.song.131000.json','["又向柴荆過上元，豪華前事不須論。", "偶逢花發閑持酒，不得人扶懶出門。", "薄技號山曾獻玉，榮途染指亦嘗黿。", "年來洗盡東陵夢，瓜壟蕭蕭老故園。"]'),
('c51a7746-7b21-427b-b11d-7770bf41e55c','陵霄花','陸游','宋','宋诗','song-poetry','','[]','庭中青松四無鄰，陵霄百尺依松身。',64,'全唐诗/poet.song.131000.json','["庭中青松四無鄰，陵霄百尺依松身。", "高花風墮赤玉盞，老蔓烟溼蒼龍鱗。", "古來豪傑人少知，昂霄聳壑寧自期。", "抱才委地固多矣，今我撫事心傷悲。"]'),
('e988982d-8e2c-4ffd-9c4f-a63363aaf529','懷舊六首  其一','陸游','宋','宋诗','song-poetry','','[]','鶴鳴山下竹連雲，鳳集城邊柳映門。',32,'全唐诗/poet.song.131000.json','["鶴鳴山下竹連雲，鳳集城邊柳映門。", "當日不知爲客樂，如今回首却消魂。"]'),
('b302a7d9-0eb7-45bc-a00e-06407975ac11','懷舊六首  其二','陸游','宋','宋诗','song-poetry','','[]','駿騾西過雨漫天，千里江山在眼邊。',32,'全唐诗/poet.song.131000.json','["駿騾西過雨漫天，千里江山在眼邊。", "二十四年如昨夢，憑誰問訊带枷僊。"]'),
('6a93219a-ebc9-47e5-a818-f7f7bb8262bf','懷舊六首  其三','陸游','宋','宋诗','song-poetry','','[]','狼烟不舉羽書稀，幕府相從日打圍。',32,'全唐诗/poet.song.131000.json','["狼烟不舉羽書稀，幕府相從日打圍。", "最憶定軍山下路，亂飄紅葉滿戎衣。"]'),
('06691b76-4acd-4197-95d0-ba23dbf22c04','懷舊六首  其四','陸游','宋','宋诗','song-poetry','','[]','翠崖紅棧鬰參差，小益初程景最奇。',32,'全唐诗/poet.song.131000.json','["翠崖紅棧鬰參差，小益初程景最奇。", "誰向豪端收拾得，李將軍畫少陵詩。"]'),
('2fe55a2c-0ff7-44e1-8dc3-b646fe1a3094','懷舊六首  其五','陸游','宋','宋诗','song-poetry','','[]','回龍寺壁看維摩，最得曹吳筆意多。',32,'全唐诗/poet.song.131000.json','["回龍寺壁看維摩，最得曹吳筆意多。", "風雨塵埃昏欲盡，何人更著手摩挲。"]'),
('9967d114-dd6c-4f68-a64b-96774819bf7b','懷舊六首  其六','陸游','宋','宋诗','song-poetry','','[]','嶓冢山頭是漢源，故祠寂寞掩朱門。',32,'全唐诗/poet.song.131000.json','["嶓冢山頭是漢源，故祠寂寞掩朱門。", "擊鮮藉草無窮樂，送老那知江上村。"]'),
('45392b88-d6a7-4058-9817-d32541506a71','夜坐','陸游','宋','宋诗','song-poetry','','[]','蓬窗夜半竹騷然，坐守殘編悄不眠。',64,'全唐诗/poet.song.131000.json','["蓬窗夜半竹騷然，坐守殘編悄不眠。", "辛苦空成左傳癖，逍遥常愧大慈僊。", "風寧可繫功名誤，日不能黏歲月遷。", "明旦覓船湖上去，西村桃李淡春烟。"]'),
('e2969d60-a894-41a5-824c-b7dcaa9db6e2','入城舟中作','陸游','宋','宋诗','song-poetry','','[]','棹邊蘸岸挼藍水，篷外橫空破墨山。',32,'全唐诗/poet.song.131000.json','["棹邊蘸岸挼藍水，篷外橫空破墨山。", "更著灘頭一行鷺，此身真在畫圖間。"]'),
('fe84b53c-e896-483f-ae17-22126f956eb9','寓蓬萊館','陸游','宋','宋诗','song-poetry','','[]','朱門高柳畫橋南，掠面風埃喜解驂。',64,'全唐诗/poet.song.131000.json','["朱門高柳畫橋南，掠面風埃喜解驂。", "霽日偶逢春盎盎，野人不慣屋潭潭。", "堂中剩喜簪裾集，樓上時聞鼓角酣。", "明發扁舟覓歸路，趁時吾欲事農蠶。"]'),
('024dc093-9edb-4f01-aea8-d274e4852c66','過能仁光孝寺欲訪昕老會府中速客遂不果入','陸游','宋','宋诗','song-poetry','','[]','春日城南過寶坊，馳驅不得駐車箱。',64,'全唐诗/poet.song.131000.json','["春日城南過寶坊，馳驅不得駐車箱。", "高門臨道凈如拭，傑屋凌空勢欲翔。", "齋近鍾魚初送響，風微松檜自生香。", "暫來堪笑忙如許，坐羨高人白晝長。"]'),
('cbcb8ade-52cd-40a4-9cc1-689ec13a831e','夜二鼓留西城門歸三山','陸游','宋','宋诗','song-poetry','','[]','秉炬夜離驛，戴星出西關。',48,'全唐诗/poet.song.131000.json','["秉炬夜離驛，戴星出西關。", "舟人飛畫檝，門鎖響銅環。", "漁火明遥浦，溪風解醉顔。", "鄰家亦驚起，迎我笑堅頑。"]'),
('4b795151-9c14-42a9-973a-848912ae815c','讀杜詩','陸游','宋','宋诗','song-poetry','','[]','千載詩亡不復刪，少陵談笑即追還。',32,'全唐诗/poet.song.131000.json','["千載詩亡不復刪，少陵談笑即追還。", "常憎晚輩言詩史，清廟生民伯仲間。"]'),
('2ce55537-0988-482f-9952-cafc96b5e33a','蘇韜光節推挽歌詞','陸游','宋','宋诗','song-poetry','','[]','才名京兆掾，門閥魏公孫。',48,'全唐诗/poet.song.131000.json','["才名京兆掾，門閥魏公孫。", "遇事雖骯髒，接人終靜溫。", "寧吟灞橋雪，不掃舍人門。", "二妙凋零盡，衰翁慨獨存。"]'),
('1b0a4413-d8f4-491d-9679-b4e3d8deaeda','村翁','陸游','宋','宋诗','song-poetry','','[]','放翁真箇是村翁，釣渭耕莘事不同。',64,'全唐诗/poet.song.131000.json','["放翁真箇是村翁，釣渭耕莘事不同。", "蹴蹋烟雲兩芒屩，憑陵風雪一篷籠。", "屢經駭浪身終免，遍閱浮漚壽未窮。", "幸有春衣堪換酒，道邊醉卧示神通。"]'),
('4d009ed1-6774-4572-8b93-0a90837b3b11','寄子布','陸游','宋','宋诗','song-poetry','','[]','釣灘耕壟雪盈簪，從入新年病至今。',64,'全唐诗/poet.song.131000.json','["釣灘耕壟雪盈簪，從入新年病至今。", "遠使有書常灑泪，長宵無夢更傷心。", "何由老眼迎歸棹，空爲秋風感暮碪。", "一紙新詩千萬恨，臨風悵望獨長吟。"]'),
('4068a503-c2c9-46d4-a329-7e5a5990d82a','落花','陸游','宋','宋诗','song-poetry','','[]','朱朱白白不禁吹，老未忘情作許悲。',64,'全唐诗/poet.song.131000.json','["朱朱白白不禁吹，老未忘情作許悲。", "瑞錦已殘猶有夢，明霞初散可無詩。", "人應偷樣傳圖本，天亦收香付蜜脾。", "榮悴相尋君看取，曉來青子已團枝。"]'),
('b3f6f415-c9d1-473f-a1c0-7b5616ad50e4','南窗','陸游','宋','宋诗','song-poetry','','[]','身輕婚嫁畢，耳靜市朝疏。',24,'全唐诗/poet.song.131000.json','["身輕婚嫁畢，耳靜市朝疏。", "褫带脫烏幘，一窗寬有餘。"]'),
('65f8490d-7088-4b06-9c56-0296c3648a90','排悶','陸游','宋','宋诗','song-poetry','','[]','白髮無端日日新，自憐猶作百憂身。',64,'全唐诗/poet.song.131000.json','["白髮無端日日新，自憐猶作百憂身。", "孤燈聽雨常終夜，一榼尋花又送春。", "旋壓麥糕邀父老，時分菜把餉比鄰。", "不須頻起陳人嘆，已是清朝六世民。"]'),
('df462b47-0d71-4df2-ba3f-f2dff2d68288','過鄰家戲作','陸游','宋','宋诗','song-poetry','','[]','老脫朝冠岸幅巾，時時乘興過比鄰。',64,'全唐诗/poet.song.131000.json','["老脫朝冠岸幅巾，時時乘興過比鄰。", "瓶無儲粟吾猶樂，步有新船子豈貧。", "醅甕香浮花露熟，藥欄土潤玉芝新。", "相從覓笑真當勉，又過浮生一歲春。"]'),
('a97634fc-63b8-4782-bf10-8965428139b7','看花','陸游','宋','宋诗','song-poetry','','[]','好樹典衣買，新花扶杖看。',48,'全唐诗/poet.song.131000.json','["好樹典衣買，新花扶杖看。", "村醪雜清濁，山果半甘酸。", "家事貧尤簡，詩情老未闌。", "鸕鶿閑似我，日暮立清灘。"]'),
('4975beea-e46c-44d8-89fc-db09b586b097','閑趣','陸游','宋','宋诗','song-poetry','','[]','同儕零落曉星稀，久住人間豈自期。',64,'全唐诗/poet.song.131000.json','["同儕零落曉星稀，久住人間豈自期。", "衰病已成垂白叟，春寒又到牡丹時。", "溪邊喚客閑持釣，燈下留僧共覆棋。", "一日轉頭還過却，紛紛世事不須知。"]'),
('10a47c69-aeeb-462e-862a-5b655bae69dd','春盡遣懷','陸游','宋','宋诗','song-poetry','','[]','裊裊爐香晝掩扉，殘年真是解塵鞿。',67,'全唐诗/poet.song.131000.json','["裊裊爐香晝掩扉，殘年真是解塵鞿。", "青{食茲}旋擣通鄰好，白葛新裁製暑衣。", "避日小魚穿藻去，倚風輕燕拂簾飛。", "要知名宦非初意，三十年前已念歸。"]'),
('36d92b11-8fc2-46a7-a83c-3bb62532213c','二友','陸游','宋','宋诗','song-poetry','','[]','清芬六出水梔子，堅瘦九節石菖蒲。',32,'全唐诗/poet.song.131000.json','["清芬六出水梔子，堅瘦九節石菖蒲。", "放翁閉門得二友，千古夷齊今豈無。"]'),
('8ecb6a76-98ae-4b07-9d2f-a1951794f123','半丈紅盛開','陸游','宋','宋诗','song-poetry','','[]','滿酌吳中清若空，共賞池邊半丈紅。',32,'全唐诗/poet.song.131000.json','["滿酌吳中清若空，共賞池邊半丈紅。", "老子通神誰得似，短筇到處即春風。"]'),
('bb3e0d5b-8d2d-4f16-86d4-eb7b0d7af161','感事四首  其一','陸游','宋','宋诗','song-poetry','','[]','雞犬相聞三萬里，遷都豈不有關中。',32,'全唐诗/poet.song.131000.json','["雞犬相聞三萬里，遷都豈不有關中。", "廣陵南幸雄圖盡，泪眼山河夕照紅。"]'),
('0804674f-3664-44d6-a3d6-30e2c50a5d78','感事四首  其二','陸游','宋','宋诗','song-poetry','','[]','堂堂韓岳兩驍將，駕馭可使復中原。',32,'全唐诗/poet.song.131000.json','["堂堂韓岳兩驍將，駕馭可使復中原。", "廟謀尚出王導下，顧用金陵爲北門。"]'),
('e780ce88-d721-411c-bdc6-8875a13e203e','感事四首  其三','陸游','宋','宋诗','song-poetry','','[]','渭上晝昏吹戰塵，橫戈慷慨欲忘身。',32,'全唐诗/poet.song.131000.json','["渭上晝昏吹戰塵，橫戈慷慨欲忘身。", "東歸却作漁村老，自誤青春不怨人。"]'),
('173952af-f6b3-444b-b75a-9c8da235083e','感事四首  其四','陸游','宋','宋诗','song-poetry','','[]','捫虱當時頗自奇，功名遠付十年期。',32,'全唐诗/poet.song.131000.json','["捫虱當時頗自奇，功名遠付十年期。", "酒澆不下胸中恨，吐向青天未必知。"]'),
('b16c1758-828a-4189-8e1b-fc30947f6b1e','豐年行','陸游','宋','宋诗','song-poetry','','[]','南村北村春雨晴，東家西家地碓聲。',96,'全唐诗/poet.song.131000.json','["南村北村春雨晴，東家西家地碓聲。", "稻陂正滿綠針密，麥隴無際黄雲平。", "前年穀與金同價，家家涕泣伐桑柘。", "豈知還復有今年，酒肉如山賽春社。", "吏不到門人晝眠，老稚安樂如登仙。", "縣前歸來傳好語，黄紙續放身丁錢。"]'),
('0e00b12d-ee2d-4e40-8e3b-c886a08b8cce','四月一日夜漏欲盡起坐達旦','陸游','宋','宋诗','song-poetry','','[]','春歸不可留，斗柄已崢嶸。',96,'全唐诗/poet.song.131000.json','["春歸不可留，斗柄已崢嶸。", "老至不可却，雪鬢森千莖。", "少年所讀書，廢忘如隔生。", "舊交死欲盡，存者萬里程。", "高談無與發，欲語輒吞聲。", "悠悠一飽計，泯泯千載名。", "逝將山丘歸，不見河雒清。", "挑燈坐待旦，攬筆衰涕傾。"]'),
('081a2044-3c56-4fd4-b599-dee12cecaeca','蓬萊行','陸游','宋','宋诗','song-poetry','','[]','山峭插雲海，樓高入烟霄。',72,'全唐诗/poet.song.131000.json','["山峭插雲海，樓高入烟霄。", "不知何宮殿，東望鬰岧嶢。", "是時青童君，初散通明朝。", "風濤中破裂，涌出黄金橋。", "授我玉芝房，服之塵念消。", "凡骨一朝換，八極坐可超。"]'),
('9d9ed72a-a35f-4d2a-af4b-c46265ff67a3','馮縣丞挽歌詞','陸游','宋','宋诗','song-poetry','','[]','尊公同故里，季父接周行。',48,'全唐诗/poet.song.131000.json','["尊公同故里，季父接周行。", "晚憙烏衣巷，重逢玉樹郎。", "名流多賞識，榮路正騰驤。", "愁絕河梁上，風烟暮莽蒼。"]'),
('ef4146ef-7881-4ed8-abf5-4fb18a5f7302','幽居初夏四首  其一','陸游','宋','宋诗','song-poetry','','["\u5199\u666f", "\u590f\u5929", "\u4f24\u6000", "\u5c71\u6c34"]','湖山勝處放翁家，槐柳陰中野徑斜。',64,'全唐诗/poet.song.131000.json','["湖山勝處放翁家，槐柳陰中野徑斜。", "水滿有時觀下鷺，草深無處不鳴蛙。", "籜龍已過頭番筍，木筆猶開第一花。", "嘆息老來交舊盡，睡餘誰共午甌茶。"]'),
('998b6f4d-487b-44e2-b421-6326d500cc34','幽居初夏四首  其二','陸游','宋','宋诗','song-poetry','','[]','藤冠草屨病支離，門外紛紛百不知。',64,'全唐诗/poet.song.131000.json','["藤冠草屨病支離，門外紛紛百不知。", "解籜有聲驚倦枕，飛花無力點清池。", "閑思舊事惟求醉，老感流年只自悲。", "綠樹陰中紅練起，一團零亂溼胭脂。"]'),
('c4f3c234-af51-4570-aebe-049c60f88674','幽居初夏四首  其三','陸游','宋','宋诗','song-poetry','','[]','長歌嫋嫋插秧天，小繖翻翻入市船。',64,'全唐诗/poet.song.131000.json','["長歌嫋嫋插秧天，小繖翻翻入市船。", "高棟巢乾初乳燕，綠槐陰密已鳴蟬。", "只言末俗人情惡，未廢先生日晏眠。", "推枕起來閑弄筆，銅蟾手自挹寒泉。"]'),
('79333aa3-75d5-4c0c-adf5-ac8bfcf3bc8f','幽居初夏四首  其四','陸游','宋','宋诗','song-poetry','','[]','鬢毛禿盡齒牙疏，難受人間折簡呼。',64,'全唐诗/poet.song.131000.json','["鬢毛禿盡齒牙疏，難受人間折簡呼。", "詩酒本來無藉在，形骸况復不枝梧。", "槐陰漸密能鄣日，池水新生可浴鳧。", "移得太行終亦死，平生常笑北山愚。"]'),
('61140a12-08d6-44c1-9f90-cca2e69ce891','出蜀十九年故交零落殆盡慨然有作','陸游','宋','宋诗','song-poetry','','[]','西遊邂逅得諸君，落筆千言酒百分。',64,'全唐诗/poet.song.131000.json','["西遊邂逅得諸君，落筆千言酒百分。", "聚散亦知元有數，死生豈料不相聞。", "平羌空憶吟江月，小益何由度棧雲。", "一事與君聊自慰，兒曹或可付斯文。"]'),
('579f19c3-5318-4973-ae79-952e48835ff1','憶天彭牡丹之盛有感','陸游','宋','宋诗','song-poetry','','[]','常記彭州送牡丹，祥雲徑尺照金盤。',32,'全唐诗/poet.song.131000.json','["常記彭州送牡丹，祥雲徑尺照金盤。", "豈知身老農桑野，一朵妖紅夢裏看。"]'),
('ee855c90-ef25-45a6-afa6-5d8528b674b8','五月七日夜夢中作二首  其一','陸游','宋','宋诗','song-poetry','','[]','征行過孤壘，寂寞已千年。',48,'全唐诗/poet.song.131000.json','["征行過孤壘，寂寞已千年。", "馬病霜菅瘦，狐鳴古冢穿。", "烟塵身欲老，金石志方堅。", "零落英雄盡，何人共著鞭。"]'),
('318467de-3b78-479e-a51c-d54aef64be6c','五月七日夜夢中作二首  其二','陸游','宋','宋诗','song-poetry','','[]','霜露薄貂裘，連年塞上留。',48,'全唐诗/poet.song.131000.json','["霜露薄貂裘，連年塞上留。", "蘆笳青冢月，鐵馬玉關秋。", "振臂忘身憊，憑天報國讎。", "諸公方衮衮，好運幄中籌。"]'),
('da358c20-086a-4704-bc8f-56575267ac6b','急雨','陸游','宋','宋诗','song-poetry','','[]','急雨清風發土香，靈臺如受寶犀凉。',32,'全唐诗/poet.song.131000.json','["急雨清風發土香，靈臺如受寶犀凉。", "華胥一枕蘧然覺，却聽蟬聲送夕陽。"]'),
('bc8666af-8278-4170-b636-da73fcb7439c','夜中步月','陸游','宋','宋诗','song-poetry','','[]','夜半不成寐，起尋微月行。',48,'全唐诗/poet.song.131000.json','["夜半不成寐，起尋微月行。", "風生驚葉墮，露重覺荷傾。", "兀兀酒中趣，悠悠身後名。", "興闌還掩戶，坐待日東生。"]'),
('f705ae27-0898-45fd-9a37-17fe0efcf241','晨起','陸游','宋','宋诗','song-poetry','','[]','齒豁不可補，髮脫無由栽。',96,'全唐诗/poet.song.131000.json','["齒豁不可補，髮脫無由栽。", "清晨明鏡中，老色蒼然來。", "餘年亦自惜，未忍付酒杯。", "抽架取我書，危坐闔復開。", "萬世見唐堯，夔龍獲親陪。", "寥寥三千年，氣象挽可回。", "豈以七尺軀，顧受世俗衰。", "道在無不可，廊廟均蒿萊。"]'),
('3cac7548-2376-4378-a530-abd4ac451374','枕上聞布穀聲','陸游','宋','宋诗','song-poetry','','[]','老去惟思日月遲，更堪青鬢總成絲。',32,'全唐诗/poet.song.131000.json','["老去惟思日月遲，更堪青鬢總成絲。", "無端催取流年去，最恨溪頭布穀兒。"]'),
('980ad1d6-a900-4f7b-a58f-ab2e20dc70f3','雨夜','陸游','宋','宋诗','song-poetry','','[]','北風吹雨亂疏鐘，蔌蔌燈花破碎紅。',64,'全唐诗/poet.song.131000.json','["北風吹雨亂疏鐘，蔌蔌燈花破碎紅。", "孤夢正行天一握，高城俄報鼓三通。", "衰遲空抱屠龍技，豪俊誰收汗馬功。", "但願輿圖早來復，白頭敢望起雲中。"]'),
('302f7a73-9bf2-415a-8926-17d8891b7a04','焚黄','陸游','宋','宋诗','song-poetry','','[]','啼呼梨棗憶兒時，駒隙頻經日月馳。',64,'全唐诗/poet.song.131000.json','["啼呼梨棗憶兒時，駒隙頻經日月馳。", "早歲已興風木嘆，餘生永廢蓼莪詩。", "燎黄恩重空垂泣，戴白身存敢自期。", "足蹇僅能成拜起，籃輿歸路不勝悲。"]'),
('93dbea98-e2de-4b3b-b59f-78e30ffbc321','即事','陸游','宋','宋诗','song-poetry','','[]','陶令常耽酒，龐翁不出家。',48,'全唐诗/poet.song.131000.json','["陶令常耽酒，龐翁不出家。", "安貧炊麥飯，省事嚼茶芽。", "池滿浮雛鴨，庭荒噪渴蛙。", "詩成賞音絕，自向小兒誇。"]'),
('f7969cd1-cbad-4743-adca-e27c00dd9a7a','失鸂鶒','陸游','宋','宋诗','song-poetry','','[]','不見池邊整羽衣，繞村散覓走群兒。',64,'全唐诗/poet.song.131000.json','["不見池邊整羽衣，繞村散覓走群兒。", "卑飛正恐爲人得，徑去何須報我知。", "久憶蘋洲應自喜，尚餘菰米亦堪悲。", "放翁未到忘情處，日暮憑欄獨詠詩。"]'),
('274659fb-030f-4c27-963c-8398a5f96d8b','贈童道人蓋與予同甲子','陸游','宋','宋诗','song-poetry','','[]','吾儕之生乙巳年，達者寥寥窮比肩。',64,'全唐诗/poet.song.131000.json','["吾儕之生乙巳年，達者寥寥窮比肩。", "退士一生藜藿食，散人萬里江湖天。", "忍貧不變我自許，挾術自營君豈然。", "一事尚須煩布策，幾時能具釣魚船。"]'),
('3cc8f5b7-bfd9-419f-8de3-3a5b42bb0ff8','上方銛老求宿蘆詩宿蘆蓋所寓室名以其似漁舟也','陸游','宋','宋诗','song-poetry','','[]','一曲亭前水接天，放翁短棹弄風烟。',32,'全唐诗/poet.song.131000.json','["一曲亭前水接天，放翁短棹弄風烟。", "宿蘆縱有江湖趣，猶是人間贗釣船。"]'),
('437791ac-8beb-4560-a8d6-c12c4c9a0ce4','夜坐園中至夜分','陸游','宋','宋诗','song-poetry','','[]','岸巾閑倚胡床坐，步屧還扶拄杖行。',64,'全唐诗/poet.song.131000.json','["岸巾閑倚胡床坐，步屧還扶拄杖行。", "漸近秋清知病減，盡捐世累覺心平。", "翻翻雙鵲風枝爽，熠熠孤螢露草明。", "更欲裴回盡幽興，麗譙傳漏報三更。"]'),
('8c0380cd-4f58-4cbe-aff8-57ed2870c0e3','六月二十四日夜分夢范至能李知幾尤延之同集江亭諸公請予賦詩記江湖之樂詩成而覺忘數字而已','陸游','宋','宋诗','song-poetry','','[]','露箬霜筠織短篷，飄然來往淡烟中。',64,'全唐诗/poet.song.131000.json','["露箬霜筠織短篷，飄然來往淡烟中。", "偶經菱市尋谿友，却揀蘋汀下釣筒。", "白菡萏香初過雨，紅蜻蜓弱不禁風。", "吳中近事君知否，團扇家家畫放翁。"]'),
('71e94b20-6284-4ed6-817e-56cb35174eb2','晨起','陸游','宋','宋诗','song-poetry','','[]','月澹知將曉，風清喜近秋。',48,'全唐诗/poet.song.131000.json','["月澹知將曉，風清喜近秋。", "狂吟詞跌宕，新沐髮颼飀。", "桐葉危先墮，蟬聲斷更遒。", "達生隨處樂，自笑替人愁。"]'),
('52c4d08f-61fb-44f9-8b39-f9e24b37ca41','村飲示鄰曲','陸游','宋','宋诗','song-poetry','','[]','七年收朝迹，名不到權門。',168,'全唐诗/poet.song.131000.json','["七年收朝迹，名不到權門。", "耿耿一寸心，思與窮友論。", "憶昔西戍日，孱虜氣可吞。", "偶失萬戶侯，遂老三家村。", "朱顔捨我去，白髮日夜繁。", "夕陽坐溪邊，看兒牧雞豚。", "雕胡幸可炊，亦有社酒渾。", "耳熱我欲歌，四座且勿喧。", "即今黄河上，事殊曹與袁。", "扶義孰可遣，一戰洗乾坤。", "西酹吳玠墓，南招宗澤魂。", "焚庭涉其血，豈獨清中原。", "吾儕雖益老，忠義傳子孫。", "征遼詔儻下，從我屬櫜鞬。"]'),
('b4f5729b-bffe-4d0e-ad53-077d6828d610','醉歸','陸游','宋','宋诗','song-poetry','','[]','十畝春蕪手自犁，瓜牛廬在鏡湖西。',64,'全唐诗/poet.song.131000.json','["十畝春蕪手自犁，瓜牛廬在鏡湖西。", "禪心每笑彈棋局，道眼長捐刮膜篦。", "絕食就官分鶴料，無車免客笑雞栖。", "旗亭酒賤秋風近，夜夜歸來醉似泥。"]'),
('a4bebb4c-4f96-40b3-83e0-b83352bc0fad','二愛  其一','陸游','宋','宋诗','song-poetry','','[]','結屋不袤丈，著身還有餘。',72,'全唐诗/poet.song.131000.json','["結屋不袤丈，著身還有餘。", "破壁作小窗，亦足陳吾書。", "無酒當飲水，無肉當飯蔬。", "知止乃不殆，此語良非虛。", "古人造道處，正自無絕殊。", "願君勿它求，且復愛吾廬。"]');
